-- Poems batch 219
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('36844f17-057a-4821-afc8-73bd7145f6e9','茅山','楊至質','宋','宋诗','song-poetry','','[]','玉肺空浮巳字山，五門不鎖洞天寬。',64,'全唐诗/poet.song.202000.json','["玉肺空浮巳字山，五門不鎖洞天寬。", "紫花可餌秋尋朮，紅焰難埋夜見丹。", "畫出一牛方水草，飛來三鵠各峰巒。", "仙蹤寂寞高風遠，誰爲先生指額瘢。"]'),
('a5dd8c9d-85bd-45dc-854e-d707a6908260','送茅山劉書記游南嶽','楊至質','宋','宋诗','song-poetry','','["\u8861\u5c71"]','憶共住華陽，晴藍紫朮香。',48,'全唐诗/poet.song.202000.json','["憶共住華陽，晴藍紫朮香。", "空山今詣闕，吾子亦游方。", "草露雙芒屨，丹經一布囊。", "好登祝融頂，紅橘迸扶桑。"]'),
('e77ad460-506b-432e-ab0a-26e5b5f3a63e','寄楊休文','李叔與','宋','宋诗','song-poetry','','[]','溪園雪凝古梅枝，我逐歸雲子到時。',64,'全唐诗/poet.song.202000.json','["溪園雪凝古梅枝，我逐歸雲子到時。", "交一臂間遲面見，乃千里外話心期。", "人緣至此猶難合，天意其然欲對移。", "擬辦瘦藤聞束擔，有何山水未經詩。"]'),
('a57e19a4-5543-4d24-a69d-8eae25322d75','舟中寄磵谷','李叔與','宋','宋诗','song-poetry','','[]','秋風四起秋雲薄，客懷頗欠商量著。',112,'全唐诗/poet.song.202000.json','["秋風四起秋雲薄，客懷頗欠商量著。", "淺灘膠舟石犖确，欲進不可退難却。", "蘋蓼妝成秋綽約，獨倚晚風吟思涸。", "故人雲錦自天落，一紙模糊萬金藥。", "上言相思下離索，勾引蓴鱸味逾惡。", "吾心孤雲身野鶴，到此方知出山錯。", "歸理綠簑更青蒻，何處方舟無杜若。"]'),
('dfaa0ea0-2fb0-4465-b444-1d049e5d0363','山窗雜詩  其一','李叔與','宋','宋诗','song-poetry','','[]','學把鉏頭蒔小畦，牡丹不種種荼縻。',32,'全唐诗/poet.song.202000.json','["學把鉏頭蒔小畦，牡丹不種種荼縻。", "花開贏得年年看，棘蔓猶堪補敗籬。"]'),
('d52bdf18-97ff-4782-9b2e-42bd2af98270','山窗雜詩  其二','李叔與','宋','宋诗','song-poetry','','[]','一樣春風到町畦，物成春亦不能齊。',32,'全唐诗/poet.song.202000.json','["一樣春風到町畦，物成春亦不能齊。", "過籬新笋貪成竹，不管同根未脫泥。"]'),
('4ab4d745-f1e4-4a18-8f03-a66465158ae0','山窗雜詩  其三','李叔與','宋','宋诗','song-poetry','','[]','夜久寒爐火尚紅，隔山誰動五更鍾。',32,'全唐诗/poet.song.202000.json','["夜久寒爐火尚紅，隔山誰動五更鍾。", "小童和夢移燈去，不管殘書讀未終。"]'),
('ae1fe070-39e1-4c1b-9d40-c72626964b8a','內河  其一','李叔與','宋','宋诗','song-poetry','','[]','短蓬邀我到常州，入郭猶如野渡頭。',32,'全唐诗/poet.song.202000.json','["短蓬邀我到常州，入郭猶如野渡頭。", "忽有畫橋楊柳岸，柳中依約見青樓。"]'),
('fbc6d624-e3a0-47e6-a537-e9d22e01ebde','內河  其二','李叔與','宋','宋诗','song-poetry','','[]','隔岸青松數百株，柳陰陰處結茅廬。',32,'全唐诗/poet.song.202000.json','["隔岸青松數百株，柳陰陰處結茅廬。", "溪翁有此不知趣，乞與詩人作退居。"]'),
('5e3ab137-3771-4302-8996-8d9cd9208bf1','烏衣園  其一','李叔與','宋','宋诗','song-poetry','','[]','綠陰庭院夏初長，梅子新肥杏子黄。',32,'全唐诗/poet.song.202000.json','["綠陰庭院夏初長，梅子新肥杏子黄。", "枝上莫彈秦吉了，遊人借此當笙簧。"]'),
('2ca17b03-1c1f-43fa-a263-1696a3900835','烏衣園  其二','李叔與','宋','宋诗','song-poetry','','[]','烏衣三徑去年開，庭樹幽陰綠作堆。',32,'全唐诗/poet.song.202000.json','["烏衣三徑去年開，庭樹幽陰綠作堆。", "胡蝶不知人是客，雙雙飛入矮牆來。"]'),
('44257c6f-1c7f-4247-8a08-66e51079dc10','層樓  其一','李叔與','宋','宋诗','song-poetry','','[]','半空和月倚新秋，十二欄干曲曲愁。',32,'全唐诗/poet.song.202000.json','["半空和月倚新秋，十二欄干曲曲愁。", "我亦天涯零落者，不如飲到醉歸休。"]'),
('21761b08-dc09-4e16-9fa7-e5c0b1a04a20','層樓  其二','李叔與','宋','宋诗','song-poetry','','[]','臺城勝概得同遊，爛醉西風藥玉舟。',32,'全唐诗/poet.song.202000.json','["臺城勝概得同遊，爛醉西風藥玉舟。", "目送歸雲天一角，教人生怕上層樓。"]'),
('7257b7f2-12b5-4164-baa2-83c8a3b6db10','山窗','李叔與','宋','宋诗','song-poetry','','[]','掛起山窗滿眼秋，小溪寒處竹深幽。',64,'全唐诗/poet.song.202000.json','["掛起山窗滿眼秋，小溪寒處竹深幽。", "有詩戲爾教兒誦，無酒歸而與婦謀。", "窗爲防風須密補，籬因禦寇更完脩。", "怕無人可論心事，賸種梅花在屋頭。"]'),
('9e32c17b-10f8-4d40-b299-3b31ebf62970','山窗雜詩  其一','李叔與','宋','宋诗','song-poetry','','[]','柳花收絮麥收芒，安石榴開日漸長。',32,'全唐诗/poet.song.202000.json','["柳花收絮麥收芒，安石榴開日漸長。", "窗下小儒無一事，自携新水活菖陽。"]'),
('753b7c7f-e3cb-43ed-8d92-19b56b75a19e','山窗雜詩  其二','李叔與','宋','宋诗','song-poetry','','[]','月照西窗夜未闌，起來和墨研池乾。',32,'全唐诗/poet.song.202000.json','["月照西窗夜未闌，起來和墨研池乾。", "急忙欲寫梅花賦，敲碎溪冰一片寒。"]'),
('d5336806-7a78-47d0-b94a-6fb09d184a11','題李伯章蓬窗','李叔與','宋','宋诗','song-poetry','','[]','短蓬留雪映窗紗，一似王家訪戴家。',32,'全唐诗/poet.song.202000.json','["短蓬留雪映窗紗，一似王家訪戴家。", "到底王家風味淺，月痕低處欠梅花。"]'),
('0feeede1-3021-4359-9dd2-560358ac5918','題劉總郎書堂屏上','李叔與','宋','宋诗','song-poetry','','[]','懷人已仙去，書堂猶昔時。',48,'全唐诗/poet.song.202000.json','["懷人已仙去，書堂猶昔時。", "夜夢雖微茫，晝日儼在茲。", "我欲載遺事，簡素多亡遺。", "目前尚如此，後世誰相知。"]'),
('049772cc-a219-432c-8a76-9dede374e41c','偶成','李叔與','宋','宋诗','song-poetry','','[]','撲斷清貧事，蕭然一室居。',48,'全唐诗/poet.song.202000.json','["撲斷清貧事，蕭然一室居。", "雨將苔曼衍，秋與蕙清癯。", "火白衣猶煖，香焦味有餘。", "山中足詩思，豈必灞橋馿。"]'),
('cf4c9ff6-ab44-40c7-83de-405686c300a5','題徐後湖扣舷歌卷末','李叔與','宋','宋诗','song-poetry','','[]','吾欲釣魚東海去，一葉扁舟未能具。',118,'全唐诗/poet.song.202000.json','["吾欲釣魚東海去，一葉扁舟未能具。", "君呼小舫山水間，扣舷作歌秋水寒。", "吾詩百篇不直一盃水，君歌一闋遊鱼亦傾耳。", "得君此編拱璧加明冰，玉笥陵雲無此清。", "安能移我龍湖白竺之茅屋，來並清江後湖曲。", "我鳴榔，君扣舷。", "醉歌長篇復短篇，却使後人呼作徐李同舟仙。"]'),
('b338f4eb-1530-4b7f-8d32-14c2f5ab3faf','送李仲炳歸  其一','李叔與','宋','宋诗','song-poetry','','[]','君家渝水我螺川，同是江南百里天。',32,'全唐诗/poet.song.202000.json','["君家渝水我螺川，同是江南百里天。", "同道同心更同姓，只年相遠却忘年。"]'),
('367db573-85cb-44cd-a306-cfc4c94ba856','送李仲炳歸  其二','李叔與','宋','宋诗','song-poetry','','[]','扁舟同載石頭城，雨打孤蓬夜共聽。',32,'全唐诗/poet.song.202000.json','["扁舟同載石頭城，雨打孤蓬夜共聽。", "愁殺明朝桃葉渡，陽關無曲柳能青。"]'),
('3b947778-be58-4654-b61d-0f095e610b9c','送李仲炳歸  其三','李叔與','宋','宋诗','song-poetry','','[]','思歸恨臂不成翰，却笑誰令汝出山。',32,'全唐诗/poet.song.202000.json','["思歸恨臂不成翰，却笑誰令汝出山。", "夢暫得歸歸未得，且編歸夢寄書還。"]'),
('7eb9a9ab-0eb1-4295-a569-624321681933','贈談天','李叔與','宋','宋诗','song-poetry','','[]','我坐詩窮子術窮，十年湖海兩漂蓬。',32,'全唐诗/poet.song.202000.json','["我坐詩窮子術窮，十年湖海兩漂蓬。", "子歸農圃吾歸釣，此去懸知命可通。"]'),
('df3e95bf-3ca9-4e08-83f5-b8eb63e30aa1','暮春感興','何基','宋','宋诗','song-poetry','','[]','郊原春向深，幽居寡來往。',132,'全唐诗/poet.song.202000.json','["郊原春向深，幽居寡來往。", "和風日披拂，淑氣遍萬象。", "草本意欣榮，禽鳥聲下上。", "靜中觀物化，胸次得浩養。", "緬懷浴沂人，從容侍函丈。", "舍瑟自言志，宣聖獨深賞。", "一私盡消融，萬理悉照朗。", "其人不可見，其意尚可想。", "我生千載後，恨不操几杖。", "春服雖已成，童冠乏儔黨。", "安得同心人，詠歸嗣遺響。"]'),
('5de4eef0-b476-49a0-8fb5-4cace9a16f76','和吳巽之石菖蒲','何基','宋','宋诗','song-poetry','','[]','菖蒲綠茸茸，偏得高人憐。',60,'全唐诗/poet.song.202000.json','["菖蒲綠茸茸，偏得高人憐。", "心清境自勝，何必幽澗邊。", "節老葉愈勁，色定枝不妍。", "堂中賢主人，與汝俱蕭然。", "豈不與世接，自遠塵俗沾。"]'),
('5c81256f-7ede-4795-8d8c-6015d8d916e6','西山孝子吟','何基','宋','宋诗','song-poetry','','[]','君不見東京茅季偉，布褐躬耕具甘旨。',386,'全唐诗/poet.song.202000.json','["君不見東京茅季偉，布褐躬耕具甘旨。", "烹雞饋母供晨羞，却辦草蔬爲客禮。", "北州高士郭林宗，一見驚嗟不能已。", "又不見唐朝董邵南，窮居行義無與比。", "朝耕夜讀養雙親，孝格天翁降祥祉。", "一時好事昌黎公，爲作啟詩歌盛美。", "兩君制行固已奇，姓名自足垂千祀。", "更有高賢爲發揮，至今赫然在人耳。", "幾年見說西山汪，信義當時表閭里。", "只今家雖四壁空，却有賢孫祖風似。", "力田養親孝行高，千載董茅同一軌。", "孑然隻影無妻兒，手自耔耘供滫瀡。", "乃翁喪明三十年，膝下承顔不離跬。", "三時但務親耕鋤，一日何曾入城市。", "朝朝敬問衣燠寒，旦旦謹察食豐菲。", "一畦早韭登春盤，五母黄雞薦秋黍。", "盡心自足爲親歡，豈必三牲八珍侈。", "謹身百不貽親憂，父子熙熙和氣裏。", "翁目雖瞽翁心怡，八十龐眉反兒齒。", "邇來缾粟頗不慳，積善固宜天相只。", "鄉閭詠嘆同一聲，養志如君能有幾。", "人有詩書君未學，我謂如君真學矣。", "孝弟是乃百行先，爲仁每必從此始。", "世人有親不能養，浪著儒冠誠可恥。"]'),
('433518f4-336a-4fed-9b0b-f6147568e0a0','老菊次時所性韻','何基','宋','宋诗','song-poetry','','[]','獨步東籬餐落菊，一幅烏紗漉浮玉。',144,'全唐诗/poet.song.202000.json','["獨步東籬餐落菊，一幅烏紗漉浮玉。", "悠然謝客欲醉眠，懶拾枯枝炮脫粟。", "靖節先生骨已寒，回生何必須神丹。", "紫陽一字冠青史，名節恃此安如山。", "義熙一去知幾變，金鈿翠葆猶年年。", "我生因循顛已華，甚矣今年脫左車。", "嘲紅弄綠少時態，歲晚相對惟寒花。", "雨荒深院黄金盡，誰謂顔色埋塵沙。", "高風雅致隨遇見，簾外玉立橫枝斜。"]'),
('714f542c-8f8a-49e6-80ff-c2538f93f287','題定武蘭亭副本','何基','宋','宋诗','song-poetry','','[]','文皇命殉昭陵土，蘭亭神蹟埋千古。',160,'全唐诗/poet.song.202000.json','["文皇命殉昭陵土，蘭亭神蹟埋千古。", "率更搨本勒堅珉，鹽帝歸裝留定武。", "薛家翻刻愚貴游，舊本和龕歸御府。", "烟塵橫空飛渡河，中原荆棘交豹虎。", "維揚蒼蒞駕南轅，百年文物不堪補。", "紛紛好事競新摹，傾敧醜俗亡遺矩。", "如今薛本亦罕見，髤𬴧典型猶媚嫵。", "清歡盛會何足傳，右軍他帖以千數。", "託言此筆不可再，慨然陳迹興懷語。", "今昔相視無已時，手掩塵編對秋雨。"]'),
('001c86c3-92d6-4800-8a87-7e46fff51e37','訪楊船山道中迷塗和王元思韻','何基','宋','宋诗','song-poetry','','[]','審問方知道，冥行易失岐。',48,'全唐诗/poet.song.202000.json','["審問方知道，冥行易失岐。", "每因貪徑捷，多致落嶔巇。", "浪謂途言惑，先由己意移。", "知津要端的，直造始無疑。"]'),
('b6b9609d-5e52-4774-995a-8ed3dbfddcce','春日閒居','何基','宋','宋诗','song-poetry','','[]','輕陰薄薄籠朝曦，小雨斑斑濕燕泥。',32,'全唐诗/poet.song.202000.json','["輕陰薄薄籠朝曦，小雨斑斑濕燕泥。", "春草階前隨意綠，曉鶑花裏盡情啼。"]'),
('86679270-22ee-4c79-a5bf-914ac32be96a','春晚郊行','何基','宋','宋诗','song-poetry','','[]','村烟澹澹日沈西，岸柳陰陰水拍堤。',32,'全唐诗/poet.song.202000.json','["村烟澹澹日沈西，岸柳陰陰水拍堤。", "江上晚風吹樹急，落紅滿地鷓鴣啼。"]'),
('36f53840-b10a-4999-9a96-a661d00183ea','法清寺水珠呈杜季高','何基','宋','宋诗','song-poetry','','[]','壘石爲山已浪呼，小球戲水更名珠。',32,'全唐诗/poet.song.202000.json','["壘石爲山已浪呼，小球戲水更名珠。", "世間何事非虛假，還值先生一笑無。"]'),
('ed8dfb06-518a-4147-8dac-24de58ed47cb','夾竹梅','何基','宋','宋诗','song-poetry','','[]','不染世間兒女塵，任他桃李自爭春。',32,'全唐诗/poet.song.202000.json','["不染世間兒女塵，任他桃李自爭春。", "也應高潔難爲對，獨有修篁是可人。"]'),
('bc268040-cefb-4fea-9ad7-1ef146d4be9f','寬兒輩','何基','宋','宋诗','song-poetry','','[]','丈夫何事怕饑窮，況復簞瓢亦未空。',32,'全唐诗/poet.song.202000.json','["丈夫何事怕饑窮，況復簞瓢亦未空。", "萬卷詩書真活計，一山梅竹自清風。"]'),
('e209bb59-92a1-47a9-a769-df91f94689a8','雜詩  其一','何基','宋','宋诗','song-poetry','','[]','一敬由來入道門，須臾不在便非仁。',32,'全唐诗/poet.song.202000.json','["一敬由來入道門，須臾不在便非仁。", "直須認取惺惺法，莫作回頭錯應人。"]'),
('673522c9-7610-416e-8a4e-8a6fea41129c','雜詩  其二','何基','宋','宋诗','song-poetry','','[]','善惡分明雖兩歧，念端差處只毫釐。',32,'全唐诗/poet.song.202000.json','["善惡分明雖兩歧，念端差處只毫釐。", "怕將私意爲天理，所以先民貴致知。"]'),
('4f5234f6-1cbc-445e-8f4f-794f291a3eb9','雜詩  其三','何基','宋','宋诗','song-poetry','','[]','聖門事業遠難攀，立志須同古孔顔。',32,'全唐诗/poet.song.202000.json','["聖門事業遠難攀，立志須同古孔顔。", "井不及泉猶棄井，山如虧簣未爲山。"]'),
('00f95d34-adc6-4e77-b32d-9cac098449ac','送王敬巖江東都憲  其一','何基','宋','宋诗','song-poetry','','[]','褰帷不憚暑天長，少試平生活國方。',32,'全唐诗/poet.song.202000.json','["褰帷不憚暑天長，少試平生活國方。", "吏蠹民冤盡梳洗，要令枯旱變豐穰。"]'),
('7c73677f-62ff-4722-9fe1-fe818a02c110','送王敬巖江東都憲  其二','何基','宋','宋诗','song-poetry','','[]','獄情微曖自難明，著意平反或失平。',32,'全唐诗/poet.song.202000.json','["獄情微曖自難明，著意平反或失平。", "生死兩無纖芥恨，考求須盡察須精。"]'),
('b8e73067-7f1b-4fd0-930b-d5bd99f52f4c','送王敬巖江東都憲  其三','何基','宋','宋诗','song-poetry','','[]','功夫真處在持操，外澤中乾亦謾勞。',32,'全唐诗/poet.song.202000.json','["功夫真處在持操，外澤中乾亦謾勞。", "獨探聖言求實用，豈同末俗爲名高。"]'),
('16dcadd8-1377-4c19-b298-045e7661f214','繳回太守趙庸齋照牒','何基','宋','宋诗','song-poetry','','[]','閉關方喜得幽棲，何用邦侯更品題。',32,'全唐诗/poet.song.202000.json','["閉關方喜得幽棲，何用邦侯更品題。", "自分終身守環堵，不將一步出盤溪。"]'),
('090864f1-a094-42b4-8f49-96f1e4a8278d','題徐伯光真','何基','宋','宋诗','song-poetry','','[]','舞雩春服浴沂侶，社飲衣簑學稼翁。',32,'全唐诗/poet.song.202000.json','["舞雩春服浴沂侶，社飲衣簑學稼翁。", "可士可農隨地樂，此心無處不春風。"]'),
('dc10edf6-13af-426b-bf47-8f4187d420a3','送淮西左憲知黄州','何基','宋','宋诗','song-poetry','','[]','日向庭闈綵服趨，天邊忽下紫泥書。',64,'全唐诗/poet.song.202000.json','["日向庭闈綵服趨，天邊忽下紫泥書。", "分銅既佩諸侯印，衣繡仍登使者車。", "萬竈貔貅須宿飽，九州鴻雁要安居。", "笑談了却公家事，指日催歸侍玉除。"]'),
('b54f40d5-a8fd-4267-87c4-d3b62d1f3d6d','海棠','何基','宋','宋诗','song-poetry','','[]','幾樹繁紅一徑深，春風裁剪錦成屏。',32,'全唐诗/poet.song.202000.json','["幾樹繁紅一徑深，春風裁剪錦成屏。", "花前莫作淵村恨，且看楊妃睡未醒。"]'),
('c206cdf8-011e-46cf-a92b-b2693cd908ea','寒夜寄友','何基','宋','宋诗','song-poetry','','[]','月色窺人冷，梅花何處香。',24,'全唐诗/poet.song.202000.json','["月色窺人冷，梅花何處香。", "遥思棲隠客，高嘯白雲鄉。"]'),
('fb0bbc0a-9d22-4265-bbb4-07da916368a7','句','何基','宋','宋诗','song-poetry','','[]','皓首何妨一布衣。',8,'全唐诗/poet.song.202000.json','["皓首何妨一布衣。"]'),
('2016d71f-3a3e-4785-b063-fd1556bfd6fd','夜泊長河','許棐','宋','宋诗','song-poetry','','[]','黄帽貪程夜泊遲，市樓燈火歇多時。',32,'全唐诗/poet.song.202000.json','["黄帽貪程夜泊遲，市樓燈火歇多時。", "滿懷風月無分付，却借漁翁短笛吹。"]'),
('78a21d82-3c78-43ca-9594-ded73195de61','訪潘叔明','許棐','宋','宋诗','song-poetry','','[]','一室寬於養鶴籠，荻簾疏透雪花風。',32,'全唐诗/poet.song.202000.json','["一室寬於養鶴籠，荻簾疏透雪花風。", "怪來几案無寒色，春在題詩卷子中。"]'),
('a6b071d2-d02e-463d-9d73-09ee7ab2f1ec','明妃','許棐','宋','宋诗','song-poetry','','[]','漢宮眉斧息邊塵，功壓貔貅百萬人。',32,'全唐诗/poet.song.202000.json','["漢宮眉斧息邊塵，功壓貔貅百萬人。", "好把香閨舊脂粉，豔妝顔色上麒麟。"]'),
('5934cb2a-e633-4098-89db-dcd69427e8e3','醉起','許棐','宋','宋诗','song-poetry','','[]','午醉醺醺到日晡，起呼茶盌炷熏爐。',32,'全唐诗/poet.song.202000.json','["午醉醺醺到日晡，起呼茶盌炷熏爐。", "隔窗幾點敲花雨，子細聽時却又無。"]'),
('27d05e07-ffc1-4f09-b047-cf3c93412d77','帕子','許棐','宋','宋诗','song-poetry','','[]','萬縷縱橫如妾恨，一方輕薄似郎恩。',32,'全唐诗/poet.song.202000.json','["萬縷縱橫如妾恨，一方輕薄似郎恩。", "多時不繫纖腰舞，却對花前拭淚痕。"]'),
('fcb168c3-4dab-4ce2-b10c-3c6491c6b4c6','晚泊臨平','許棐','宋','宋诗','song-poetry','','[]','晚卸風帆泊市橋，稅亭民屋總蕭條。',32,'全唐诗/poet.song.202000.json','["晚卸風帆泊市橋，稅亭民屋總蕭條。", "秦封不到河邊柳，送往迎來枉折腰。"]'),
('56065e35-84eb-4bf8-9931-f80bdadb846e','元夕後湖上作','許棐','宋','宋诗','song-poetry','','[]','自從樓閣罷燒燈，未有今朝一日晴。',64,'全唐诗/poet.song.202000.json','["自從樓閣罷燒燈，未有今朝一日晴。", "暖拆葑邊冰翼破，寒留山頂雪痕輕。", "嬌驄已印尋芳跡，小妓新翻鬻唱聲。", "每箇旗亭商一醉，也應排日到清明。"]'),
('791bf27c-b50f-4fc2-b739-56f110b13fa3','沈子壽郊居','許棐','宋','宋诗','song-poetry','','[]','屋外猶餘地百弓，經鋤知費幾年工。',64,'全唐诗/poet.song.202000.json','["屋外猶餘地百弓，經鋤知費幾年工。", "栽蔬少似於陵仲，種菊多於靖節翁。", "偃屈溪山詩卷裏，破除風月酒杯中。", "近來又喜禪機透，一顧叢林萬衲空。"]'),
('308f67f1-c91c-4bf9-8de4-7324e4e8268e','贈葉靖逸','許棐','宋','宋诗','song-poetry','','["\u897f\u6e56"]','借得城居一丈寬，五車書向腹中安。',64,'全唐诗/poet.song.202000.json','["借得城居一丈寬，五車書向腹中安。", "聲華馥似當風桂，氣味清於著露蘭。", "朝士時將餘俸贈，鋪家傳得近詩刊。", "回看舊隠西湖上，誰伴沙鷗度歲寒。"]'),
('2e0131e3-0cb7-4461-b660-7b12f91b0e62','鄭介道見訪','許棐','宋','宋诗','song-poetry','','[]','步頭楊柳種多年，今日方維勝客船。',64,'全唐诗/poet.song.202000.json','["步頭楊柳種多年，今日方維勝客船。", "掃石共看山色坐，枕書同聽雨聲眠。", "溪羹旋煮蓴絲滑，野飯新炊芡玉圓。", "不管歸心忙似箭，强留吟過菊花天。"]'),
('d3238094-f2af-4111-9249-5bd6f5de855f','贈龔彥質','許棐','宋','宋诗','song-poetry','','[]','慈湖分與半窗燈，照得襟懷徹底明。',64,'全唐诗/poet.song.202000.json','["慈湖分與半窗燈，照得襟懷徹底明。", "蒲座夜閑貓占卧，筍輿春暖鶴隨行。", "爐香欲盡經猶誦，硯墨才濃句已成。", "歲晚弟兄俱白首，一樓風雨話深更。"]'),
('12c9e0c9-fb9e-49cb-af03-a9e977835c85','題常穆仲蘸碧','許棐','宋','宋诗','song-poetry','','[]','舫樣一亭小，依山復靠池。',48,'全唐诗/poet.song.202000.json','["舫樣一亭小，依山復靠池。", "每來分席坐，須憶下湖時。", "竹弄當窗影，花添蘸水枝。", "人間風浪惡，泛宅幾天涯。"]'),
('527c7435-6941-4c15-b5bc-a2e69d339104','趙叔魯','許棐','宋','宋诗','song-poetry','','[]','天上除書駱驛飛，謫僊何事得來遲。',64,'全唐诗/poet.song.202000.json','["天上除書駱驛飛，謫僊何事得來遲。", "旅懷寬似居家日，學力高於未第時。", "山带晴霏橫畫軸，水流清響入琴絲。", "世間多少王孫貴，無我寒泉一句詩。"]'),
('26646be6-fb37-4dcd-bd3d-1ecea98b3cda','秋江漁父','許棐','宋','宋诗','song-poetry','','[]','小舟輕似一鷗飛，戀月隨風慣不歸。',32,'全唐诗/poet.song.202000.json','["小舟輕似一鷗飛，戀月隨風慣不歸。", "困卧蘆花深雪裏，夜寒添蓋舊蓑衣。"]'),
('94aaaac2-4f1e-468e-8d31-0e28becabd52','山間','許棐','宋','宋诗','song-poetry','','[]','趁得山間笋蕨春，借厨烹煮自吹薪。',32,'全唐诗/poet.song.202000.json','["趁得山間笋蕨春，借厨烹煮自吹薪。", "倩誰分我杯羹去，寄與中朝食肉人。"]'),
('f3f3b3e1-0886-4f4e-b0e1-a1e9a5a56e93','木山父書院','許棐','宋','宋诗','song-poetry','','[]','占得文房一丈强，地幽雖夏亦清凉。',64,'全唐诗/poet.song.202000.json','["占得文房一丈强，地幽雖夏亦清凉。", "瓶花誤倒水侵案，書葉亂掀風滿床。", "薜長密藤遮半壁，桐分疏影出低牆。", "客來莫道無祗待，只啜茶甌却味長。"]'),
('840be31b-b990-4242-9a1f-2cebcc56c745','蠟梅江梅同瓶','許棐','宋','宋诗','song-poetry','','[]','苗裔元從庾嶺分，兩般標致一般春。',64,'全唐诗/poet.song.202000.json','["苗裔元從庾嶺分，兩般標致一般春。", "淡妝西子呈嬌態，黄面瞿曇現小身。", "不羨腰金橫玉貴，來尋嚼蠟飲冰人。", "只愁花謝香狼籍，桃李如何接後陳。"]'),
('5d1340c7-e33b-44b5-ad57-452cc29c4e61','贈畫魚沈秀才','許棐','宋','宋诗','song-poetry','','[]','寫字摛文不療饑，生涯換得頗新奇。',64,'全唐诗/poet.song.202000.json','["寫字摛文不療饑，生涯換得頗新奇。", "錦心暗織臨淵網，蓬鬢潜繅釣雨絲。", "落筆易於投餌處，得錢多似出罾時。", "漁翁枉占煙波闊，不及君家小硯池。"]'),
('6bb07431-ccb4-40f9-820a-e0044a104ea8','贈北磵','許棐','宋','宋诗','song-poetry','','[]','天下名山行脚遍，依然形影瘦伶俜。',64,'全唐诗/poet.song.202000.json','["天下名山行脚遍，依然形影瘦伶俜。", "支吾寒暑袈裟耐，變眩煙霞筆硯靈。", "對客敬如堂上佛，讀書通似藏中經。", "石頭路滑終難到，不是詩禪莫扣扃。"]'),
('101f5bc9-ee39-4112-aefb-7d1ae0b5bc4a','雪曉','許棐','宋','宋诗','song-poetry','','[]','臘雪連宵接曉飛，錦衾公子未曾知。',32,'全唐诗/poet.song.202000.json','["臘雪連宵接曉飛，錦衾公子未曾知。", "起來携杖敲梅樹，扶得輕盈壓損枝。"]'),
('7b5532d8-7363-41b6-96bd-c9b58c8a6a73','閨怨五首  其一','許棐','宋','宋诗','song-poetry','','[]','眉鎖從春不暫開，懶移心事向妝臺。',32,'全唐诗/poet.song.202000.json','["眉鎖從春不暫開，懶移心事向妝臺。", "恩情恰似殘花片，去逐東流更不迴。"]'),
('f36ab1d4-bdff-4994-a173-87488aab20da','閨怨五首  其二','許棐','宋','宋诗','song-poetry','','[]','別後相思瘦玉肌，不堪重著看花衣。',32,'全唐诗/poet.song.202000.json','["別後相思瘦玉肌，不堪重著看花衣。", "恨君得似梁間燕，社日辭家社日歸。"]'),
('2da2660f-41dd-4b94-83e2-2a0b819323c6','閨怨五首  其三','許棐','宋','宋诗','song-poetry','','[]','月引庭花影上窗，悶和簪朶卧空床。',32,'全唐诗/poet.song.202000.json','["月引庭花影上窗，悶和簪朶卧空床。", "春寒翠被無人共，閑却熏爐一字香。"]'),
('8d9904d8-389f-4560-b354-1cd07d516c6b','閨怨五首  其四','許棐','宋','宋诗','song-poetry','','[]','離愁一點濃如黛，强把金篦掃不開。',32,'全唐诗/poet.song.202000.json','["離愁一點濃如黛，强把金篦掃不開。", "新月幾番呈巧樣，薄情夫壻未歸來。"]'),
('10da9e67-c1eb-4c0d-8bdb-d7dc413b4f82','閨怨五首  其五','許棐','宋','宋诗','song-poetry','','[]','小院東風去住中，春愁元不隔簾櫳。',32,'全唐诗/poet.song.202000.json','["小院東風去住中，春愁元不隔簾櫳。", "自家顔色凋零盡，却對花枝惜墮紅。"]'),
('1a86ec04-28e3-4e47-9ff3-dabd77297749','枯荷','許棐','宋','宋诗','song-poetry','','[]','萬柄綠荷衰颯盡，雨中無可蓋眠鷗。',32,'全唐诗/poet.song.202000.json','["萬柄綠荷衰颯盡，雨中無可蓋眠鷗。", "當時乍疊青錢滿，肯信池塘有暮秋。"]'),
('90cf59ac-f5bf-4c60-99f7-819428dfd1c3','庭樹','許棐','宋','宋诗','song-poetry','','[]','今年庭樹著花稀，因是耽書失事治。',32,'全唐诗/poet.song.202000.json','["今年庭樹著花稀，因是耽書失事治。", "何處結巢雙喜鵲，却來刪得幾枯枝。"]'),
('aeadb282-cc1e-41d4-9ebe-511bfc233f00','春晚','許棐','宋','宋诗','song-poetry','','[]','推過詩編把酒斟，挽春佳句讓鶑吟。',32,'全唐诗/poet.song.202000.json','["推過詩編把酒斟，挽春佳句讓鶑吟。", "門前却喜無人掃，積得殘花一寸深。"]'),
('b1c32a26-391a-4076-b1de-0df5f3f35020','贈臨上人','許棐','宋','宋诗','song-poetry','','[]','遶湖山疊翠，師住最高層。',48,'全唐诗/poet.song.202000.json','["遶湖山疊翠，師住最高層。", "野偈書林葉，茶鐺煮澗冰。", "松筠爲道友，日月是禪燈。", "儻許分峰隠，甘爲有髮僧。"]'),
('5d9e2b1e-402e-4486-b3d5-34e00cefbfb4','客路','許棐','宋','宋诗','song-poetry','','[]','客路久驅馳，秋深兩鬢知。',48,'全唐诗/poet.song.202000.json','["客路久驅馳，秋深兩鬢知。", "田家投夜宿，漁竈寄晨炊。", "契分燈前影，生涯橐裏詩。", "遥憐故園菊，荒草沒霜枝。"]'),
('68ee811e-b2d0-4c79-87d9-fe38b0d3ea21','鍾俊卿見訪','許棐','宋','宋诗','song-poetry','','[]','荒圃知非延客地，謾分苔石坐移時。',64,'全唐诗/poet.song.202000.json','["荒圃知非延客地，謾分苔石坐移時。", "杯中淺注三行酒，几上同看數板詩。", "樹未經霜飛葉早，菊因閏月放花遲。", "自無景物留君住，却恨西山日半規。"]'),
('347c8068-f877-4c95-9472-b7477f34f54b','題倦庵','許棐','宋','宋诗','song-poetry','','[]','自扁庵爲倦，斯名恐未然。',48,'全唐诗/poet.song.202000.json','["自扁庵爲倦，斯名恐未然。", "醉巾頻漉破，遊屐幾磨穿。", "新種竹都活，舊栽花更妍。", "門前春水漲，催發孝廉船。"]'),
('6738627f-d57e-49d8-ba56-1f6238cc8e95','贈元耘軒','許棐','宋','宋诗','song-poetry','','[]','白髮蕭蕭客帝都，故園閑却種瓜鉏。',64,'全唐诗/poet.song.202000.json','["白髮蕭蕭客帝都，故園閑却種瓜鉏。", "平時不信爲儒誤，今日方知涉世疏。", "煙浦未尋歸去艇，雪窗猶讀借來書。", "詩名壓盡江湖客，要在唐人向上居。"]'),
('c1eac774-240f-44c6-aa49-5273c8bd33eb','題吳叔清郊居','許棐','宋','宋诗','song-poetry','','[]','哦松未了賦歸歟，旋買田園結草廬。',64,'全唐诗/poet.song.202000.json','["哦松未了賦歸歟，旋買田園結草廬。", "數畝竹陰惟欠鶴，半池山影不妨魚。", "舉杯多是沽來酒，插架無非讀過書。", "我已倦爲都下客，願君分與把茅居。"]'),
('99d3237b-c0ce-4b18-900a-ddea0e281c27','書郭子度壁','許棐','宋','宋诗','song-poetry','','[]','禁苑精廬是切鄰，衣巾雖舊不沾塵。',64,'全唐诗/poet.song.202000.json','["禁苑精廬是切鄰，衣巾雖舊不沾塵。", "鐘魚聲裏吟連曉，花柳香中醉過春。", "和土重泥燒藥竈，買絲新接釣魚綸。", "遶湖十萬人家住，如此清閑有幾人。"]'),
('ec467731-578d-45ef-bd01-ae4467b3ecca','雁字','許棐','宋','宋诗','song-poetry','','[]','點畫分明印碧空，迴鸞返鵲勢差同。',64,'全唐诗/poet.song.202000.json','["點畫分明印碧空，迴鸞返鵲勢差同。", "月邊映得銀鈎體，雪裏摹成玉箸工。", "斷續似經秦火後，悲凉如在楚詞中。", "愁人筆硯俱荒廢，倩寫相思寄便風。"]'),
('31fccbba-c935-4685-8e6b-c29123f69336','宮詞二首  其一','許棐','宋','宋诗','song-poetry','','[]','卧聽羊車輥夜雷，知從誰處燕酣回。',32,'全唐诗/poet.song.202000.json','["卧聽羊車輥夜雷，知從誰處燕酣回。", "蟾光也解君王意，隔箇簾櫳不入來。"]'),
('e185d5d0-662f-42e9-b347-780877879489','宮詞二首  其二','許棐','宋','宋诗','song-poetry','','[]','同入宮來幾許人，因何遣妾護長門。',32,'全唐诗/poet.song.202000.json','["同入宮來幾許人，因何遣妾護長門。", "雲鬟半脫香腮瘦，却愛菱花鏡子昏。"]'),
('74386c2c-2877-44fb-908c-fe0707b158c9','古墓','許棐','宋','宋诗','song-poetry','','[]','石人猶自立蒿萊，拂讀殘碑字字哀。',32,'全唐诗/poet.song.202000.json','["石人猶自立蒿萊，拂讀殘碑字字哀。", "鄰冢已澆寒食酒，野風分送紙錢來。"]'),
('8a143829-2a89-49e8-8952-4396ee8ff5df','憶鄭元甫','許棐','宋','宋诗','song-poetry','','[]','別後黄花兩度殘，天涯彼此寄書難。',32,'全唐诗/poet.song.202000.json','["別後黄花兩度殘，天涯彼此寄書難。", "幾行雁字斜陽裏，聊當平安一紙看。"]'),
('05676262-68d7-47c0-9939-3b789718e9a7','贈芸窗','許棐','宋','宋诗','song-poetry','','[]','能書能畫又能詩，除却芸窗別數誰。',32,'全唐诗/poet.song.202000.json','["能書能畫又能詩，除却芸窗別數誰。", "只是霜毫冰繭紙，才經拈起便新奇。"]'),
('c628f329-2932-49fd-b02e-394979ed3335','戍婦詞一首','許棐','宋','宋诗','song-poetry','','[]','半落釭花午夜閑，戍衣裁就寄君難。',32,'全唐诗/poet.song.202000.json','["半落釭花午夜閑，戍衣裁就寄君難。", "雁來不带平安字，却带邊風入帳寒。"]'),
('36fb5568-3362-48e5-b5af-be2adbc0c787','贈陳宗之','許棐','宋','宋诗','song-poetry','','[]','六月長安熱似焚，廛中清趣總輸君。',32,'全唐诗/poet.song.202000.json','["六月長安熱似焚，廛中清趣總輸君。", "買書人散桐陰晚，卧看風行水上文。"]'),
('46692c1a-dc54-47a6-aeda-752128f0bed8','傷春曲','許棐','宋','宋诗','song-poetry','','[]','日日望郎郎未歸，玉肌寬盡縷金衣。',96,'全唐诗/poet.song.202000.json','["日日望郎郎未歸，玉肌寬盡縷金衣。", "春心撩亂强拘束，碎剪紅綃補舊枝。", "紅綃才向枝頭住，殘花又逐東風去。", "願花飛入笑筵中，莫入愁人斷腸處。", "愁人見花人自羞，花見愁人花也愁。", "花飛有盡愁無盡，柳外一聲黄栗留。"]'),
('ddc9f560-0d8e-4791-9843-97a0beab2f6c','四時宮詞各一首  其一','許棐','宋','宋诗','song-poetry','','[]','因見落花心覺悟，薄羅襟上淚痕乾。',32,'全唐诗/poet.song.202000.json','["因見落花心覺悟，薄羅襟上淚痕乾。", "容顔縱似花枝好，能得君王幾日看。"]'),
('4ee2bf9c-7938-4115-9444-a0c9682e54e3','四時宮詞各一首  其二','許棐','宋','宋诗','song-poetry','','[]','碧玉凉梳落枕邊，懶梳雙鬢學新蟬。',32,'全唐诗/poet.song.202000.json','["碧玉凉梳落枕邊，懶梳雙鬢學新蟬。", "恩情不及班姬扇，縱是炎天亦棄捐。"]'),
('c0c0a0f0-270f-4b26-b2aa-5f61b7aee1e2','四時宮詞各一首  其三','許棐','宋','宋诗','song-poetry','','[]','凉夜誰同玉簟眠，湘波冷浸一枝蓮。',32,'全唐诗/poet.song.202000.json','["凉夜誰同玉簟眠，湘波冷浸一枝蓮。", "君王不學中秋月，處處分身處處圓。"]'),
('7838d28c-0e4f-4bce-868c-143156cf9074','四時宮詞各一首  其四','許棐','宋','宋诗','song-poetry','','[]','雪壓長門消未盡，夜衾堆盡舊宮羅。',32,'全唐诗/poet.song.202000.json','["雪壓長門消未盡，夜衾堆盡舊宮羅。", "鴛鴦瓦下垂冰筯，未抵思君玉筯多。"]'),
('e18a9ed5-3754-49cc-bcf9-b9de707f69b1','郭評事','許棐','宋','宋诗','song-poetry','','[]','廷評滿腹貯陽春，筆下從來活幾人。',64,'全唐诗/poet.song.202000.json','["廷評滿腹貯陽春，筆下從來活幾人。", "廳小似分幽寺住，俸輕如在舊山貧。", "堆書教子猶疑少，倒屣迎賓不厭頻。", "欲效林宗巾角墊，自嫌雙鬢有紅塵。"]'),
('a0e5e97e-6022-4cc1-92d3-92a7daded214','挽吳春伯','許棐','宋','宋诗','song-poetry','','[]','入門諸子哭褰衣，痛說嚴君屬纊時。',64,'全唐诗/poet.song.202000.json','["入門諸子哭褰衣，痛說嚴君屬纊時。", "病重刀圭難作效，家貧衾含不如儀。", "從春屢有登臨約，近日方無唱和詩。", "執紼南屏山下路，悲風吹亂綠楊絲。"]'),
('3726b6dd-533e-4489-9b02-6b38795a0e13','挽郭子度','許棐','宋','宋诗','song-poetry','','[]','連年染患貌梔黄，盧扁猶無起死方。',64,'全唐诗/poet.song.202000.json','["連年染患貌梔黄，盧扁猶無起死方。", "稚女自敲尸畔磬，鄰僧來炷佛前香。", "生涯謾有千書卷，受用惟存一奠觴。", "聽說茶毗心更苦，拭乾清淚又成行。"]'),
('aff9b26d-1312-46ff-80b4-59b87f7ca00d','寄吳宜之','許棐','宋','宋诗','song-poetry','','[]','文公徒弟無多在，學術應如壽數高。',64,'全唐诗/poet.song.202000.json','["文公徒弟無多在，學術應如壽數高。", "好句先教諸子和，墊巾翻被俗人嘲。", "湖邊茶店同誰坐，井畔柴扉欠我敲。", "昨夜相思眠不穩，月眉斜印落花梢。"]'),
('a7100f08-a95d-4edc-912a-a04eb034d024','瑛上人','許棐','宋','宋诗','song-poetry','','[]','十二三時便出家，何曾頃刻離煙霞。',64,'全唐诗/poet.song.202000.json','["十二三時便出家，何曾頃刻離煙霞。", "晨持數卷日方上，夜梵千聲月未斜。", "洗鉢不經鷗浴水，插瓶嫌採蝶殘花。", "儒冠誤我駸駸老，何日蒲團共結跏。"]'),
('e1960dcd-3c5d-4c98-92bc-a5f941e81134','木芙蓉','許棐','宋','宋诗','song-poetry','','[]','芙蓉豔金谷，秋色錦機中。',24,'全唐诗/poet.song.202000.json','["芙蓉豔金谷，秋色錦機中。", "霜樹不知醜，葉與花爭紅。"]'),
('0e93ab15-1bb4-422d-b2ce-13fec81c3208','東歸道中','許棐','宋','宋诗','song-poetry','','[]','芙蓉波面出罾魚，廉似城中買擔蔬。',32,'全唐诗/poet.song.202000.json','["芙蓉波面出罾魚，廉似城中買擔蔬。", "欲試膾刀還不忍，恐傷千里寄人書。"]'),
('6665f4d0-0161-4b16-bf2a-a9178952b21a','籠禽怨','許棐','宋','宋诗','song-poetry','','[]','千金新購入雕籠，恨在嬌聲斷續中。',32,'全唐诗/poet.song.202000.json','["千金新購入雕籠，恨在嬌聲斷續中。", "昨夜羈雌何處宿，落花殘月故巢空。"]'),
('c22e8b3c-7759-4d7b-add1-385858252beb','破鏡詞','許棐','宋','宋诗','song-poetry','','[]','寶鏡一從分破後，不堪磨拭照妝鈿。',32,'全唐诗/poet.song.202000.json','["寶鏡一從分破後，不堪磨拭照妝鈿。", "倩誰携上青雲去，補得今宵缺月圓。"]'),
('369194ba-e400-4dc3-b9ee-f8b4178406a9','龔彥質恕可二丈','許棐','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兩龔當暑客秦溪，旋買黄綀替熟衣。',32,'全唐诗/poet.song.202000.json','["兩龔當暑客秦溪，旋買黄綀替熟衣。", "想見西湖風月裏，藕花凝望載詩歸。"]'),
('f7a1eaba-4750-44f3-9da5-bef0a65314ad','張聲父','許棐','宋','宋诗','song-poetry','','[]','城中破屋妻兒住，自向招提借小房。',64,'全唐诗/poet.song.202000.json','["城中破屋妻兒住，自向招提借小房。", "壁上碑文皆古篆，案頭書冊半僊方。", "月嫌碎竹遮窗暗，風款飛花入座香。", "點檢未如僧相處，只多髭鬢幾莖霜。"]'),
('bdc8a666-82db-4846-89a8-45152d503ffd','秋齋即事','許棐','宋','宋诗','song-poetry','','[]','桂香吹過中秋了，菊傍重陽未肯開。',32,'全唐诗/poet.song.202000.json','["桂香吹過中秋了，菊傍重陽未肯開。", "幾日銅瓶無可浸，賺他饑蝶入窗來。"]'),
('434dd41e-a0ab-4513-89c1-043a3cac643b','泛剡','許棐','宋','宋诗','song-poetry','','[]','水闊無風似有風，蘆花摇落櫓聲中。',32,'全唐诗/poet.song.202000.json','["水闊無風似有風，蘆花摇落櫓聲中。", "鷗無一點驚猜意，認作當時載雪翁。"]'),
('9ab2dbbf-a002-45ad-9488-9e216cf5cf97','醉歸','許棐','宋','宋诗','song-poetry','','[]','半醉歸來卧不成，月華霜彩爛中庭。',32,'全唐诗/poet.song.202000.json','["半醉歸來卧不成，月華霜彩爛中庭。", "茶鐺凍結香匜冷，只把梅花嗅得醒。"]'),
('52d6b5c1-6432-41c2-88c9-e05b50692b69','湖上曲','許棐','宋','宋诗','song-poetry','','[]','新晴旋蠟遊春屐，半濕香泥恰好行。',32,'全唐诗/poet.song.202000.json','["新晴旋蠟遊春屐，半濕香泥恰好行。", "琢得小詞腔未穩，往來花下怯歌鶑。"]'),
('76961e28-0abb-44e6-b868-9fe893fec767','趙野雲','許棐','宋','宋诗','song-poetry','','[]','載雨駕雷翻覆頃，漏星藏月卷舒間。',32,'全唐诗/poet.song.202000.json','["載雨駕雷翻覆頃，漏星藏月卷舒間。", "若將雲與詩人比，政恐雲無日日閑。"]'),
('d38494b2-85e4-4976-81fb-4218eb7e9128','古硯送趙明府','許棐','宋','宋诗','song-poetry','','[]','一片端州古硯磚，翁孫相授當良田。',64,'全唐诗/poet.song.202000.json','["一片端州古硯磚，翁孫相授當良田。", "寒梅磵下和冰洗，秋桂窗前滴露研。", "學字不工空費紙，吟詩雖苦未成編。", "贈君携去薇花畔，草詔閑時枕匣眠。"]'),
('2cbfadf2-44ce-441f-a5c5-4b67dd2597b9','戲題花片','許棐','宋','宋诗','song-poetry','','[]','一片落花題一字，湊成一首怨春詩。',32,'全唐诗/poet.song.202000.json','["一片落花題一字，湊成一首怨春詩。", "縱橫貼在窗紗上，巧似迴文織錦時。"]'),
('07581e1d-ee32-4e97-b482-f6ddca2e1d3f','寄衣曲','許棐','宋','宋诗','song-poetry','','[]','蘆花風緊雁飛飛，便寄邊衣也是遲。',64,'全唐诗/poet.song.202000.json','["蘆花風緊雁飛飛，便寄邊衣也是遲。", "妾把剪刀猶覺冷，况君披甲枕戈時。", "願君百戰圖勳業，馘項殲嬴頻獻捷。", "博取貂蟬金印歸，無負君王無負妾。"]'),
('5e87beb4-18d7-463a-8b1b-18c85b6e13f8','畫眉曲','許棐','宋','宋诗','song-poetry','','[]','日印花枝欲滿窗，旋磨鸞鏡試新妝。',32,'全唐诗/poet.song.202000.json','["日印花枝欲滿窗，旋磨鸞鏡試新妝。", "恩情只似春宵短，眉黛空如柳葉長。"]'),
('2ea7fa94-3503-4648-9d4e-7c0f56ede9bb','宿閑林步','許棐','宋','宋诗','song-poetry','','[]','山禽棲定澗蛙鳴，時復鴟梟雜數聲。',32,'全唐诗/poet.song.202000.json','["山禽棲定澗蛙鳴，時復鴟梟雜數聲。", "昨夜酒添春睡重，幸無憎愛到天明。"]'),
('5df67b52-502f-4899-ac95-46dab24ad253','宮女詞','許棐','宋','宋诗','song-poetry','','[]','妍醜三千衆，恩情一例輕。',24,'全唐诗/poet.song.202000.json','["妍醜三千衆，恩情一例輕。", "妾身雖寂寞，天下却升平。"]'),
('92253db0-cb18-4996-8f99-a07b1898e2d1','真珠園','許棐','宋','宋诗','song-poetry','','[]','芭蕉葉上題詩字，雨後來看半不全。',32,'全唐诗/poet.song.202000.json','["芭蕉葉上題詩字，雨後來看半不全。", "餘濕未勝濃墨補，且携巵酒到花前。"]'),
('c85753c7-b060-455b-bda8-4e2a97886a1f','湖邊','許棐','宋','宋诗','song-poetry','','[]','湖邊開到木芙蓉，攘盡荷花十里紅。',32,'全唐诗/poet.song.202000.json','["湖邊開到木芙蓉，攘盡荷花十里紅。", "紅蓼莫慙顔色淺，榮枯同是一秋風。"]'),
('88e9ac64-a8f9-42d3-9cbd-c2792b0d69ce','讀南嶽新稿','許棐','宋','宋诗','song-poetry','','["\u8861\u5c71"]','春來遊未遍湖山，已是風光一半殘。',32,'全唐诗/poet.song.202000.json','["春來遊未遍湖山，已是風光一半殘。", "細把劉郎詩讀後，鶑花雖好不須看。"]'),
('1cf77882-6dae-4761-8962-ae40fe7781cd','花','許棐','宋','宋诗','song-poetry','','[]','牆頭新露一枝紅，壓盡隋人萬綵工。',32,'全唐诗/poet.song.202000.json','["牆頭新露一枝紅，壓盡隋人萬綵工。", "香豔便棲雲鬢老，也勝飄泊晚西風。"]'),
('23123b14-c0f6-4c76-b0f6-7af8390709db','別友','許棐','宋','宋诗','song-poetry','','[]','分付離觴莫滿斟，酒深還與恨同深。',32,'全唐诗/poet.song.202000.json','["分付離觴莫滿斟，酒深還與恨同深。", "自憐不及春江燕，一路相隨伴好吟。"]'),
('ce25a003-f0b0-4dff-87b3-f3981da1a4ca','不語僧','許棐','宋','宋诗','song-poetry','','[]','默坐蒲龕若塑成，客來惟聽小鐘鳴。',32,'全唐诗/poet.song.202000.json','["默坐蒲龕若塑成，客來惟聽小鐘鳴。", "却嫌庭樹無禪力，時有風枝雨葉聲。"]'),
('006adab2-e88f-4bd7-961d-d51a9e02ab1a','孔海翁','許棐','宋','宋诗','song-poetry','','[]','鑑湖湖上寄閑身，好景應同賀監分。',64,'全唐诗/poet.song.202000.json','["鑑湖湖上寄閑身，好景應同賀監分。", "梅下有船供載雪，荷邊無地可鉏雲。", "吟人多倩刪詩稿，名士爭求作序文。", "畫卷書編藏滿屋，其他生計盡輸君。"]'),
('33de4483-c68d-4056-b68a-4bc620dff3be','題縣樓呈丘竹坡','許棐','宋','宋诗','song-poetry','','[]','令君聊試棟梁材，結就譙樓亦壯哉。',64,'全唐诗/poet.song.202000.json','["令君聊試棟梁材，結就譙樓亦壯哉。", "疑是海宮新湧出，不然僊府乍移來。", "無人敢带私心入，萬戶皆知正道開。", "細數代瓜能幾日，曉籌昏鼓莫相催。"]'),
('a4f7de39-99da-41a6-8db0-07ca1175e28a','寄題竹坡','許棐','宋','宋诗','song-poetry','','[]','郭外移來費俸金，幾年擡舉玉成林。',64,'全唐诗/poet.song.202000.json','["郭外移來費俸金，幾年擡舉玉成林。", "更無餘地栽閑樹，儘有高枝著卧禽。", "寒影似傳東野貌，清聲如寫伯夷心。", "呼童少殺青瑶簡，染月濡雲寄我吟。"]'),
('f7a63315-4e3f-4903-b8da-fc5ca2d7ba03','數椽','許棐','宋','宋诗','song-poetry','','[]','數椽茅屋傍林塘，幽似山僧獨住房。',64,'全唐诗/poet.song.202000.json','["數椽茅屋傍林塘，幽似山僧獨住房。", "夜靜只憑猿守宅，晝閑時有鶴升堂。", "旋收落葉供茶爨，細搗枯花作印香。", "書冊滿床詩滿橐，別無生計亦何妨。"]'),
('0deebfc6-2baa-42e8-ad5f-41ccb596ea32','送友人爲僧','許棐','宋','宋诗','song-poetry','','[]','知心朋友雲霄裏，三尺官綾取不難。',64,'全唐诗/poet.song.202000.json','["知心朋友雲霄裏，三尺官綾取不難。", "禪衲乍披身愈瘦，儒冠新脫頂微寒。", "數編詩稿聊收起，一藏經文旋取看。", "惟我塵緣推不去，蕭蕭華髮倦漁竿。"]'),
('20bf615d-6b88-4b48-be62-0aa872ed81cd','地爐','許棐','宋','宋诗','song-poetry','','[]','穴地爲爐了一寒，肉屏氈帳任無緣。',64,'全唐诗/poet.song.202000.json','["穴地爲爐了一寒，肉屏氈帳任無緣。", "晨燒樹下沾霜葉，夜煮山頭瀉月泉。", "已借陽和歸故絮，更分光焰到殘編。", "百年貧富灰埃盡，荒冢纍纍野燒邊。"]'),
('b76272d2-86cf-4eca-b7e8-0c1909ef2b30','春雪','許棐','宋','宋诗','song-poetry','','[]','東風吹雨作花飛，寒勒芳程幾日遲。',32,'全唐诗/poet.song.202000.json','["東風吹雨作花飛，寒勒芳程幾日遲。", "惟有庭前老梅樹，謝渠添補落殘枝。"]'),
('5f2203b8-ecee-42e5-8c81-a7d819a6a9c5','挽沈晏如','許棐','宋','宋诗','song-poetry','','[]','不信詩人一例窮，如公半世又成空。',64,'全唐诗/poet.song.202000.json','["不信詩人一例窮，如公半世又成空。", "湖邊便欠尋梅友，籬下應無采菊翁。", "雪片堆平閑藥竈，雨聲敲碎舊漁篷。", "墓銘吟稿兒封寄，血淚斑斑浣紙紅。"]'),
('7a5a3312-a8dd-474e-8efe-5fa33deca1e1','贈相士','許棐','宋','宋诗','song-poetry','','[]','澗水溪冰似鏡清，自看寒貌已分明。',32,'全唐诗/poet.song.202000.json','["澗水溪冰似鏡清，自看寒貌已分明。", "煩君別相江湖友，來歲誰魁淡墨名。"]'),
('c106ba7c-ac2e-4cdd-9d45-f51cdeaf288e','陳裕齋墨戲','許棐','宋','宋诗','song-poetry','','[]','臨帖鈔書外，尤深破墨工。',48,'全唐诗/poet.song.202000.json','["臨帖鈔書外，尤深破墨工。", "萬峰千嶂趣，片紙尺綃中。", "雲暗孤村月，潮生滿樹風。", "自嫌吾已老，摩硯一無功。"]'),
('6c5c7a47-f3f2-477d-8a87-f70cbcb1939e','題吳秋潭隠居圖','許棐','宋','宋诗','song-poetry','','[]','到處有茅堪蓋屋，誰家遷槿不成籬。',32,'全唐诗/poet.song.202000.json','["到處有茅堪蓋屋，誰家遷槿不成籬。", "秋潭何事經營晚，應是無人會買詩。"]'),
('e547cd18-8cfa-4475-a93d-973edee8d885','題摩雲','許棐','宋','宋诗','song-poetry','','[]','老松陰下訪摩雲，仰望青雲隔幾塵。',32,'全唐诗/poet.song.202000.json','["老松陰下訪摩雲，仰望青雲隔幾塵。", "不是倚空梯百尺，只緣中有道高人。"]'),
('0eb459d4-40fe-4b7a-b2ea-ca5b318fabf6','田間','許棐','宋','宋诗','song-poetry','','[]','田間久不到，草木半蕭疏。',48,'全唐诗/poet.song.202000.json','["田間久不到，草木半蕭疏。", "鷗占沉舟浴，蛩分破壁居。", "僕溫携到酒，鄰送賣殘蔬。", "未說催租事，黏窗且讀書。"]'),
('1720e0f5-d1f7-48cd-817b-ad0b414806b6','題野處','許棐','宋','宋诗','song-poetry','','[]','數畝家園枕碧波，樹桑疏處補花窠。',64,'全唐诗/poet.song.202000.json','["數畝家園枕碧波，樹桑疏處補花窠。", "簷低不礙儒冠入，橋矮才通釣艇過。", "雲笛旋裁門外竹，雨衣新織檻前莎。", "有時牛背看書罷，一曲春風甯戚歌。"]'),
('c5bf984b-745b-4911-b858-8ea3db9c6574','孫祺卿新居','許棐','宋','宋诗','song-poetry','','[]','幾年銖累束脩錢，才向湖邊置一廛。',64,'全唐诗/poet.song.202000.json','["幾年銖累束脩錢，才向湖邊置一廛。", "種竹庭深難得月，養魚池小易爲泉。", "山呈好畫當書案，柳撒輕絲罩釣船。", "酒力半酣詩思倦，矮床相對白鷗眠。"]'),
('b7f4e35f-dd55-4e2a-8d1a-4b1ed3312f25','招高菊澗','許棐','宋','宋诗','song-poetry','','[]','歸買秦溪屋一間，才如都下僦樓寬。',64,'全唐诗/poet.song.202000.json','["歸買秦溪屋一間，才如都下僦樓寬。", "門前養草如花賞，壁上黏碑當畫看。", "自改舊詩多未穩，獨斟新酒不成歡。", "髯仙只在淵明宅，泥濘相邀寸步難。"]'),
('da146044-e528-4b41-97af-249c3f271b39','李明府雪中小閲','許棐','宋','宋诗','song-poetry','','[]','令君蒙雪教千兵，一點妖氛不敢生。',64,'全唐诗/poet.song.202000.json','["令君蒙雪教千兵，一點妖氛不敢生。", "和氣旋回弓力軟，寒光微映劍花明。", "民居似倚銀城壯，海道如鋪玉簟平。", "入蔡歸來方夜半，畫堂歌管未收聲。"]'),
('c9c39f6d-f393-40c5-8d63-e51031853695','西真圖','許棐','宋','宋诗','song-poetry','','[]','翠水池邊宴早秋，雲謠聲裏月西流。',32,'全唐诗/poet.song.202000.json','["翠水池邊宴早秋，雲謠聲裏月西流。", "醉歸不信乘鸞穩，却擘蓮花作采舟。"]'),
('95bbb46e-b856-4f44-98e4-0a39a289fcce','書北庵門','許棐','宋','宋诗','song-poetry','','[]','十度來敲九不應，隔籬空見竹青青。',32,'全唐诗/poet.song.202000.json','["十度來敲九不應，隔籬空見竹青青。", "不知池裏黄金鯽，聽講楞伽幾卷經。"]'),
('7cc0cf58-f1d3-45fc-bb6d-a8310144fed5','贈術士張癡','許棐','宋','宋诗','song-poetry','','[]','伶俐不如癡，從來我亦知。',48,'全唐诗/poet.song.202000.json','["伶俐不如癡，從來我亦知。", "才吟詩好日，便是命窮時。", "鼠笑瓶無粟，蝸嫌壁有碑。", "五行修得否，髭鬢已絲絲。"]'),
('669f9aa2-441f-49b9-845e-cb2dc0834005','謝毓齋李尚書惠詩序','許棐','宋','宋诗','song-poetry','','[]','綠野堂邊種藥成，已斑髭鬢復青青。',64,'全唐诗/poet.song.202000.json','["綠野堂邊種藥成，已斑髭鬢復青青。", "謝庭子弟皆英物，漢殿公卿半學生。", "爭捧溪藤求妙畫，競磨崖石乞新銘。", "如何海角孤吟者，文集中間也掛名。"]'),
('dc490fac-816f-4d90-a41c-f5feb534d15a','葉充齋','許棐','宋','宋诗','song-poetry','','[]','歙浦租船只載詩，一廉如此似君稀。',32,'全唐诗/poet.song.202000.json','["歙浦租船只載詩，一廉如此似君稀。", "雙親猶道行裝重，多带羅紋一硯歸。"]'),
('2b791097-d186-49ec-beef-5a77c75fae9c','題趙子固春山上寺圖','許棐','宋','宋诗','song-poetry','','[]','望得招提見，程猶半日間。',48,'全唐诗/poet.song.202000.json','["望得招提見，程猶半日間。", "馬嘶曾到處，僕指未行山。", "風遞松聲遠，雲連草色閑。", "何如添箇我，坐石聽潺湲。"]'),
('8603b3f4-9e5d-44e8-86c3-8b5dec2a47d8','湯婆子','許棐','宋','宋诗','song-poetry','','[]','一冬專寵道人房，不藉華清賜浴湯。',64,'全唐诗/poet.song.202000.json','["一冬專寵道人房，不藉華清賜浴湯。", "皤腹却無璋瓦分，矮身難稱綺羅妝。", "春生蝴蝶半床夢，暖迫梅花一帳香。", "醉倚肉屏君莫羨，北邙多少黑頭郎。"]'),
('4e28936a-aca8-4799-8fcb-04fcf07009ea','送寫神李肖巖入道','許棐','宋','宋诗','song-poetry','','[]','一掣塵緣去學仙，鶴程風露漸高寒。',32,'全唐诗/poet.song.202000.json','["一掣塵緣去學仙，鶴程風露漸高寒。", "白玉樓中逢鼻祖，爲傳吟貌寄予看。"]'),
('71a2fc44-fb1c-4ac3-af0b-46bc0454108b','寄趙倉','許棐','宋','宋诗','song-poetry','','[]','麾節交迎出帝城，滿朝皆羨板輿榮。',64,'全唐诗/poet.song.202000.json','["麾節交迎出帝城，滿朝皆羨板輿榮。", "一州暫輟春風暖，八郡同瞻霽月明。", "吳苑鶑花新管領，秦溪桃李舊生成。", "應憐倦卧寒窗者，煮藥爐邊聽雪聲。"]'),
('90603602-ab7f-4669-9daa-4743ee5c7e86','送趙子梁','許棐','宋','宋诗','song-poetry','','[]','梅福舟行速，離觴不暇斟。',48,'全唐诗/poet.song.202000.json','["梅福舟行速，離觴不暇斟。", "雖然交日淺，頗覺別情深。", "宿處雁相伴，到時鶑對吟。", "水心新冢下，替我一沾襟。"]'),
('1a1a20e7-9d1a-4f57-9b00-5d46cfb15efd','得閑亭','許棐','宋','宋诗','song-poetry','','[]','柳風雖小絲絲裊，花雨無多點點香。',32,'全唐诗/poet.song.202000.json','["柳風雖小絲絲裊，花雨無多點點香。", "惟有吟毫閑未得，染紅濡綠一春忙。"]'),
('02aa6e76-9cf3-43e0-bb77-f727be862c9f','題錢慶豐醒庵','許棐','宋','宋诗','song-poetry','','[]','不向杯中物，吟邊僅有君。',48,'全唐诗/poet.song.202000.json','["不向杯中物，吟邊僅有君。", "自無沉醉分，非效獨醒人。", "捲箔進明月，開門放宿雲。", "揀茶敲未遍，又摘露芽春。"]'),
('7c1eba40-aeba-41b1-b606-193e7fc521e9','挽周倅','許棐','宋','宋诗','song-poetry','','[]','真是分風月，歸來無俸錢。',48,'全唐诗/poet.song.202000.json','["真是分風月，歸來無俸錢。", "人皆嗤拙宦，天又嗇長年。", "舊宅寒潮外，新塋古樹邊。", "一詩哀不盡，簷雨對潸然。"]'),
('61c1b842-3aff-493c-8050-dbc8ce45d2a8','上趙蘭坡','許棐','宋','宋诗','song-poetry','','[]','身迫雲霄自不知，只如師友講論時。',64,'全唐诗/poet.song.202000.json','["身迫雲霄自不知，只如師友講論時。", "驅龍駕鳳陽冰字，剪月裁霞太白詩。", "雨院炷香熏畫卷，晴窗添水浸花枝。", "十年漫走江湖上，只尺蘭坡却到遲。"]'),
('66ae9a6d-d5ba-4df0-a497-a4b351e2c144','上嘉禾趙守','許棐','宋','宋诗','song-poetry','','[]','邦君一念只寬民，真箇龔黄現後身。',64,'全唐诗/poet.song.202000.json','["邦君一念只寬民，真箇龔黄現後身。", "和氣蒸爲千耒雨，暖雲裁作萬襦春。", "座中長有清吟客，庭下渾無健訟人。", "諸郡盡能依此樣，世間那有一家貧。"]'),
('9f9a39bb-0700-44c8-a1d1-4b7faa96cb7f','劍言','許棐','宋','宋诗','song-poetry','','[]','朝潤郅支膏，暮澤樓蘭血。',24,'全唐诗/poet.song.202000.json','["朝潤郅支膏，暮澤樓蘭血。", "何如沉土中，蝕爲無用鐵。"]'),
('00fbeafe-0c84-46b6-a211-e6179b64a4a3','題常宣仲草堂','許棐','宋','宋诗','song-poetry','','[]','隔市能幾步，幽趣踰山林。',72,'全唐诗/poet.song.202000.json','["隔市能幾步，幽趣踰山林。", "鑿池小如斗，水淺魚自深。", "簷任樹枝礙，階從草色侵。", "不肯一鋤斫，恐傷春風心。", "朝出貨仁義，暮歸炊古今。", "客來無可款，石爐添水沉。"]'),
('a5cc39f1-f8de-4986-9d6c-b819ea4ec677','題張俞仲竹屋','許棐','宋','宋诗','song-poetry','','[]','削成千蠹簡，此屋是餘材。',48,'全唐诗/poet.song.202000.json','["削成千蠹簡，此屋是餘材。", "長有清風至，渾無俗客來。", "猿當吟案立，鶴趁釣船迴。", "添足歲寒計，栽松復種梅。"]'),
('24a987e2-e021-49d4-968f-f7e0c4215831','李方庵款梅','許棐','宋','宋诗','song-poetry','','[]','梅花惆悵三年別，香鎖空庭幾風月。',64,'全唐诗/poet.song.202000.json','["梅花惆悵三年別，香鎖空庭幾風月。", "今年花發主人歸，依舊主人貧徹骨。", "小枝分立硯屏邊，無酒酬春燭焰寒。", "數葉殘書繙未了，喚起山童敲鳳團。"]'),
('f0d9302b-0f4b-45dc-bde3-ac5b4edb94b6','樂府  其一','許棐','宋','宋诗','song-poetry','','[]','妾心如鏡面，一規秋水清。',24,'全唐诗/poet.song.202000.json','["妾心如鏡面，一規秋水清。", "郎心如鏡背，磨殺不分明。"]'),
('fa5c2f37-646f-41cb-8cf1-43faebbba28e','樂府  其二','許棐','宋','宋诗','song-poetry','','[]','小窗寒燭夜，結紐綴郎襟。',24,'全唐诗/poet.song.202000.json','["小窗寒燭夜，結紐綴郎襟。", "不結尋常紐，結郎長遠心。"]'),
('16e88caa-474f-4551-8280-d6207575fb3a','樂府  其三','許棐','宋','宋诗','song-poetry','','[]','郎身如紙鳶，斷線隨風去。',24,'全唐诗/poet.song.202000.json','["郎身如紙鳶，斷線隨風去。", "願得上林枝，爲妾縈留住。"]'),
('e94e82bf-ab3f-4511-b9c7-1bfdfef6b151','題舒王遊半山圖','許棐','宋','宋诗','song-poetry','','[]','馿載新詩僕抱書，松聲禽語當傳呼。',32,'全唐诗/poet.song.202000.json','["馿載新詩僕抱書，松聲禽語當傳呼。", "不知邂逅耕田者，問著青苗免役無。"]'),
('77fa3af0-2ddf-49a3-ba5b-57c569313f35','題錢叔恭立齋銘後','許棐','宋','宋诗','song-poetry','','[]','拄義撐仁難著脚，十人著脚九斜欹。',32,'全唐诗/poet.song.202000.json','["拄義撐仁難著脚，十人著脚九斜欹。", "此銘不特爲君助，今古儒家砥柱碑。"]'),
('92bb87dd-3024-4cdf-bdb7-2c732bbf20fb','舊漁竿','許棐','宋','宋诗','song-poetry','','[]','掣斷江湖幾線風，蓑衣閑掛餌瓢空。',32,'全唐诗/poet.song.202000.json','["掣斷江湖幾線風，蓑衣閑掛餌瓢空。", "何因獻入君王手，持向磻溪釣太公。"]'),
('0c0daf6a-d5a2-4995-83c0-58538032cb0b','草屨','許棐','宋','宋诗','song-poetry','','[]','江湖蓑笠舊交情，石滑泥深步轉輕。',32,'全唐诗/poet.song.202000.json','["江湖蓑笠舊交情，石滑泥深步轉輕。", "恰是革華蹤跡險，宦程高處越難行。"]'),
('65b17a05-1832-4caf-adb6-511dbbe7f712','贈劉相士','許棐','宋','宋诗','song-poetry','','[]','滿鏡秋霜鬢影寒，此生堪笑復堪憐。',32,'全唐诗/poet.song.202000.json','["滿鏡秋霜鬢影寒，此生堪笑復堪憐。", "煩君只相看書眼，更對青燈得幾年。"]'),
('7cce2d53-567e-40ae-a9b0-e4359810eb5b','宗之惠梅窠水玉牋','許棐','宋','宋诗','song-poetry','','[]','百幅吳冰千蘂雪，對吟終日不成詩。',32,'全唐诗/poet.song.202000.json','["百幅吳冰千蘂雪，對吟終日不成詩。", "憶君同在孤山下，商略春風弄筆時。"]'),
('a97c76da-3320-4697-9bd1-aa99ed9a4317','月澗惠硯滴梅腦  其一','許棐','宋','宋诗','song-poetry','','[]','手不題詩已數年，硯磚相伴學枯禪。',32,'全唐诗/poet.song.202000.json','["手不題詩已數年，硯磚相伴學枯禪。", "爲君蘸濕玄暉筆，寫出江山雪後天。"]'),
('1717b070-c34f-4dff-9333-12d14479fcb2','月澗惠硯滴梅腦  其二','許棐','宋','宋诗','song-poetry','','[]','踏雪尋梅興未償，衣襟頼有隔年香。',32,'全唐诗/poet.song.202000.json','["踏雪尋梅興未償，衣襟頼有隔年香。", "銅𠤷更炷冰花腦，不到孤山也不妨。"]'),
('1e2d149f-1fbf-468c-8d57-c4b72ef2d13c','春思','許棐','宋','宋诗','song-poetry','','[]','嫁得蕭郎不戀家，幾年流落在天涯。',32,'全唐诗/poet.song.202000.json','["嫁得蕭郎不戀家，幾年流落在天涯。", "滿懷多少傷春事，嫌殺門前叫賣花。"]'),
('44f3156c-180e-45e0-98fc-c100a5f70e70','送趙丞','許棐','宋','宋诗','song-poetry','','[]','竹梢風露松梢月，未抵吟丞氣味清。',32,'全唐诗/poet.song.202000.json','["竹梢風露松梢月，未抵吟丞氣味清。", "笑問兩年何所得，錦囊詩重俸囊輕。"]'),
('8c0cbcc9-0128-438c-af30-3c5aa39f6022','贈墨僧','許棐','宋','宋诗','song-poetry','','[]','老硯磨穿事不成，萬書堆裏鬢星星。',32,'全唐诗/poet.song.202000.json','["老硯磨穿事不成，萬書堆裏鬢星星。", "願隨君去柯山下，收拾殘煙寫佛經。"]'),
('e409dd2b-24e7-4435-b75e-9e71af84c72c','重陽乏酒','許棐','宋','宋诗','song-poetry','','[]','黄花冷笑竹籬邊，笑我床頭乏酒錢。',32,'全唐诗/poet.song.202000.json','["黄花冷笑竹籬邊，笑我床頭乏酒錢。", "带雨折來無用處，碎挼金屑和茶煎。"]'),
('13014e42-84ad-49f4-a918-81d124758eb3','燭','許棐','宋','宋诗','song-poetry','','[]','長身夜占銀臺立，焰焰光摇頂上珠。',32,'全唐诗/poet.song.202000.json','["長身夜占銀臺立，焰焰光摇頂上珠。", "貪向華堂照歌舞，不知灰得寸心無。"]'),
('dcc7ca1d-47f9-42e0-8f33-f5507333864d','代術者言','許棐','宋','宋诗','song-poetry','','[]','不聞沸鼎烹夷叔，那有雲臺畫四凶。',32,'全唐诗/poet.song.202000.json','["不聞沸鼎烹夷叔，那有雲臺畫四凶。", "自與心君消息了，却將甲乙問窮通。"]'),
('21b71d5e-d95c-48dc-b1b0-eddb96a54879','贈錢相士','許棐','宋','宋诗','song-poetry','','[]','我貌君容一種寒，鷺漂鷗泊廿來年。',32,'全唐诗/poet.song.202000.json','["我貌君容一種寒，鷺漂鷗泊廿來年。", "我詩吟就無人買，君相公卿煞得錢。"]'),
('c0c4437c-d6ff-4762-92e4-9d38b0ab8de4','觀松巖畫卷','許棐','宋','宋诗','song-poetry','','[]','老屐相隨四十年，慣看蒼翠聽潺湲。',32,'全唐诗/poet.song.202000.json','["老屐相隨四十年，慣看蒼翠聽潺湲。", "今朝細玩松巖畫，猶有吟行未到山。"]'),
('ef87491b-f434-473d-ae20-b5084ecb4662','吳江道中','許棐','宋','宋诗','song-poetry','','[]','一別吳松二十秋，敗荷枯柳總新愁。',32,'全唐诗/poet.song.202000.json','["一別吳松二十秋，敗荷枯柳總新愁。", "白頭交友凋零盡，頼有寒江幾箇鷗。"]'),
('e50b7b9a-187e-4095-aed5-3e1be23abccf','題陸宣公堂','許棐','宋','宋诗','song-poetry','','[]','一編奏議從頭讀，句句冰聯玉綴成。',64,'全唐诗/poet.song.202000.json','["一編奏議從頭讀，句句冰聯玉綴成。", "不是德宗嫌切直，自緣唐室未升平。", "諂魂盡逐殘星滅，義魄長隨霽月明。", "我亦愛君憂國者，歲時來一拜先生。"]'),
('fb69d6d1-9c7c-4c0e-8cce-e7fb27d583a0','送趙蘭坡','許棐','宋','宋诗','song-poetry','','[]','弟判嘉興藹政聲，蘭坡兄又出專城。',64,'全唐诗/poet.song.202000.json','["弟判嘉興藹政聲，蘭坡兄又出專城。", "如將天上一蟾影，分作人間兩郡明。", "江冷雪隨帆幅去，路晴梅夾轎窗行。", "開藩便拜歸班詔，也與玉山添重名。"]'),
('2cd3a3a6-b1c9-4a26-949f-95b0ac4419d5','題趙恕可山臺','許棐','宋','宋诗','song-poetry','','[]','繞宅無非罨畫山，吟臺更對好峰巒。',64,'全唐诗/poet.song.202000.json','["繞宅無非罨畫山，吟臺更對好峰巒。", "錦囊低掛花梢上，玉子輕敲竹廕間。", "小硯買來猿解捧，異書編就鶴同看。", "主人出赴功名會，澗水自清雲自閑。"]'),
('885156a7-a303-42c8-9ecb-8e5e34e82ea3','小蓑道人','許棐','宋','宋诗','song-poetry','','[]','滿面瘡痍瘢，胸中一泓雪。',52,'全唐诗/poet.song.202000.json','["滿面瘡痍瘢，胸中一泓雪。", "醒吟鶴背風，醉卧鷗邊月。", "不賣嚇鬼符，不試{熝/匕}金訣。", "笑問舊蓑衣，秋來添幾結。"]'),
('524845d0-9f90-426e-b171-a877ccb9de3e','題丘竹坡新第','許棐','宋','宋诗','song-poetry','','[]','長安富貴海，十客九倦還。',96,'全唐诗/poet.song.202000.json','["長安富貴海，十客九倦還。", "君去不著意，君歸無愧顔。", "舊圃一二畝，新居十數間。", "花尋直樹種，竹簡斜枝刪。", "詩句滿壁寫，書編到處安。", "冬簷日春煖，夏戶風晝寒。", "不是時令舛，自緣心地寬。", "天下政多事，未須牢閉關。"]'),
('3c256758-7e74-471a-97a4-e1b6ed4ab679','題雪林畫卷','許棐','宋','宋诗','song-poetry','','[]','亂灑春霙著紙寒，玉成天地片時間。',32,'全唐诗/poet.song.203000.json','["亂灑春霙著紙寒，玉成天地片時間。", "有人諳盡江湖冷，却愛尋常罨畫山。"]'),
('ab6d4785-02ee-41f2-ada7-e82bbfe84618','蘭花','許棐','宋','宋诗','song-poetry','','[]','竹底松根慣寂寥，肯隨桃李媚兒曹。',32,'全唐诗/poet.song.203000.json','["竹底松根慣寂寥，肯隨桃李媚兒曹。", "高名壓盡離騷卷，不入離騷更自高。"]'),
('95756b58-a6fc-4a49-887b-129ffa8d00be','郭南湖見訪却適有出一絕爲謝','許棐','宋','宋诗','song-poetry','','[]','一篷風雨偶歸遲，見說君來扣我扉。',32,'全唐诗/poet.song.203000.json','["一篷風雨偶歸遲，見說君來扣我扉。", "童子困眠梅樹下，不曾放得鶴雙飛。"]'),
('8cfaef4a-ad30-4f2f-91e6-0a23ec9258f8','枯樹','許棐','宋','宋诗','song-poetry','','[]','幾年柴立荒塍下，春雨秋風總不知。',32,'全唐诗/poet.song.203000.json','["幾年柴立荒塍下，春雨秋風總不知。", "一點陽和到桃李，紅紅白白便盈枝。"]'),
('d36c5e12-afbc-4137-86a0-755730fc450c','錢謙齋新居','許棐','宋','宋诗','song-poetry','','[]','住破吳松江上屋，杭州城外結新廬。',64,'全唐诗/poet.song.203000.json','["住破吳松江上屋，杭州城外結新廬。", "未尋陸羽烹茶具，先借淵明種菊鉏。", "山入樓中成好句，月來窗下伴殘書。", "御街車馬無行處，誰肯抽身覓退居。"]'),
('8efcd1f7-257f-467f-bb3d-c35cedb2546a','上趙克家太守','許棐','宋','宋诗','song-poetry','','[]','說著嘉興太守賢，野梅官柳亦歡然。',64,'全唐诗/poet.song.203000.json','["說著嘉興太守賢，野梅官柳亦歡然。", "貧民不識重租苦，老吏難將一事瞞。", "但有詩書堆几上，更無歌舞到樽前。", "凡爲郡者皆如此，天下何由不治安。"]'),
('05f7cdfb-cc0a-4263-a876-3c319f1bae8d','趙宰瓊花圖','許棐','宋','宋诗','song-poetry','','[]','祠下靈根無別種，凡花誰敢鬭榮枯。',32,'全唐诗/poet.song.203000.json','["祠下靈根無別種，凡花誰敢鬭榮枯。", "被君分種鵝谿上，從此人間有兩株。"]'),
('8a4206be-aaa8-43a6-ac36-1ecd2446ef56','寄然鏡潭','許棐','宋','宋诗','song-poetry','','[]','鏡潭炯炯秋無底，著一纖雲也是多。',32,'全唐诗/poet.song.203000.json','["鏡潭炯炯秋無底，著一纖雲也是多。", "禪外當無些子事，如何猶有作詩魔。"]'),
('d22735fc-05d2-4c3c-b848-1565016f1bd3','茉莉','許棐','宋','宋诗','song-poetry','','[]','荔枝鄉裏玲瓏雪，來助長安一夏凉。',32,'全唐诗/poet.song.203000.json','["荔枝鄉裏玲瓏雪，來助長安一夏凉。", "情味於人最濃處，夢回猶覺鬢邊香。"]'),
('00f072b6-7eb4-4d3e-97a7-a6795b3eb4ac','題猗綠堂','許棐','宋','宋诗','song-poetry','','[]','蕭蕭萬竿玉，深護讀書堂。',48,'全唐诗/poet.song.203000.json','["蕭蕭萬竿玉，深護讀書堂。", "夢趁秋聲薄，詩攙夜色凉。", "敲茶風遞響，滴硯露涵香。", "不雜有花樹，花紅不久長。"]'),
('f50764b2-af21-4314-b42a-47d139aeb3fd','趙山臺寄詩集','許棐','宋','宋诗','song-poetry','','[]','海雁叫將秋色去，山臺鈔寄好詩來。',32,'全唐诗/poet.song.203000.json','["海雁叫將秋色去，山臺鈔寄好詩來。", "菊花過了梅花未，自有花從筆底開。"]'),
('f6c902d2-8e2f-4e0c-8fd7-c523a29d050c','寄題東津','許棐','宋','宋诗','song-poetry','','[]','東津占得江山勝，安頓亭臺到處宜。',64,'全唐诗/poet.song.203000.json','["東津占得江山勝，安頓亭臺到處宜。", "夜夜中秋明月影，朝朝寒食好花枝。", "長牋短軸真行字，舊軸新編倡和詩。", "只隔一潮飛不去，悵懷惟有白鷗知。"]'),
('e8324e60-1238-451c-bb79-69b43190d4d8','寄友','許棐','宋','宋诗','song-poetry','','[]','已奏春班名字了，不妨閑作幾時遊。',32,'全唐诗/poet.song.203000.json','["已奏春班名字了，不妨閑作幾時遊。", "家僮未要裝詩擔，見說三高索倡酬。"]'),
('f98d1f34-a5e1-4b33-83f5-63f33d15b0a6','紅梅','許棐','宋','宋诗','song-poetry','','[]','不堪冷照黄昏月，强倚春風作杏粧。',32,'全唐诗/poet.song.203000.json','["不堪冷照黄昏月，强倚春風作杏粧。", "雖得容顔暫時好，欠他肌骨舊來香。"]'),
('7f436a72-a772-4c58-b15d-6d6df4b8eeb7','迓張宰','許棐','宋','宋诗','song-poetry','','[]','倦骨畏寒如畏虎，可曾一步出柴扉。',32,'全唐诗/poet.song.203000.json','["倦骨畏寒如畏虎，可曾一步出柴扉。", "因迎令尹西郊外，折得梅花滿把歸。"]'),
('bb0fdbee-4079-4e9d-b591-d1f3412b975a','謝施雲溪寄詩','許棐','宋','宋诗','song-poetry','','[]','折得桂花三數枝，雲谿又寄幾篇詩。',32,'全唐诗/poet.song.203000.json','["折得桂花三數枝，雲谿又寄幾篇詩。", "詩香入在花香裏，韻似龍涎火暖時。"]'),
('5e381f6c-3b6b-4358-835d-97a79c4bdebd','餞梅','許棐','宋','宋诗','song-poetry','','[]','十日九風雪，差見今春寒。',48,'全唐诗/poet.song.203000.json','["十日九風雪，差見今春寒。", "梅花辦歸計，一點心欲酸。", "所秉太孤潔，有此末路難。", "來年復相見，一笑賀平安。"]'),
('ed80fa9c-4c9d-492b-8333-fe33b7765563','築城曲','許棐','宋','宋诗','song-poetry','','[]','日將西，杵聲急，一聲聲自死腸出。',48,'全唐诗/poet.song.203000.json','["日將西，杵聲急，一聲聲自死腸出。", "城高不特土累成，半是鋪填怨夫骨。", "儒坑戰地骨更多，十二金人隨鬼泣。"]'),
('b9e5db09-65f9-4be4-85bd-9bafa3f9ccda','烏夜啼','許棐','宋','宋诗','song-poetry','','[]','丈人屋侵雲，烏愛丈人屋。',72,'全唐诗/poet.song.203000.json','["丈人屋侵雲，烏愛丈人屋。", "涂人亦愛烏，烏聲喜相續。", "屋底間蛾眉，環坐理絲竹。", "絲竹無新腔，寫汝聲爲曲。", "丈人一賞音，瓦礫棄珠玉。", "移噪鄰翁家，聞者皆唾逐。"]'),
('483c2eef-2b9a-4ea1-ae9c-47c87039c557','馬塍種花翁','許棐','宋','宋诗','song-poetry','','[]','東塍白髮翁，勤朴種花戶。',72,'全唐诗/poet.song.203000.json','["東塍白髮翁，勤朴種花戶。", "盆賣有根花，價重無人顧。", "西塍年少郎，荒嬉度朝暮。", "盆賣無根花，價廉爭奪去。", "年少傳語翁，同業勿相妬。", "賣假不賣真，何獨是花樹。"]'),
('f5592c3a-b781-47e4-8fbc-690f74ff347d','泥孩兒','許棐','宋','宋诗','song-poetry','','[]','牧瀆一塊泥，裝塑恣華侈。',96,'全唐诗/poet.song.203000.json','["牧瀆一塊泥，裝塑恣華侈。", "所恨肌體微，金珠載不起。", "雙罩紅紗厨，嬌立瓶花底。", "少婦初嘗酸，一玩一心喜。", "潜乞大士靈，生子願如爾。", "豈知貧家兒，呱呱瘦於鬼。", "棄卧橋巷間，誰或顧生死。", "人賤不如泥，三歎而已矣。"]'),
('c4962824-7d23-496c-b2a1-5e4bd143cc53','染絲上春機  其一','許棐','宋','宋诗','song-poetry','','[]','染絲上春機，春濃絲色淺。',24,'全唐诗/poet.song.203000.json','["染絲上春機，春濃絲色淺。", "妾心隨梭飛，郎心如軸轉。"]'),
('8342b500-aa37-4ea6-996c-2dc6028bbb77','染絲上春機  其二','許棐','宋','宋诗','song-poetry','','[]','染絲上春機，錦成貴無價。',24,'全唐诗/poet.song.203000.json','["染絲上春機，錦成貴無價。", "不忍裁成衣，怕剪鴛鴦破。"]'),
('8648ba64-999a-417e-b95a-6657896ecb30','長門怨  其一','許棐','宋','宋诗','song-poetry','','[]','妾身如蓮根，沉埋淤泥底。',24,'全唐诗/poet.song.203000.json','["妾身如蓮根，沉埋淤泥底。", "雖有白玉姿，無人爲拈洗。"]'),
('4fa25c77-a31a-4d26-af88-5091597f4c8e','長門怨  其二','許棐','宋','宋诗','song-poetry','','[]','妾身如亂絲，卷藏箱篋底。',24,'全唐诗/poet.song.203000.json','["妾身如亂絲，卷藏箱篋底。", "願上鴛鴦機，無人爲分理。"]'),
('8ebb5788-2bfa-4f7d-9b34-a8d42966cf56','秋風辭  其一','許棐','宋','宋诗','song-poetry','','[]','颯颯秋風來，一葉兩葉墜。',24,'全唐诗/poet.song.203000.json','["颯颯秋風來，一葉兩葉墜。", "燕子動歸心，薄情知也未。"]'),
('33c71bd5-ad6b-4bf3-81ab-a2d2c22f405a','秋風辭  其二','許棐','宋','宋诗','song-poetry','','[]','颯颯秋風來，衣衾愁未整。',24,'全唐诗/poet.song.203000.json','["颯颯秋風來，衣衾愁未整。", "莫作閨中寒，且作天涯冷。"]'),
('9b74e417-2fe2-4007-b15d-09e2e7f42c8f','三臺春曲  其一','許棐','宋','宋诗','song-poetry','','[]','昨夜微風細雨，今朝薄霽輕寒。',28,'全唐诗/poet.song.203000.json','["昨夜微風細雨，今朝薄霽輕寒。", "簷外一聲啼鳥，報知花柳平安。"]'),
('ae87acae-6c6a-4ae2-9610-6d9431b8ae9a','三臺春曲  其二','許棐','宋','宋诗','song-poetry','','[]','春是人間過客，花隨春不多時。',28,'全唐诗/poet.song.203000.json','["春是人間過客，花隨春不多時。", "人比花尤易老，那堪終日相思。"]'),
('56aaff0c-c072-408c-b2ee-0d292148decd','胡蝶飛','許棐','宋','宋诗','song-poetry','','[]','胡蝶飛，胡蝶飛，紅邊迷了紫邊迷，粉老香乾何處歸。',40,'全唐诗/poet.song.203000.json','["胡蝶飛，胡蝶飛，紅邊迷了紫邊迷，粉老香乾何處歸。", "不學蜜蜂做家計，勤苦之中有甘味。"]'),
('3c76faf1-a1a1-4d79-9582-a4e44ff9de3f','破琴','許棐','宋','宋诗','song-poetry','','[]','幸逃煮鶴煙，枯羸卧烏几。',48,'全唐诗/poet.song.203000.json','["幸逃煮鶴煙，枯羸卧烏几。", "向來千萬音，今在何人耳。", "舊譜傳不真，零落幾張紙。", "瓦缶空雷鳴，牙夔喚不起。"]'),
('a4688319-4c21-4ad3-b426-fc20bc8c2c4a','破硯','許棐','宋','宋诗','song-poetry','','[]','碌碌礲磑間，得此一雋石。',48,'全唐诗/poet.song.203000.json','["碌碌礲磑間，得此一雋石。", "磨我三十年，貌黧雙鬢白。", "渠亦苦我磨，眼穿流淚墨。", "老蟾在傍笑，兩窮自相厄。"]'),
('c6fe9a43-2341-4027-bbc4-0b3bb0fd19f0','對鏡詞','許棐','宋','宋诗','song-poetry','','[]','烟護杏腮寒，日襯桃腮暖。',24,'全唐诗/poet.song.203000.json','["烟護杏腮寒，日襯桃腮暖。", "惟有鏡中花，東風都不管。"]'),
('470f9a10-9472-436a-8fbb-f66351d2d857','織錦詞','許棐','宋','宋诗','song-poetry','','[]','綵絲愁緒雜春機，咿𠵣聲中日又西。',32,'全唐诗/poet.song.203000.json','["綵絲愁緒雜春機，咿𠵣聲中日又西。", "織到花枝連理處，玉驄門外一嬌嘶。"]'),
('12576cc2-2823-40d5-b07c-362b4d8baa57','母忌','許棐','宋','宋诗','song-poetry','','[]','一別音容歲幾更，紙灰飛盡淚猶傾。',32,'全唐诗/poet.song.203000.json','["一別音容歲幾更，紙灰飛盡淚猶傾。", "最憐春雨相將足，綿上有田誰共耕。"]'),
('fff957e3-d7b3-450e-8f2f-96de043f6a2b','春思','許棐','宋','宋诗','song-poetry','','[]','朝來一陣無情雨，敲得庭花半欲殘。',32,'全唐诗/poet.song.203000.json','["朝來一陣無情雨，敲得庭花半欲殘。", "燕子不知人冷落，飛來簾底避春寒。"]'),
('a416a0d3-0db7-4681-888a-d2cd1f73c87b','春雨','許棐','宋','宋诗','song-poetry','','[]','老來慵把種花鋤，片紫纖紅一任無。',32,'全唐诗/poet.song.203000.json','["老來慵把種花鋤，片紫纖紅一任無。", "不忍今春孤負雨，自收簷水浸菖蒲。"]'),
('5a653f1c-4ba1-4a27-b47e-b045e0970734','燕','許棐','宋','宋诗','song-poetry','','[]','處處亭臺宴好春，唱花歌柳調爭新。',32,'全唐诗/poet.song.203000.json','["處處亭臺宴好春，唱花歌柳調爭新。", "梁間不用多言語，回耳聽君有幾人。"]'),
('f0d9076b-4140-468c-a325-4b61e234eb8e','石菖蒲','許棐','宋','宋诗','song-poetry','','[]','一碧生涯水石濱，縷風絲雨瘦精神。',32,'全唐诗/poet.song.203000.json','["一碧生涯水石濱，縷風絲雨瘦精神。", "前身恐是巢由輩，怕著人間半點塵。"]'),
('43879d80-518c-4e7d-a746-9ae0aa83efa0','草  其一','許棐','宋','宋诗','song-poetry','','[]','生長冷階閒砌畔，一春知見幾花飛。',32,'全唐诗/poet.song.203000.json','["生長冷階閒砌畔，一春知見幾花飛。", "雖霑雨露無多子，却到秋來綠轉肥。"]'),
('4013c583-785c-4c0b-89a0-6c4be0ab5a25','草  其二','許棐','宋','宋诗','song-poetry','','[]','不是東風有愛憎，爲憐微細頗加情。',32,'全唐诗/poet.song.203000.json','["不是東風有愛憎，爲憐微細頗加情。", "胚紅孕紫寧交晚，且放青青寸草生。"]'),
('a83713cd-a00b-4f32-9a87-c7695603c250','池魚','許棐','宋','宋诗','song-poetry','','[]','深淺生涯足，浮沉世念輕。',24,'全唐诗/poet.song.203000.json','["深淺生涯足，浮沉世念輕。", "莫貪鈎上餌，去作鼎中羹。"]'),
('3970a3cd-1335-4271-92de-051084af9043','柳','許棐','宋','宋诗','song-poetry','','[]','青青得意春三月，撩弄東風舞腰活。',32,'全唐诗/poet.song.203000.json','["青青得意春三月，撩弄東風舞腰活。", "莫道長條舞得多，長條先被行人折。"]'),
('117af59d-3d39-45e1-a924-9a07b5ce94a3','小盆花','許棐','宋','宋诗','song-poetry','','[]','小小盆中花，春風隨分足。',48,'全唐诗/poet.song.203000.json','["小小盆中花，春風隨分足。", "花肥無賸紅，葉瘦無欠綠。", "心傾幾點香，也飽遊蜂腹。", "太盛必易衰，荒烟鎖金谷。"]'),
('df72e946-66cb-4af1-b701-126cb7eb779f','花願','許棐','宋','宋诗','song-poetry','','[]','未到無生無滅地，聊爲春風露紅紫。',32,'全唐诗/poet.song.203000.json','["未到無生無滅地，聊爲春風露紅紫。", "不願隨風趁蝶飛，願就枝頭抱香死。"]'),
('1490ff2f-bc1d-4cc5-ba04-c4e30a6de1c9','諭柳','許棐','宋','宋诗','song-poetry','','[]','不須嬌逞舞腰支，不須巧畫宮粧眉。',32,'全唐诗/poet.song.203000.json','["不須嬌逞舞腰支，不須巧畫宮粧眉。", "只把千絲萬絲結，結住行人無別離。"]'),
('48f09fa3-f132-4e6c-bc57-b3382f57d152','選官圖','許棐','宋','宋诗','song-poetry','','[]','排銜累職甚分明，除罷皆由彩色行。',32,'全唐诗/poet.song.203000.json','["排銜累職甚分明，除罷皆由彩色行。", "縱有黄金無好采，也難平白到公卿。"]'),
('ffa268a9-8108-4484-b44b-a26b36875386','猗綠惠燭','許棐','宋','宋诗','song-poetry','','[]','剪剪春生萬卷堂，一花知勝幾螢光。',32,'全唐诗/poet.song.203000.json','["剪剪春生萬卷堂，一花知勝幾螢光。", "癡兒不識半行字，只解高燒照海棠。"]'),
('5293937a-c231-4d34-af73-c9e1feb7b56d','落花','許棐','宋','宋诗','song-poetry','','[]','落花傳語五更風，能旁亭臺幾日紅。',32,'全唐诗/poet.song.203000.json','["落花傳語五更風，能旁亭臺幾日紅。", "把似匆匆又飛去，不銷裁染費春工。"]'),
('b9fabacc-e9f3-412b-928d-4de6b4da4438','落梅','許棐','宋','宋诗','song-poetry','','[]','紅杏枝枝嬌似染，綠楊處處密成圍。',32,'全唐诗/poet.song.203000.json','["紅杏枝枝嬌似染，綠楊處處密成圍。", "苦無顔色相追逐，自趁東風作雪飛。"]'),
('79672716-0e13-4f89-b44c-d4da61ed0e17','贈壽醫師','許棐','宋','宋诗','song-poetry','','[]','軒窗開處總湖光，誦罷難經納晚凉。',64,'全唐诗/poet.song.203000.json','["軒窗開處總湖光，誦罷難經納晚凉。", "雨濺荷香沾古衲，月移松影罩禪床。", "燃燈就取燒丹火，煮藥先留瀹茗湯。", "二豎三彭都見佛，人間無病亦無方。"]'),
('2f03aa12-271f-48f0-9aa9-679b1afdf6ef','陳宗之疊寄書籍小詩爲謝','許棐','宋','宋诗','song-poetry','','[]','江海歸來二十春，閉門爲學轉辛勤。',64,'全唐诗/poet.song.203000.json','["江海歸來二十春，閉門爲學轉辛勤。", "自憐兩鬢空成白，猶喜雙眸未肯昏。", "君有新刊須寄我，我逢佳處必思君。", "城南昨夜聞秋雨，又拜新凉到骨恩。"]'),
('ced7f89e-d82c-4436-9d09-ca9e6e123e5a','送趙竹潭','許棐','宋','宋诗','song-poetry','','[]','已彊詩仙一夜留，任教侵早放船休。',32,'全唐诗/poet.song.203000.json','["已彊詩仙一夜留，任教侵早放船休。", "恨身不似梅花片，飛入寒篷伴遠遊。"]'),
('fca58c10-d25b-4419-aa9d-0aeb4bd3a2aa','贈僧','許棐','宋','宋诗','song-poetry','','[]','僧趁雪前到，梅花猶恨遲。',48,'全唐诗/poet.song.203000.json','["僧趁雪前到，梅花猶恨遲。", "略譚殘歲夢，便和早春詩。", "僵雁依船宿，寒猿捧硯隨。", "吟單未須捲，重見是何時。"]'),
('c52ab7ae-98ff-44b6-9325-da4965cb7fed','璉市廢宅','許棐','宋','宋诗','song-poetry','','[]','雙槐枝葉似飄蓬，奕世榮華一旦空。',64,'全唐诗/poet.song.203000.json','["雙槐枝葉似飄蓬，奕世榮華一旦空。", "燕繞故基尋畫棟，鳥棲荒樹憶金籠。", "書分幾處青燈下，劍入誰家寶匣中。", "遥睇錢塘三尺墓，離離枯草泣低風。"]'),
('77af7a4e-7919-4539-9e22-ee3444b9d45a','壽張倅','許棐','宋','宋诗','song-poetry','','[]','明日方重九，先期菊已花。',48,'全唐诗/poet.song.203000.json','["明日方重九，先期菊已花。", "固知天有意，欲祝壽無涯。", "玉斝浮金蕊，冰姿映臉霞。", "長生此真術，不用紫河車。"]'),
('db15ccee-4456-4257-ae8d-3db34245ecad','徑山冬日','釋元肇','宋','宋诗','song-poetry','','[]','東西兩徑幽，歲晚得周游。',48,'全唐诗/poet.song.203000.json','["東西兩徑幽，歲晚得周游。", "壑雪陰猶在，溪雲凍不浮。", "鳥驚樵斧重，猿挂樹枝柔。", "怕有梅花發，因行到水頭。"]'),
('826ce23c-6035-4b60-8c58-51caec72c836','洞霄宮','釋元肇','宋','宋诗','song-poetry','','[]','夾道列蒼官，回回水屈盤。',48,'全唐诗/poet.song.203000.json','["夾道列蒼官，回回水屈盤。", "一峯天柱杪，九鏁洞雲寒。", "澗草受春綠，山茶落曉丹。", "霜髯雪眉叟，倚杖聽驚湍。"]'),
('0b3a3aa4-a570-4e64-a7f8-b2ee8d873ed4','虎丘','釋元肇','宋','宋诗','song-poetry','','[]','滄海何年湧，秦傳虎踞丘。',48,'全唐诗/poet.song.203000.json','["滄海何年湧，秦傳虎踞丘。", "池空劍光冷，墳缺鬼吟愁。", "石礙樓臺側，烟深草木浮。", "吳人貪勝槩，春盡亦來游。"]'),
('f8831332-4b69-4811-a25e-b2649b142913','楓橋','釋元肇','宋','宋诗','song-poetry','','[]','出郭初逢寺，長洲茂苑西。',48,'全唐诗/poet.song.203000.json','["出郭初逢寺，長洲茂苑西。", "塔風喧梵語，石雨暗唐題。", "日莫山如染，春深草欲迷。", "門前有流水，舊號越來溪。"]'),
('702b8efe-dcef-4c00-b838-19968338dae5','齊雲樓','釋元肇','宋','宋诗','song-poetry','','[]','高壓子城闉，簷牙半入雲。',48,'全唐诗/poet.song.203000.json','["高壓子城闉，簷牙半入雲。", "人煙極目盡，天語舉頭聞。", "齊魯猶堪望，江淮渺莫分。", "平生湖海氣，獨倚到斜曛。"]'),
('bf7fdb46-08e8-4fe5-bb51-5b3ca521ae50','姑蘇臺','釋元肇','宋','宋诗','song-poetry','','[]','古今興廢事，天地不能齊。',48,'全唐诗/poet.song.203000.json','["古今興廢事，天地不能齊。", "水闊連湖外，山多在郭西。", "登臨煙雨後，悵望夕陽低。", "若問烏棲曲，城頭夜夜啼。"]'),
('76710e17-c774-4252-86f6-3a0d8b2715d8','洞庭翠峰','釋元肇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','峯點浮螺翠，遥波界玉田。',48,'全唐诗/poet.song.203000.json','["峯點浮螺翠，遥波界玉田。", "雲中聽鷄犬，路入趁漁船。", "濃淡霜天曉，青黄橘戶煙。", "寺因明覺住，清響有人傳。"]'),
('22b5504b-1794-4a4e-af1e-219ef994e6b1','道場山','釋元肇','宋','宋诗','song-poetry','','[]','水國山爲重，僧居占上頭。',48,'全唐诗/poet.song.203000.json','["水國山爲重，僧居占上頭。", "鐘聲冠別寺，塔杪入他州。", "巖響寒泉雨，風欺老樹秋。", "定回緣愛月，增起殿前樓。"]'),
('c8d0acb8-07bc-453d-be51-ce189acb4529','徑山天開圖畫','釋元肇','宋','宋诗','song-poetry','','[]','幽澗瀉泠泠，千峯疊障屏。',48,'全唐诗/poet.song.203000.json','["幽澗瀉泠泠，千峯疊障屏。", "曉雲開混沌，遠水接滄溟。", "松影摇禪榻，苔衣上浄瓶。", "塵中夢不到，爭欲買丹青。"]'),
('cb927f78-aab0-40bd-a09c-acaf4c5ff085','石頭城','釋元肇','宋','宋诗','song-poetry','','[]','西風動古情，更上石頭城。',48,'全唐诗/poet.song.203000.json','["西風動古情，更上石頭城。", "一片斜陽外，幾番曾力爭。", "天青雲破碎，草碧鷺分明。", "寂寞潮回處，如今亦耦耕。"]'),
('0fc33dd8-3a78-4b7b-a36d-ab33b55b3377','雨華臺','釋元肇','宋','宋诗','song-poetry','','[]','高立講經臺，浮雲四面開。',48,'全唐诗/poet.song.203000.json','["高立講經臺，浮雲四面開。", "地中遺石子，天上雨華來。", "塔老香燈冷，夜深神鬼哀。", "回看六朝事，只有冢成堆。"]'),
('fd92e94a-de74-415a-a4ab-4b9410df5591','烏衣園','釋元肇','宋','宋诗','song-poetry','','[]','烏衣園裏過，不覺立多時。',48,'全唐诗/poet.song.203000.json','["烏衣園裏過，不覺立多時。", "舊事人能說，春風燕得知。", "倒垂池上柳，斜插酒邊旗。", "來往城南路，年年長別離。"]'),
('8eec2db6-7dc6-433d-b3fd-127aa58a319e','金山','釋元肇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江界楚吳，屹立兩浮屠。',48,'全唐诗/poet.song.203000.json','["長江界楚吳，屹立兩浮屠。", "潮覺山高下，雲知樹有無。", "狂瀾中砥柱，靜夜渾儀圖。", "僧應何方供，飄飄踏一蘆。"]'),
('de4f38b0-62a5-4bb6-929c-6632b1561e6a','海門古城','釋元肇','宋','宋诗','song-poetry','','[]','昔聞天祚際，城此鎮東州。',48,'全唐诗/poet.song.203000.json','["昔聞天祚際，城此鎮東州。", "壞塹尋餘鏃，荒祠立故侯。", "荆榛無茂日，禾黍幾番秋。", "江上寒潮水，依然到石頭。"]'),
('7ad459e0-3798-4362-bde9-2b9e7fe4c8f8','狼山','釋元肇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','寺因先幻有，仙跡本虞君。',48,'全唐诗/poet.song.203000.json','["寺因先幻有，仙跡本虞君。", "渡口幾點屋，山腰一抹雲。", "長江浮地軸，孤塔煥天文。", "欲問秦皇事，高崖迥不聞。"]'),
('7d6a8fe8-291d-479a-8a9b-6026217e6239','破山興福寺','釋元肇','宋','宋诗','song-poetry','','[]','此山名最重，常建昔題來。',48,'全唐诗/poet.song.203000.json','["此山名最重，常建昔題來。", "大士講經處，老龍拏石開。", "庭前纓絡樹，池內白蓮臺。", "幾載惟聞說，何當到一回。"]'),
('b2f79ec5-9391-4f83-bf45-7f6cf620ddf2','霅城','釋元肇','宋','宋诗','song-poetry','','[]','苕霅頻年夢，今秋始一過。',48,'全唐诗/poet.song.203000.json','["苕霅頻年夢，今秋始一過。", "水霾寒氣早，山出晚晴多。", "巷陌喧菱市，樓臺接櫂歌。", "一般清絕處，城裏見漁蓑。"]'),
('c2135272-1b9c-4a71-92d2-fdf3693ff10f','瓊花','釋元肇','宋','宋诗','song-poetry','','[]','勝地足繁華，靈根最可嘉。',48,'全唐诗/poet.song.203000.json','["勝地足繁華，靈根最可嘉。", "人間無別種，后土獨開花。", "玉帳三千客，珠簾十萬家。", "年年到初夏，來此醉流霞。"]'),
('0cbca4c5-e2f7-49d3-956e-158e0dcb31e9','芍藥','釋元肇','宋','宋诗','song-poetry','','[]','舊說揚州有，移來此地栽。',48,'全唐诗/poet.song.203000.json','["舊說揚州有，移來此地栽。", "年年送春後，處處見花開。", "紅藥還相似，朱顔換不回。", "晴窗添水浸，吟媿謝公才。"]'),
('6207cd61-22fe-4d37-badd-6c359635eac1','水仙','釋元肇','宋','宋诗','song-poetry','','[]','仙家遺玉種，歲晚發幽芳。',48,'全唐诗/poet.song.203000.json','["仙家遺玉種，歲晚發幽芳。", "露重金杯側，天寒翠袖長。", "神猶步洛汜，夢不到高唐。", "待得春風覺，游蜂空斷腸。"]'),
('e3e487f5-0f48-478a-9fe4-26c70e8c1877','鳳仙花','釋元肇','宋','宋诗','song-poetry','','[]','鳳者世難逢，花開瑞亦同。',48,'全唐诗/poet.song.203000.json','["鳳者世難逢，花開瑞亦同。", "九苞元有種，五色自成叢。", "竹實無心食，池光照影中。", "玉簫吹不徹，飛起向秋風。"]'),
('ded57743-8544-4401-82f8-a005f840a256','膽瓶蕉','釋元肇','宋','宋诗','song-poetry','','[]','解報窗前雨，清聲細可聽。',48,'全唐诗/poet.song.203000.json','["解報窗前雨，清聲細可聽。", "一身都是膽，數葉共生缾。", "不作抽書樣，休尋本草經。", "夏蟲猶怕苦，莫敢近青青。"]'),
('ea38dfb4-30b1-43ec-b549-ebd812d6983a','石菖蒲','釋元肇','宋','宋诗','song-poetry','','[]','烟雨暝朝昏，龍湫鴈蕩濱。',48,'全唐诗/poet.song.203000.json','["烟雨暝朝昏，龍湫鴈蕩濱。", "移根來別處，終日伴閒身。", "勁氣衝如髮，寒芒凜辟塵。", "年年看花者，應笑不曾春。"]'),
('f1d6ed69-fc39-4157-881a-f7359edf9e56','金魚','釋元肇','宋','宋诗','song-poetry','','[]','造物真成戲，鱗中亦有殊。',48,'全唐诗/poet.song.203000.json','["造物真成戲，鱗中亦有殊。", "黄金凡幾尾，碧沼自相濡。", "衆口安能鑠，懸腰但可模。", "多因名色誤，不得泳江湖。"]'),
('fc4664cb-35f2-4e75-8500-afaa13f3dd8b','移竹','釋元肇','宋','宋诗','song-poetry','','[]','南庭多綠竹，移種近西牆。',48,'全唐诗/poet.song.203000.json','["南庭多綠竹，移種近西牆。", "遠待三年後，陰成一片凉。", "月鋪金鏁碎，風度玉鏗鏘。", "定愛常來坐，中間頓石牀。"]'),
('52b20fb0-0d4d-4cf3-be67-fbcd40ec8f48','聞鴈有感','釋元肇','宋','宋诗','song-poetry','','[]','秋思堪悲處，江城鴈到初。',48,'全唐诗/poet.song.203000.json','["秋思堪悲處，江城鴈到初。", "先聲落羈旅，寒陣過空虛。", "淅淅黄蘆際，茫茫碧水餘。", "愁人在沙漠，可有寄來書。"]'),
('510c9053-5f3d-40de-9c94-d3e35b55764d','竹鄰','釋元肇','宋','宋诗','song-poetry','','[]','虛懷似此君，所至愛爲鄰。',48,'全唐诗/poet.song.203000.json','["虛懷似此君，所至愛爲鄰。", "寒影過牆綠，清風無俗塵。", "恐孤棲鳳侶，不作釣魚身。", "昔有吟人癖，移家更苦辛。"]'),
('e0dcb56b-45e7-461b-b4c2-5957cf4d0d7c','蝶','釋元肇','宋','宋诗','song-poetry','','[]','一捻翅如霜，閒飛宮樣黄。',48,'全唐诗/poet.song.203000.json','["一捻翅如霜，閒飛宮樣黄。", "年年因物化，日日爲花忙。", "風雨驚相失，兒童趁欲狂。", "尋常見圖畫，安得遇滕王。"]'),
('40e7ec84-cd29-4945-bdaa-6f6b02f46b1c','蜘蛛','釋元肇','宋','宋诗','song-poetry','','[]','羅網挂虛簷，將身僻罅潜。',48,'全唐诗/poet.song.203000.json','["羅網挂虛簷，將身僻罅潜。", "露含罾眼細，月鏤藕絲織。", "作繭輸他巧，飛蟲苦被黏。", "靜中觀節物，能有幾時炎。"]'),
('dee9784b-b98f-45bd-9043-45938e636d95','茶花','釋元肇','宋','宋诗','song-poetry','','[]','茗有花難識，山中採得來。',48,'全唐诗/poet.song.203000.json','["茗有花難識，山中採得來。", "試從枝上看，全勝琖中開。", "綠葉微如桂，黄心大似梅。", "晴窗澹相對，能遣睡魔回。"]'),
('d8fd7c3a-3702-4225-b24a-1c46e9524a2d','題草書洗兵馬','釋元肇','宋','宋诗','song-poetry','','[]','諸將收功日，山東平定時。',48,'全唐诗/poet.song.203000.json','["諸將收功日，山東平定時。", "妙須懷素筆，草出少陵詩。", "風雨驅馳疾，龍蛇變化宜。", "何當崖石上，見寫次山碑。"]'),
('426ff495-3c28-4c08-9c21-c3ac93ff1901','陳圃疏方池','釋元肇','宋','宋诗','song-poetry','','[]','細斸蒼苔地，東西曲带坡。',48,'全唐诗/poet.song.203000.json','["細斸蒼苔地，東西曲带坡。", "取泥高壅竹，積水旋栽荷。", "明月自先到，清風應更多。", "丁寧安畧彴，時復小經過。"]'),
('d11f1902-275d-4295-ab5a-b515a5753a41','大水傷田家','釋元肇','宋','宋诗','song-poetry','','[]','沙頭秋日黄，煙水白茫茫。',48,'全唐诗/poet.song.203000.json','["沙頭秋日黄，煙水白茫茫。", "無處分畦畛，傷時貴粃糠。", "家鵝隨野鶩，農父作漁郎。", "禹力成千古，孤吟欲斷腸。"]'),
('32b70b69-dffe-477d-8c53-5077052ef0b4','宿福勝寺','釋元肇','宋','宋诗','song-poetry','','[]','投宿三十里，過山千萬層。',48,'全唐诗/poet.song.203000.json','["投宿三十里，過山千萬層。", "天寒猶有菊，寺靜更無僧。", "掘芋充朝供，尋薪點夜燈。", "望雲歸未得，惆悵一枝藤。"]'),
('a7e9d43f-5e89-467e-81ba-d2c9bb127123','中秋下含輝亭','釋元肇','宋','宋诗','song-poetry','','[]','秋意足淒冷，歸心只自憐。',48,'全唐诗/poet.song.203000.json','["秋意足淒冷，歸心只自憐。", "亂峯分落照，隻鴈度遥天。", "拙學千金帚，浮生上水船。", "含暉亭畔月，最好別時圓。"]'),
('fefacb72-3d98-485f-8dcd-c297881cd092','雪','釋元肇','宋','宋诗','song-poetry','','[]','風回急有聲，欲住更娉婷。',48,'全唐诗/poet.song.203000.json','["風回急有聲，欲住更娉婷。", "頃刻增奇觀，依稀得細聽。", "空庭禽啄樹，吟屋凍生瓶。", "多是鄰僧愛，柴扉晚不扃。"]'),
('6a24041d-4149-4bb5-8cde-6fab6e65616e','庭池','釋元肇','宋','宋诗','song-poetry','','[]','窗外空無有，清池瞰屋除。',48,'全唐诗/poet.song.203000.json','["窗外空無有，清池瞰屋除。", "去萍嫌礙月，留藻怕驚魚。", "夜雨知深淺，晨光透碧虛。", "時時來顧影，照見白髭疎。"]'),
('f9b5024c-71ed-426d-8998-85c6bfb8d21f','疊石','釋元肇','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u592a\u6e56"]','澄徹池光上，嵸巃相對閑。',48,'全唐诗/poet.song.203000.json','["澄徹池光上，嵸巃相對閑。", "誰將太湖石，疊作小廬山。", "種樹蟠春長，栽花带土慳。", "當時真隠者，只在篆烟間。"]'),
('b0896b1d-7ab6-4680-92f7-6323767c7a97','竹院','釋元肇','宋','宋诗','song-poetry','','[]','愛竹真成癖，相傳子又孫。',48,'全唐诗/poet.song.203000.json','["愛竹真成癖，相傳子又孫。", "蒼寒雲翳翳，碧浄玉溫溫。", "月散驚龍化，風喧醒鶴魂。", "幾回清不寐，因雪夜開門。"]'),
('614c15ee-db65-4ada-bb34-938660072e8b','南塔','釋元肇','宋','宋诗','song-poetry','','[]','韶光將歛艷，麥野綠成堆。',48,'全唐诗/poet.song.203000.json','["韶光將歛艷，麥野綠成堆。", "庵內人如在，庭前柏自栽。", "爐煙沿石碧，經梵雜風哀。", "諸子知仁孝，逢春好一來。"]'),
('32371336-1741-46e6-8eec-01e4ddb90ff3','海陵道中','釋元肇','宋','宋诗','song-poetry','','[]','來往吳陵路，漁樵是切鄰。',48,'全唐诗/poet.song.203000.json','["來往吳陵路，漁樵是切鄰。", "雨容輕濕曉，水氣暗浮春。", "野鴈情如客，汀鷗黠近人。", "梅花篷底見，倍覺有精神。"]'),
('adbbe378-c760-4303-ae11-46ebbc58fc0a','山居','釋元肇','宋','宋诗','song-poetry','','[]','山寺偏宜夏，游塵不染苔。',48,'全唐诗/poet.song.203000.json','["山寺偏宜夏，游塵不染苔。", "煙光收迥野，江影上層臺。", "竹筍侵崖出，藤花借樹開。", "幽禽如解意，飛去又飛來。"]'),
('3a56385b-31de-4e6f-bed8-eaad272d66de','秋晚庵中','釋元肇','宋','宋诗','song-poetry','','[]','江邊成獨宿，徹夜聽吟蛩。',48,'全唐诗/poet.song.203000.json','["江邊成獨宿，徹夜聽吟蛩。", "窗月低殘影，客衣寒未重。", "林疎出幽磬，風迥遞村舂。", "細采東籬菊，曉雲橫瘦筇。"]'),
('70b1dd79-3a24-401f-a178-da7fed8a994e','閒居','釋元肇','宋','宋诗','song-poetry','','[]','孤雲自舒卷，萬類各生成。',48,'全唐诗/poet.song.203000.json','["孤雲自舒卷，萬類各生成。", "邁世有貧士，長年無俗情。", "林塘初雨過，山鳥不時鳴。", "爲問滄浪客，何須歌濯纓。"]'),
('4cb97ad0-20b1-4480-bbae-011513fe9d80','和許提幹宿平遠','釋元肇','宋','宋诗','song-poetry','','[]','傾蓋話平遠，陰陰清晝長。',48,'全唐诗/poet.song.203000.json','["傾蓋話平遠，陰陰清晝長。", "滄波沒鷗鷺，煙草暗牛羊。", "樓影欹東嶺，鐘聲出上方。", "新詩吟不足，就月屢移床。"]'),
('8a570ec0-204f-4594-bfa9-4678475fea69','病起','釋元肇','宋','宋诗','song-poetry','','[]','江臯生遠趣，盡日獨沈吟。',48,'全唐诗/poet.song.203000.json','["江臯生遠趣，盡日獨沈吟。", "雨洗四郊浄，雲分片地陰。", "黄梅成樹落，青稻入村深。", "農事今如許，猶能一散襟。"]'),
('f86d428e-16f1-45f3-9c78-6fc57659bf82','山村初夏','釋元肇','宋','宋诗','song-poetry','','[]','麥熟鳥聲樂，桑空蠶箔溫。',48,'全唐诗/poet.song.203000.json','["麥熟鳥聲樂，桑空蠶箔溫。", "陰陰傍山路，曲曲抱溪村。", "喚雨鳩夫婦，添林竹子孫。", "牛羊雜樵牧，隨月到柴門。"]'),
('40b933d1-864f-4899-b99f-3bec4ab0e8f0','中秋','釋元肇','宋','宋诗','song-poetry','','[]','今夜中秋月，相看異楚江。',48,'全唐诗/poet.song.203000.json','["今夜中秋月，相看異楚江。", "侵階如有雪，透屋欲無窗。", "鵲爲無枝遶，鐘因得句撞。", "不知風露冷，吟到影成雙。"]'),
('4ecc1a70-66d0-4d92-8637-e14f64c632b7','林酒仙','釋元肇','宋','宋诗','song-poetry','','[]','持犯苦相分，陶沈麯糵真。',48,'全唐诗/poet.song.203000.json','["持犯苦相分，陶沈麯糵真。", "世間皆醉夢，師是獨醒人。", "難合虛開口，長留坐化身。", "春風過東寺，苔砌落花新。"]'),
('6ac0ace0-6cd7-4f9f-9fc4-fcc097a121e4','臘雪','釋元肇','宋','宋诗','song-poetry','','[]','從前知雪意，祇向夜中來。',48,'全唐诗/poet.song.203000.json','["從前知雪意，祇向夜中來。", "光逼鷄窗曉，寒催蝶夢回。", "開門思煮茗，摇樹怕傷梅。", "高處偏多積，因高却易隤。"]'),
('762faa45-c0da-4a60-9045-206900d61cc2','大閲','釋元肇','宋','宋诗','song-poetry','','[]','吳宮舊有名，閲武事非輕。',48,'全唐诗/poet.song.203000.json','["吳宮舊有名，閲武事非輕。", "金鼓從天落，戈鍪照雪明。", "令嚴雲鳥絕，機發鬼神驚。", "士氣賈餘勇，歸笳奏太平。"]'),
('741fdf77-a17d-4e57-8933-6402fe8e9d76','春雪','釋元肇','宋','宋诗','song-poetry','','[]','乾坤公道在，又見雪來蘇。',48,'全唐诗/poet.song.203000.json','["乾坤公道在，又見雪來蘇。", "貴賤皆白屋，高低盡坦涂。", "莫嫌春力淺，猶勝去年無。", "却憶尋芳者，還成訪戴圖。"]'),
('bf1dd17b-a8e6-4bcd-8790-eebd8fcd809e','送春','釋元肇','宋','宋诗','song-poetry','','[]','又送春歸去，幽居轉寂寥。',48,'全唐诗/poet.song.203000.json','["又送春歸去，幽居轉寂寥。", "林花皆落盡，鬢雪不曾消。", "明日無三月，愁吟過一宵。", "更添簷外雨，點點在芭蕉。"]'),
('f5fc5063-9797-4150-98a1-eb9febc7f68a','清明','釋元肇','宋','宋诗','song-poetry','','[]','寒食清明節，家家拜掃辰。',48,'全唐诗/poet.song.203000.json','["寒食清明節，家家拜掃辰。", "酒杯難醉土，淚眼不知春。", "舊塚連新塚，今人歎昔人。", "路傍無主認，幾箇石麒麟。"]'),
('24116524-12a0-4986-afe7-31f32441cf9a','哀通城','釋元肇','宋','宋诗','song-poetry','','[]','聞道通城破，傷心不可論。',48,'全唐诗/poet.song.203000.json','["聞道通城破，傷心不可論。", "隔江三日火，故里幾人存。", "哭透青天裂，冤銜白晝昏。", "時逢過來者，恐是夢中魂。"]'),
('65f3bc79-0620-4e66-8340-d1c1f8bce68f','掬泉','釋元肇','宋','宋诗','song-poetry','','[]','一坳寒貯玉，非沼又非渠。',48,'全唐诗/poet.song.203000.json','["一坳寒貯玉，非沼又非渠。", "捉月弄清淺，把山摇碧虛。", "久晴應不竭，積雨亦無餘。", "陸羽來題品，他泉定弗如。"]'),
('994551a2-4b30-4316-9883-be19460a2415','時敬菴','釋元肇','宋','宋诗','song-poetry','','[]','主人時孝敬，結屋尉幽靈。',48,'全唐诗/poet.song.203000.json','["主人時孝敬，結屋尉幽靈。", "山近嵐生砌，池清月在庭。", "鳥行窺施食，鶴立聽看經。", "有客來相過，林扉且莫扃。"]'),
('df92438d-9814-419e-9e7f-dd51ce009e33','夜坐','釋元肇','宋','宋诗','song-poetry','','[]','露坐黄昏後，城居若在村。',48,'全唐诗/poet.song.203000.json','["露坐黄昏後，城居若在村。", "天陰螢火亮，秋近草蟲喧。", "老去渾無睡，貧來不閉門。", "也知疎拙甚，此意與誰論。"]'),
('cfbd46d6-71c7-44c3-882a-8101204353da','七夕','釋元肇','宋','宋诗','song-poetry','','[]','年年逢七夕，鵲遶故枝驚。',48,'全唐诗/poet.song.203000.json','["年年逢七夕，鵲遶故枝驚。", "天上誰曾會，人間自動情。", "巧雲還易散，曲月豈長明。", "大拙無如我，孤吟曉未成。"]'),
('d21b953c-5ab0-402d-80a6-eb26b630e1d0','雪中訪趙守宗簿','釋元肇','宋','宋诗','song-poetry','','[]','終歲揜柴荆，雪中乘興行。',48,'全唐诗/poet.song.203000.json','["終歲揜柴荆，雪中乘興行。", "水光相莽蒼，雲意自從橫。", "風壓孤舟重，烟消野店明。", "休尋戴安道，且訪謝宣城。"]'),
('4dfdd59b-0007-45ce-a8ec-f9a3ce928b27','送趙守寺丞除郎','釋元肇','宋','宋诗','song-poetry','','[]','專城不兩年，千騎促朝天。',48,'全唐诗/poet.song.203000.json','["專城不兩年，千騎促朝天。", "星宿明前席，江神護奏篇。", "梅開堠亭雪，柳綻御樓煙。", "悵望寒汀晚，蘆花一釣船。"]'),
('556f13a3-37e3-4f6d-9149-b2607d79b0c4','送仲新恩','釋元肇','宋','宋诗','song-poetry','','[]','倍喜逢鄉老，離家歲月長。',48,'全唐诗/poet.song.203000.json','["倍喜逢鄉老，離家歲月長。", "衣霑新雨露，面带舊風霜。", "雲氣侵晴檻，泉聲入夜堂。", "明朝出山去，後會說重陽。"]'),
('ad3306ff-030b-4e1c-bbc1-76f21fc72609','送凌僉判','釋元肇','宋','宋诗','song-poetry','','[]','江臯秋意足，倚策送君行。',48,'全唐诗/poet.song.203000.json','["江臯秋意足，倚策送君行。", "戍皷聲方斷，登樓賦已成。", "野潮漫曉白，鄉岫出煙迎。", "只有津亭柳，摇摇繫別情。"]'),
('7de9d0e5-9877-4bb0-97b1-4ea03039ed46','送孫教授翔父','釋元肇','宋','宋诗','song-poetry','','[]','泮宮留不得，廊廟嘆才難。',48,'全唐诗/poet.song.203000.json','["泮宮留不得，廊廟嘆才難。", "遠送嫌江礙，深思上閣看。", "菊開秋意足，鴈到水天寒。", "德釋關民社，何須問改官。"]'),
('50469345-fe6a-40cb-9e09-b04ea124a1d4','寄趙東閣','釋元肇','宋','宋诗','song-poetry','','[]','與君生己酉，年月日時中。',48,'全唐诗/poet.song.203000.json','["與君生己酉，年月日時中。", "除郤吟相似，其它事不同。", "夢寒春草綠，天闊莫江空。", "見面知何處，東華踏軟紅。"]'),
('03724519-44f7-496a-bb1d-194d5a9c20a4','訪方蕙巖不值','釋元肇','宋','宋诗','song-poetry','','[]','吳城多第宅，毋過蕙巖家。',48,'全唐诗/poet.song.203000.json','["吳城多第宅，毋過蕙巖家。", "不是門如海，都緣刺似麻。", "風聲虛動竹，日影漸移花。", "清興渾無奈，歸來自煮茶。"]'),
('396d2426-2b7e-4e60-81f7-b79c8ac0b495','和宋松竹','釋元肇','宋','宋诗','song-poetry','','[]','保障風寒地，勤勞不問家。',48,'全唐诗/poet.song.203000.json','["保障風寒地，勤勞不問家。", "年來對松竹，客至話桑麻。", "靈運池塘草，玄都觀裏花。", "打門驚夢起，上苑賜新茶。"]'),
('cec0dd96-8baf-4cb3-baf4-bd231549b047','和方新恩','釋元肇','宋','宋诗','song-poetry','','[]','詩禮擅英華，源流奕世家。',48,'全唐诗/poet.song.203000.json','["詩禮擅英華，源流奕世家。", "已攀天上桂，不棄道傍麻。", "烏鵲朝來噪，青燈昨夜花。", "慚無報瓊句，相對只杯茶。"]'),
('d3a42417-6dd9-4e02-a712-44c78417973c','送致政許朝請','釋元肇','宋','宋诗','song-poetry','','[]','相遇在東州，相分十五秋。',48,'全唐诗/poet.song.203000.json','["相遇在東州，相分十五秋。", "挂冠當健日，見子早封侯。", "城外鐘寒寺，山陰雪夜舟。", "還經釣臺過，不媿客星游。"]'),
('654963f7-9900-4edf-bb36-8f384b4e4b61','方蕙巖宅','釋元肇','宋','宋诗','song-poetry','','[]','移宅住園中，高懷便不同。',48,'全唐诗/poet.song.203000.json','["移宅住園中，高懷便不同。", "生涯雖最少，樂地却無窮。", "人記爲州日，家傳處士風。", "閒來對巖石，坐到夕陽紅。"]'),
('de00fb16-7709-4c3a-a1ea-d3cd11daa770','題陳藏一山房','釋元肇','宋','宋诗','song-poetry','','[]','浩浩人如海，吟居獨可嘉。',48,'全唐诗/poet.song.203000.json','["浩浩人如海，吟居獨可嘉。", "遠山長入戶，萬卷是生涯。", "挂石添名畫，分缾插買花。", "多應市朝客，無暇到君家。"]'),
('d583d4f2-fa4c-427a-909f-009e020ad90c','寄龜翁史君','釋元肇','宋','宋诗','song-poetry','','[]','添藁近方開，傳從越上來。',48,'全唐诗/poet.song.203000.json','["添藁近方開，傳從越上來。", "不曾經道句，真箇是仙才。", "禹廟題新在，蘭亭到幾回。", "莫教兒輩覺，瓜戍恐相催。"]'),
('63053787-c56b-48d6-b455-e2d36ad46458','寄項秘監','釋元肇','宋','宋诗','song-poetry','','[]','吳中住歲餘，所樂在詩書。',48,'全唐诗/poet.song.203000.json','["吳中住歲餘，所樂在詩書。", "有句題幽石，無人識借居。", "蓬萊最高處，雅頌正關渠。", "此道能如古，今誰伴直廬。"]'),
('d91f7360-f08c-4d6a-b2ab-9719f00fb941','寄御史王少卿','釋元肇','宋','宋诗','song-poetry','','[]','朝陽有鳴鳳，天下喜初聞。',48,'全唐诗/poet.song.203000.json','["朝陽有鳴鳳，天下喜初聞。", "去棹輕如葉，閒心淡似雲。", "杯羹留奉母，一飯不忘君。", "千古濠梁水，流清滌世氛。"]'),
('0e70bd03-e94f-4872-9dc0-cc1ec4f71595','和黄東浦早秋韻','釋元肇','宋','宋诗','song-poetry','','[]','門徑半交莎，幽居事若何。',48,'全唐诗/poet.song.203000.json','["門徑半交莎，幽居事若何。", "地偏人到少，雲淡自怡多。", "林杪危凉葉，池容減翠荷。", "翻思種陽艷，終竟不如禾。"]'),
('9c48ad6a-6b0f-4ed6-827e-fe0612e32f84','寄鄭司業直院右史','釋元肇','宋','宋诗','song-poetry','','[]','由來行所學，最是得時難。',48,'全唐诗/poet.song.203000.json','["由來行所學，最是得時難。", "春草書带綠，東風御柳寒。", "金爐烟噴曉，玉署漏聲殘。", "獻納絲綸樣，流傳盛代看。"]'),
('56d4d792-bf24-4342-a28f-492341e18d88','次韻趙竹所書詩卷後','釋元肇','宋','宋诗','song-poetry','','[]','江湖三十載，每聽說君詩。',48,'全唐诗/poet.song.203000.json','["江湖三十載，每聽說君詩。", "古寺過逢處，寒城欲莫時。", "自看霜落後，唯倚竹相知。", "吟壘慚無律，虛勞爲出奇。"]'),
('3409f5af-00c1-4eab-91b0-6a92e932430a','周伯弜詩送僧至吳','釋元肇','宋','宋诗','song-poetry','','[]','周友別多時，湖山翠染衣。',48,'全唐诗/poet.song.203000.json','["周友別多時，湖山翠染衣。", "宦情如紙薄，詩句逐雲飛。", "一片孤鴻影，三高釣雪磯。", "只消傳此意，知我似君稀。"]'),
('ca7ab659-bfc4-4962-aa0c-0e2d51509487','書薛野鶴水竹稿','釋元肇','宋','宋诗','song-poetry','','[]','野性昂如鶴，期君壽合堅。',48,'全唐诗/poet.song.203000.json','["野性昂如鶴，期君壽合堅。", "雖然傳去世，必定得爲仙。", "華表千年後，崖銘幾字全。", "詩名長不泯，集是石龜編。"]'),
('4a56532d-282d-4998-a95f-e088ac960622','送周肖白','釋元肇','宋','宋诗','song-poetry','','[]','新年纔兩日，又見送行人。',48,'全唐诗/poet.song.203000.json','["新年纔兩日，又見送行人。", "畫好難投俗，詩工不療貧。", "烟深楊柳岸，雨瘦鷺鷥身。", "且莫東歸去，京華易得春。"]'),
('0c364488-2856-4236-a1b7-7817ae86c32d','題石瑶林山錄','釋元肇','宋','宋诗','song-poetry','','[]','天姥紫芝岑，僊靈宅下臨。',48,'全唐诗/poet.song.203000.json','["天姥紫芝岑，僊靈宅下臨。", "幽光千古月，孝德一生心。", "拱木秋聲早，寒泉泪滴深。", "彼蒼知不遠，同聘入書林。"]'),
('1e098f75-0c57-452a-8529-3949a80df3cc','足菴寄朱新父','釋元肇','宋','宋诗','song-poetry','','[]','知機何太蚤，菴以足爲題。',48,'全唐诗/poet.song.203000.json','["知機何太蚤，菴以足爲題。", "動靜關天理，纖洪類物齊。", "魚游池水滿，鳥宿樹枝低。", "來往門前客，黄塵沒馬蹄。"]'),
('a0c561a8-b942-4508-987c-a23e10fd13d2','湯西樓新居','釋元肇','宋','宋诗','song-poetry','','[]','聞君移住處，相近太平坊。',48,'全唐诗/poet.song.203000.json','["聞君移住處，相近太平坊。", "舊日同吟侶，新來認草堂。", "避喧猶未可，在陋亦何妨。", "只有西樓月，清光不改常。"]'),
('be34bc2f-1d1b-4038-af67-cfb93329acbb','和王郎中韻','釋元肇','宋','宋诗','song-poetry','','[]','淮水入吳深，乘流住到今。',48,'全唐诗/poet.song.203000.json','["淮水入吳深，乘流住到今。", "石幢寒日影，鐵塔夜風吟。", "舉世無知己，惟公識此心。", "朝來惠新作，三嘆有餘音。"]'),
('edd0cdcd-16f4-4a15-a5bf-3b44fce8080d','梅山','釋元肇','宋','宋诗','song-poetry','','[]','歷陽風土秀，清氣在梅山。',48,'全唐诗/poet.song.203000.json','["歷陽風土秀，清氣在梅山。", "自古英靈出，垂名天地間。", "相傳司業句，又逐省郎還。", "歲歲春消息，寧忘問故關。"]'),
('9840d88f-1e91-4d1e-9366-a44e903dc9b1','小閤','釋元肇','宋','宋诗','song-poetry','','[]','老子小婆娑，裝成安樂窩。',48,'全唐诗/poet.song.203000.json','["老子小婆娑，裝成安樂窩。", "不堪人狹隘，足稱自吟哦。", "愛日烘窗煖，承簷聽雨多。", "來春在鈴下，思治作民和。"]'),
('943a049b-47a7-4cb5-af6b-2d853d229992','吊毛惜惜','釋元肇','宋','宋诗','song-poetry','','[]','妓者有毛嬙，高沙駡賊狂。',48,'全唐诗/poet.song.203000.json','["妓者有毛嬙，高沙駡賊狂。", "一身雖就死，千古不曾亡。", "嗟爾男兒活，羞它冢樹傍。", "史應收烈傳，祀合御睢陽。"]'),
('9eb5cc92-4e50-4d37-ba61-43eded6d8059','曉谷','釋元肇','宋','宋诗','song-poetry','','[]','長夜何時旦，藏脩只任真。',48,'全唐诗/poet.song.203000.json','["長夜何時旦，藏脩只任真。", "惜陰常起早，吹律自生春。", "處處聞啼鳥，聲聲若應人。", "日高雲散後，方始正衣巾。"]'),
('f7fefc43-0fc6-4443-b7b2-e0f61bfb5f8c','送張明府知黄崗','釋元肇','宋','宋诗','song-poetry','','[]','去作黄崗縣，風寒護上流。',48,'全唐诗/poet.song.203000.json','["去作黄崗縣，風寒護上流。", "近時登要路，皆用試邊頭。", "赤壁應無恙，雪堂還在不。", "多將民疾苦，歸日奏宸旒。"]'),
('88cf89e5-3765-4d51-b487-d8dba5a3c9a8','送潘提幹','釋元肇','宋','宋诗','song-poetry','','[]','聖代重倫魁，難教佐外臺。',48,'全唐诗/poet.song.203000.json','["聖代重倫魁，難教佐外臺。", "天文動星象，雲氣上蓬萊。", "道士携琴送，吟船載鶴回。", "中興紫岩老，今日又重來。"]'),
('08e669ad-fe73-48ef-ba7c-d362463d4212','送王右曹知南劍','釋元肇','宋','宋诗','song-poetry','','[]','列宿守延平，旌旗過浙迎。',48,'全唐诗/poet.song.203000.json','["列宿守延平，旌旗過浙迎。", "地傳龍化劍，州傍水爲城。", "勁氣民情直，澄波政樣清。", "公庭應事簡，所得是詩名。"]'),
('2ec6469d-ea01-46d3-b6f9-d53000b77548','送山陰僧還西山','釋元肇','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','香城高處住，瀑布挂簷間。',48,'全唐诗/poet.song.203000.json','["香城高處住，瀑布挂簷間。", "莫雨滕王閣，白雲秦望山。", "到家如客寄，直語對人慳。", "却憶來時路，松門夜不關。"]'),
('bf058682-d1b9-43cc-82ae-3e61fda1b69e','贈縫人','釋元肇','宋','宋诗','song-poetry','','[]','傳來家法遠，妙在自通方。',48,'全唐诗/poet.song.203000.json','["傳來家法遠，妙在自通方。", "到處逢僧說，前年離帝鄉。", "腰圍憐我瘦，舞袖爲誰長。", "不用懸牌額，蘭深路有香。"]'),
('45db0bc5-4d95-42e5-8a04-e83c99080b61','雲谷日者','釋元肇','宋','宋诗','song-poetry','','[]','賣卜不論錢，開囊乞贈篇。',48,'全唐诗/poet.song.203000.json','["賣卜不論錢，開囊乞贈篇。", "先生雖有術，野客不知年。", "披雪穿吳市，占星落楚天。", "茫茫寰海內，爲覓隠神僊。"]'),
('62463146-12f9-4ba3-b887-77d422fbc427','送陳省元歸通川','釋元肇','宋','宋诗','song-poetry','','[]','買宅船橋住，情深得共論。',48,'全唐诗/poet.song.203000.json','["買宅船橋住，情深得共論。", "兒能學吳語，老念出齊門。", "綠樹陰行色，清江漲別痕。", "鄰人相過處，歡樂勝羌村。"]'),
('188e438c-c152-4525-b3e2-6451ca76a02e','歲晚過上竺禮天目','釋元肇','宋','宋诗','song-poetry','','[]','幽懷日成趣，與世不相聞。',48,'全唐诗/poet.song.203000.json','["幽懷日成趣，與世不相聞。", "瘦似梅花樹，閑如竺嶺雲。", "葉間新句法，石上舊苔紋。", "送我溪橋路，松梢又夕曛。"]'),
('5316feaa-e367-4132-9a7e-a0e8548bf102','和天目送行','釋元肇','宋','宋诗','song-poetry','','[]','握手下層翠，秋聲動泬寥。',48,'全唐诗/poet.song.203000.json','["握手下層翠，秋聲動泬寥。", "葉寒山徑響，雨積水程遥。", "古甸分煙樹，孤城带晚潮。", "懷人在空谷，誼不就旌招。"]'),
('1f8c01fb-f428-4251-8753-6357ea440b77','訪天目梁渚','釋元肇','宋','宋诗','song-poetry','','[]','煙渚落漁篷，行行訪隠蹤。',48,'全唐诗/poet.song.203000.json','["煙渚落漁篷，行行訪隠蹤。", "野禽衝斷徑，樵子指前峯。", "雲閟安禪石，霜清得句鐘。", "長淮一千里，九日却重逢。"]'),
('eccc04a3-ed7c-4ed5-9d01-07f8fab1ebf5','謝煥書記畫','釋元肇','宋','宋诗','song-poetry','','[]','住寺近郊臺，禪林扣遍回。',48,'全唐诗/poet.song.203000.json','["住寺近郊臺，禪林扣遍回。", "門從齋後閉，客自雨中來。", "靜勝方知妙，吟成不敢催。", "相思渺何許，時展畫圖開。"]'),
('6eb7d9a1-b04d-475e-b53c-a49ce3c33ba6','送江西益禪人','釋元肇','宋','宋诗','song-poetry','','[]','世路今方隘，情親別更難。',48,'全唐诗/poet.song.203000.json','["世路今方隘，情親別更難。", "孤篷和雨宿，十月渡江寒。", "詩到愁時澀，書來約歲闌。", "青青狼伍寺，何日共闌干。"]'),
('450f26c5-4f1e-43b3-99b3-0640bd5d19e8','送深禪人歸衡岳隠山','釋元肇','宋','宋诗','song-poetry','','[]','江浙參尋遍，仍思故隠山。',48,'全唐诗/poet.song.203000.json','["江浙參尋遍，仍思故隠山。", "不知人住處，惟見鴈飛還。", "說法龍來聽，長年雲閉關。", "莫將殘菜葉，流落在溪間。"]'),
('28ee6369-052e-48ac-b6c9-d0ac8e6c7d2a','送同游歸里','釋元肇','宋','宋诗','song-poetry','','[]','俱有萱庭念，相依歲月深。',48,'全唐诗/poet.song.203000.json','["俱有萱庭念，相依歲月深。", "平時行樂地，此夜別離心。", "曉渡吳雲濕，秋生楚岫陰。", "獨憐烏鵲喜，不到我家林。"]'),
('d9cd6502-4c73-4cef-bfa2-44d7d9d2632e','寄遠','釋元肇','宋','宋诗','song-poetry','','[]','拄策窮西望，閑雲去復生。',48,'全唐诗/poet.song.203000.json','["拄策窮西望，閑雲去復生。", "亂鴉棲落日，孤鴈叫寒更。", "坐久燈生暈，衣單夢不成。", "遥知今夜月，還向故人明。"]'),
('bc094b86-c7b5-4513-8dde-e78ea75e920d','送珂書記游金陵','釋元肇','宋','宋诗','song-poetry','','[]','兩度扣幽扃，知君無俗情。',48,'全唐诗/poet.song.203000.json','["兩度扣幽扃，知君無俗情。", "遠拋孤嶼碧，久住冷泉清。", "吟骨瘦欲出，行囊貧得輕。", "天寒猶未返，貪看石頭城。"]'),
('32622ed1-d661-4c23-81ab-8db811eb180e','更深亭','釋元肇','宋','宋诗','song-poetry','','[]','幽趣上林梢，添高一把茅。',48,'全唐诗/poet.song.203000.json','["幽趣上林梢，添高一把茅。", "乾坤常在定，日月自相交。", "雲怕人知處，門開僧不敲。", "叢臺歌舞散，空有燕來巢。"]'),
('20af5ee1-61be-422b-8a7d-4030a0372aab','懷人','釋元肇','宋','宋诗','song-poetry','','[]','自覺懷人遠，閒房獨揜扃。',48,'全唐诗/poet.song.203000.json','["自覺懷人遠，閒房獨揜扃。", "去時梅著子，歸晚竹添丁。", "海岸無山碧，天涯有草青。", "春潮知信候，日日過夷亭。"]'),
('587f3b17-d377-4c1b-abd4-65efb2f6436b','送僧東歸','釋元肇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','欲作廬山去，幡然興已收。',48,'全唐诗/poet.song.203000.json','["欲作廬山去，幡然興已收。", "故鄉一夜夢，明月兩中秋。", "落葉堆寒色，孤帆挂遠愁。", "不知從此後，誰上仲宣樓。"]'),
('06a98dc5-9067-4a2f-9948-7cee19890cba','送沅清谿游江西','釋元肇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','桐廬山下水，徹底照人清。',48,'全唐诗/poet.song.203000.json','["桐廬山下水，徹底照人清。", "流向西江去，吟高舊日聲。", "洪崖千丈雪，黄鶴一樓晴。", "知是何時到，隨緣不算程。"]'),
('5a615787-19f9-4fbe-80a3-38acb9cae223','寫照王肖巖','釋元肇','宋','宋诗','song-poetry','','[]','王君善寫真，當世獨超倫。',48,'全唐诗/poet.song.203000.json','["王君善寫真，當世獨超倫。", "纔見皆能識，方知妙入神。", "鴛行傳國士，麟閣貌功臣。", "安有工夫到，寒巖枯木身。"]'),
('bd6b7e76-ece5-46d9-9b8d-14b067c69974','寄冷泉康書狀','釋元肇','宋','宋诗','song-poetry','','[]','康廬有隠君，久愛北山文。',48,'全唐诗/poet.song.203000.json','["康廬有隠君，久愛北山文。", "磵底弄清泚，嶺頭吟白雲。", "月隨行處影，猿向定中聞。", "寄得書來說，憐余在鷺群。"]'),
('d34aca4c-e581-4b0c-b6b3-8092b4ca8140','渡越','釋元肇','宋','宋诗','song-poetry','','[]','半月金陵路，今朝渡浙河。',48,'全唐诗/poet.song.203000.json','["半月金陵路，今朝渡浙河。", "回頭吳岫在，到耳越音多。", "賀監湖邊柳，右軍池上鵝。", "宛然風物在，人事幾消磨。"]'),
('0a9bc2a6-060b-4eff-b2bc-7dd20659f258','剡中','釋元肇','宋','宋诗','song-poetry','','[]','雨宿剡中寺，曉行猶未晴。',48,'全唐诗/poet.song.203000.json','["雨宿剡中寺，曉行猶未晴。", "諸峯雲不定，疊磵水爭鳴。", "野店穿心過，村樵當面橫。", "尋思戴安道，千古一谿清。"]'),
('55086ade-d180-4dc0-a32d-130213e3fbdf','新昌石像','釋元肇','宋','宋诗','song-poetry','','[]','願力堅如石，三生鑿得開。',48,'全唐诗/poet.song.203000.json','["願力堅如石，三生鑿得開。", "始知真實相，元不假胚胎。", "寶閣層層見，香雲冉冉回。", "盡誠皈敬者，莫待下生來。"]'),
('31cd1a84-64c0-4799-94c5-111db28645e2','天姥','釋元肇','宋','宋诗','song-poetry','','[]','自登天姥嶺，飛雪滿千峯。',48,'全唐诗/poet.song.203000.json','["自登天姥嶺，飛雪滿千峯。", "采藥難尋徑，啼猿不見蹤。", "赤城應改色，白道定相逢。", "漸覺吾廬近，微聞日暮鐘。"]'),
('68f87e45-6eec-43e6-812e-11a8d331edee','石橋','釋元肇','宋','宋诗','song-poetry','','[]','絕景隔凡塵，探幽雪未分。',48,'全唐诗/poet.song.203000.json','["絕景隔凡塵，探幽雪未分。", "飛來雙磵瀑，攤作一橋雲。", "聖跡常時現，人間到處聞。", "煎茶亭上立，花乳自紛紛。"]'),
('cd10ea21-28c9-46af-a511-4d6cbeb75b6e','送照晦巖赴下竺','釋元肇','宋','宋诗','song-poetry','','[]','法道日堪嗟，邪師似稻麻。',48,'全唐诗/poet.song.203000.json','["法道日堪嗟，邪師似稻麻。", "靈山承付囑，佛隴正傳家。", "曲水慈雲石，薌風御苑花。", "曇猷橋畔別，烟樹思無涯。"]'),
('c403d859-7c71-480d-84a3-a9b078f055c3','桐柏觀','釋元肇','宋','宋诗','song-poetry','','[]','仙者曾居地，峯巒特異常。',48,'全唐诗/poet.song.203000.json','["仙者曾居地，峯巒特異常。", "泉飄簫樂響，松暗洞門藏。", "玉井通三島，瓊臺接上蒼。", "有時聞鶴下，醮罷月侵廊。"]'),
('ccdc4337-c808-4fe8-b447-1300284e16b1','酬趙菊莊','釋元肇','宋','宋诗','song-poetry','','[]','讀來詩百首，清絕少如君。',48,'全唐诗/poet.song.203000.json','["讀來詩百首，清絕少如君。", "碧水有明月，青天無片雲。", "台山才一見，衡岳又相分。", "此處多回鴈，新題到里枌。"]'),
('d143af23-cf18-48f8-81ae-1265022a422b','華頂峰','釋元肇','宋','宋诗','song-poetry','','[]','台嶺碧重重，中高華頂峯。',48,'全唐诗/poet.song.203000.json','["台嶺碧重重，中高華頂峯。", "盡頭滄海出，半被白雲封。", "屋冷僧拋去，僊來井有蹤。", "絕無猿鳥路，爭得世人逢。"]'),
('87afbc84-1397-4d77-a0ac-25213d1bd543','羅漢樹','釋元肇','宋','宋诗','song-poetry','','[]','嶺上羅漢樹，魁梧迥不群。',48,'全唐诗/poet.song.203000.json','["嶺上羅漢樹，魁梧迥不群。", "死心雖滅火，直氣尚凌雲。", "空得渾無物，中能著數君。", "非同木居士，題號涉功勛。"]'),
('44849654-30bf-4649-a84b-61d22806af08','宿廣閏寺庾嶺方丈','釋元肇','宋','宋诗','song-poetry','','[]','兩程行始到，寺與海波鄰。',48,'全唐诗/poet.song.203000.json','["兩程行始到，寺與海波鄰。", "插草燉煌士，傳衣庾嶺人。", "話長緣久別，月澹欲侵晨。", "憶在凌霄日，相同是夙因。"]'),
('1d83cd8c-2b21-4d45-a545-2b461050b6af','寄南叔凱','釋元肇','宋','宋诗','song-poetry','','[]','苦思南叔凱，相別已多年。',48,'全唐诗/poet.song.203000.json','["苦思南叔凱，相別已多年。", "生與慈雲近，燈從智者傳。", "憐渠如我癖，忤俗是詩篇。", "橋畔青松老，期來看瀑泉。"]'),
('c9418845-18e1-4b39-82b3-ec92f532564c','雪中','釋元肇','宋','宋诗','song-poetry','','[]','籃輿走白沙，風雪正交加。',48,'全唐诗/poet.song.203000.json','["籃輿走白沙，風雪正交加。", "片石皆成玉，莖茅盡著花。", "禽危巢欲墮，樵失路應差。", "歸晚堪尋處，清溪一綫斜。"]'),
('a8cda60b-a837-48f4-a8eb-8a4b12faa711','寒巖','釋元肇','宋','宋诗','song-poetry','','[]','信宿到寒巖，靈蹤出曉嵐。',48,'全唐诗/poet.song.203000.json','["信宿到寒巖，靈蹤出曉嵐。", "懸崖嵌似鑿，著屋巧如龕。", "石月觀心處，霜鐘是對譚。", "徧尋雙隠句，風葉已䰐鬖。"]'),
('c1438fc7-f8ea-4564-96ff-855cb1a404c5','明巖','釋元肇','宋','宋诗','song-poetry','','[]','不與衆峯同，纔容寸步通。',48,'全唐诗/poet.song.203000.json','["不與衆峯同，纔容寸步通。", "跨門巖響屧，縣度水行空。", "僧住知無厭，人來看莫窮。", "相傳幽洞透，寒拾往還中。"]'),
('10ff414e-37b6-4429-bcc6-b753a182dbbb','天封','釋元肇','宋','宋诗','song-poetry','','[]','神指靈墟地，峯從華頂分。',48,'全唐诗/poet.song.203000.json','["神指靈墟地，峯從華頂分。", "東封時未至，西域教先聞。", "丈室高皇字，重修笠澤文。", "幽尋三十里，穿破石橋雲。"]'),
('dbd2487d-64dd-4627-aad6-e91552556e70','赤城','釋元肇','宋','宋诗','song-poetry','','[]','秀氣融台岳，虛玄第玉京。',48,'全唐诗/poet.song.203000.json','["秀氣融台岳，虛玄第玉京。", "飛霞染丹石，危堞露層城。", "華雨無時歇，松風夾道鳴。", "曇猷洗腸處，泉井至今赬。"]'),
('e1f2b740-2506-4b1b-835d-aebe0e1da697','蓮華峰','釋元肇','宋','宋诗','song-poetry','','[]','絕頂高峰上，如何下手栽。',48,'全唐诗/poet.song.203000.json','["絕頂高峰上，如何下手栽。", "崔嵬出雲際，菡萏向天開。", "大寂身千劫，浮圖雪一桅。", "橫擔楖栗去，曾有幾人來。"]'),
('c91aaa84-3c7e-4770-8b49-fb7afad1b4ce','台城道中','釋元肇','宋','宋诗','song-poetry','','[]','枝暗花成子，風飄絮作萍。',48,'全唐诗/poet.song.203000.json','["枝暗花成子，風飄絮作萍。", "雨侵溪漲白，山脫晚雲青。", "又過仙人渡，還登酌水亭。", "往來人自老，雙鷺立烟汀。"]'),
('4706f865-2544-46a0-95bb-0012fa9d06ab','寄吳荆溪大監','釋元肇','宋','宋诗','song-poetry','','[]','水心銘未立，屬望在荆溪。',48,'全唐诗/poet.song.203000.json','["水心銘未立，屬望在荆溪。", "一字如山重，何人落筆題。", "昌黎懸斗柄，皇甫接天梯。", "草木無情者，垂垂露泣低。"]'),
('b52a252d-2338-4a1a-96d3-fae827a3d707','碧沼','釋元肇','宋','宋诗','song-poetry','','[]','瀲灧一池蓮，禪房住半邊。',48,'全唐诗/poet.song.203000.json','["瀲灧一池蓮，禪房住半邊。", "北通關市路，西透馬塍泉。", "碧色冷摇日，香風近撲天。", "遠公雖不作，清社有人傳。"]'),
('ce85be1f-b201-4815-9a8d-387166917e22','酬上官右史','釋元肇','宋','宋诗','song-poetry','','[]','住山今幾年，歸興只飄然。',48,'全唐诗/poet.song.203000.json','["住山今幾年，歸興只飄然。", "野水無邊際，浮雲自變遷。", "螭坳曾侍立，漁火對愁眠。", "二老成來往，三生定有緣。"]'),
('63551dc7-4eb2-467a-807b-bd27b6199da0','泊然','釋元肇','宋','宋诗','song-poetry','','[]','真箇無營者，方能向此居。',48,'全唐诗/poet.song.203000.json','["真箇無營者，方能向此居。", "花間誰是蝶，池上不知魚。", "竹戶清陰碎，苔階翠點疎。", "東西幾片壁，只貼坐忘書。"]'),
('707f9b01-ed8a-4926-9482-b370b71f7d4d','天台道中','釋元肇','宋','宋诗','song-poetry','','[]','麥壠桑麻接，行行百里賒。',48,'全唐诗/poet.song.203000.json','["麥壠桑麻接，行行百里賒。", "一番飛穀雨，滿地落桐花。", "水曲成三渡，山坳忽數家。", "歸來襟袖上，猶带赤城霞。"]'),
('4b48366c-578e-4a8f-b4d4-eaeb97bd8bc2','怡雲','釋元肇','宋','宋诗','song-poetry','','[]','雲是無心物，悠悠天地間。',48,'全唐诗/poet.song.203000.json','["雲是無心物，悠悠天地間。", "長年抱幽石，何處覓深山。", "白日看舒卷，清風任往還。", "有時隨雨去，不似老僧閑。"]'),
('8d2c93f0-0453-4752-b248-7a641d361655','施東洲蒼雲','釋元肇','宋','宋诗','song-poetry','','[]','東洲一片雲，凝住石湖濱。',48,'全唐诗/poet.song.203000.json','["東洲一片雲，凝住石湖濱。", "群岫堆蒼玉，萬松生翠鱗。", "相看碑上字，不死墓中人。", "曾筆中興事，傷時在泣麟。"]'),
('4ba70c01-60e1-459f-8755-b0c8807efcef','漁父','釋元肇','宋','宋诗','song-poetry','','[]','身外即江山，流行坎止間。',48,'全唐诗/poet.song.203000.json','["身外即江山，流行坎止間。", "烟波垂釣直，天地一舟閑。", "到岸賣魚去，無錢得酒還。", "不知塵世換，幾度月彎彎。"]'),
('a14872dd-2d15-4ba3-9afd-bc5224c91b2e','水竹園','釋元肇','宋','宋诗','song-poetry','','[]','開園多傍水，種竹近臨臯。',48,'全唐诗/poet.song.203000.json','["開園多傍水，種竹近臨臯。", "試問諸君子，何須快剪刀。", "清風招六逸，碧浪識三高。", "却笑任公子，持竿欲釣鰲。"]'),
('86517c2c-2d75-4041-9371-d4f680775a87','寄張書監','釋元肇','宋','宋诗','song-poetry','','[]','張公深隠處，花墅竹間籬。',48,'全唐诗/poet.song.203000.json','["張公深隠處，花墅竹間籬。", "不作明時用，能令薄俗移。", "高風喧地籟，清節照天池。", "月下常來往，幽禽野鹿知。"]'),
('fe9f7f45-2f88-4996-a0d0-303b231a271d','琴川圖','釋元肇','宋','宋诗','song-poetry','','[]','勝處著幽亭，烟林四望平。',48,'全唐诗/poet.song.203000.json','["勝處著幽亭，烟林四望平。", "高山千古意，流水七弦情。", "偃室猶堪仰，虞風舊有名。", "丹青難下手，松竹自傳聲。"]'),
('48a398ef-2bfe-4a4f-9a5d-b911f647dfaa','上官右史慶幸堂','釋元肇','宋','宋诗','song-poetry','','[]','先生何慶幸，年老樂安閑。',48,'全唐诗/poet.song.203000.json','["先生何慶幸，年老樂安閑。", "得地無多畝，營堂不數間。", "種花皆結子，移石便成山。", "只有雙雙鶴，相隨日往還。"]'),
('3c57a33c-9e89-449e-90c6-c1de90bd570c','竹石','釋元肇','宋','宋诗','song-poetry','','[]','脩篁擁翠幢，魁石坐端方。',48,'全唐诗/poet.song.203000.json','["脩篁擁翠幢，魁石坐端方。", "勁節經寒在，新梢入夏長。", "雲從根上起，玉向實中藏。", "爲雨從龍後，清風滿菊堂。"]'),
('d2641c62-4f73-445b-8e6b-a429f97c6b79','潤雲','釋元肇','宋','宋诗','song-poetry','','[]','高結據空虛，吳中大隠居。',48,'全唐诗/poet.song.203000.json','["高結據空虛，吳中大隠居。", "碧雲生暮景，清氣浥樓書。", "座上通玄客，門前長者車。", "東隅貫休閣，相望復何如。"]'),
('ec95ca31-f818-46b7-bf1d-f50a3e4640d9','宜靜','釋元肇','宋','宋诗','song-poetry','','[]','日月忙推轂，乾坤著草亭。',48,'全唐诗/poet.song.203000.json','["日月忙推轂，乾坤著草亭。", "一波才底定，萬化自消停。", "幽極風敲竹，微聞鶴振翎。", "白雲雖自在，爭似遠山青。"]'),
('d6f65a68-9af1-43b9-a881-842b3ff91379','梅月','釋元肇','宋','宋诗','song-poetry','','[]','堂上傳風雅，高標一段奇。',48,'全唐诗/poet.song.203000.json','["堂上傳風雅，高標一段奇。", "韻清梅蘸水，生白月來時。", "有影皆成畫，無聲總是詩。", "屋頭春信早，催發向南枝。"]'),
('6a57cb47-808b-47aa-9979-77a82184b2e8','過鄭文昌庵','釋元肇','宋','宋诗','song-poetry','','[]','臘天三四日，曾到錦峯來。',48,'全唐诗/poet.song.203000.json','["臘天三四日，曾到錦峯來。", "世上無知己，松根坐古苔。", "茶烟凝戶曉，風雪打舡回。", "却憶星辰履，如今安在哉。"]'),
('0e74512e-29f9-4101-b932-0bc0c42516aa','和洪提舉送平齋集','釋元肇','宋','宋诗','song-poetry','','[]','平齋大全集，千古播幽芳。',48,'全唐诗/poet.song.203000.json','["平齋大全集，千古播幽芳。", "騷雅杜陵老，雄深馬子長。", "天能留稷契，世可致虞唐。", "樂府尤清麗，難回鐵石腸。"]'),
('7befbc2f-e808-4194-b639-493a3d4422f2','得坐','釋元肇','宋','宋诗','song-poetry','','[]','一室坐春空，寥寥萬境容。',48,'全唐诗/poet.song.203000.json','["一室坐春空，寥寥萬境容。", "月移旁砌竹，風借別樓鐘。", "暗處元非滯，明邊亦是逢。", "五更侵早起，清露滴長松。"]'),
('86c4db16-a131-470a-a58d-ea519ad1cd3d','落花','釋元肇','宋','宋诗','song-poetry','','[]','萬紫及千紅，枝頭一餉空。',48,'全唐诗/poet.song.203000.json','["萬紫及千紅，枝頭一餉空。", "多因傷夜雨，曾不怨春風。", "片片隨流去，紛紛夕照中。", "自開還自落，只與去年同。"]'),
('787dd64a-9b74-478b-888a-9e2ff2f8195d','秋日菴居','釋元肇','宋','宋诗','song-poetry','','[]','開門一逕通，花木四時同。',48,'全唐诗/poet.song.203000.json','["開門一逕通，花木四時同。", "陰密松成蓋，香多桂作叢。", "鑿池要皓月，移竹種清風。", "未息塵機者，應難到此中。"]'),
('e5721713-21bb-4b47-ab04-b72b6af3bd79','九日','釋元肇','宋','宋诗','song-poetry','','[]','今逢重九名，居野見幽清。',48,'全唐诗/poet.song.203000.json','["今逢重九名，居野見幽清。", "地靜黄花早，天空落葉聲。", "耕人齊上壟，荒日半沈城。", "除却陶彭澤，同誰話此情。"]'),
('255b1078-1490-421d-9968-0aa9118fccc4','火閤','釋元肇','宋','宋诗','song-poetry','','[]','裝折圍爐地，方方七尺强。',48,'全唐诗/poet.song.203000.json','["裝折圍爐地，方方七尺强。", "易容元亮膝，難著浄名床。", "省炭功雖小，燒香味較長。", "晏然宜袖手，免去暴朝陽。"]'),
('e90ff29f-93b7-4410-b5b8-68d0c5ca9f0b','乖目相者','釋元肇','宋','宋诗','song-poetry','','[]','一雙乖角眼，閲世妙無倫。',48,'全唐诗/poet.song.203000.json','["一雙乖角眼，閲世妙無倫。", "白日常穿市，青雲少見人。", "未嘗眠鎖店，午後聽鐘鄰。", "盍向邊頭看，誰爲閣上麟。"]'),
('55b0c433-41d0-4164-93e5-4de7610a47e1','披雲庵','釋元肇','宋','宋诗','song-poetry','','[]','絕頂住居安，千峯翠作攢。',48,'全唐诗/poet.song.203000.json','["絕頂住居安，千峯翠作攢。", "風吹雲影破，天漏月光寒。", "野水無行路，孤松半倚看。", "有時吟到曉，清韻激飛湍。"]'),
('63fcea45-9240-4d9e-8655-10dbb97057d4','馬宋英畫松','釋元肇','宋','宋诗','song-poetry','','[]','元氣淋漓濕，畫師今幾人。',48,'全唐诗/poet.song.203000.json','["元氣淋漓濕，畫師今幾人。", "宋英傳古色，韋偃是前身。", "森竦髯如蝟，粼皴鐵作鱗。", "蟠根巖壑底，多幸不遭秦。"]'),
('276d19e8-dbdd-45d1-b1ac-61245922f29b','寄題趙山臺蓮華方丈','釋元肇','宋','宋诗','song-poetry','','[]','十尺方圍地，一枰雲錦衣。',48,'全唐诗/poet.song.203000.json','["十尺方圍地，一枰雲錦衣。", "禪心不著水，天女暗投機。", "莫道榮枯異，誰云語默非。", "荷間休結屋，趣入道山歸。"]'),
('04788951-6ca1-49b5-ab5f-60151a90ab3a','嘯巖','釋元肇','宋','宋诗','song-poetry','','[]','丘石虎西蹲，月明煙水村。',48,'全唐诗/poet.song.203000.json','["丘石虎西蹲，月明煙水村。", "扣舷穿蠡口，長嘯徹蘇門。", "要得却胡騎，應須夢至尊。", "苦吟天地窄，萬物本同根。"]'),
('af8dd6d9-29b6-4097-9c45-24d274c281a8','送印寶章知溫州','釋元肇','宋','宋诗','song-poetry','','[]','東嘉山水郡，靈運後知名。',48,'全唐诗/poet.song.203000.json','["東嘉山水郡，靈運後知名。", "孤嶼雲簪筆，清江玉带城。", "伏波思鴈遠，春草夢詩成。", "五馬人生貴，二難時共榮。"]'),
('656450da-a3ac-4055-b916-fced04ec2176','蒙齋','釋元肇','宋','宋诗','song-poetry','','[]','蒙居養正齋，清景湛靈臺。',48,'全唐诗/poet.song.203000.json','["蒙居養正齋，清景湛靈臺。", "疊石移山至，開池待月來。", "是誰游象外，求我放心回。", "庭際風敲竹，分陰滿綠苔。"]'),
('8381cc30-905f-42fd-b0fc-33bbf20ee034','水心先生挽章二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','歸自金陵後，情疎狎隠淪。',48,'全唐诗/poet.song.203000.json','["歸自金陵後，情疎狎隠淪。", "身緣憂國瘦，家爲著書貧。", "江海星沈夜，池塘草不春。", "門生天下是，椽筆付何人。"]'),
('c179171e-2ba6-4c7e-bcc7-2c8f0f4e53d8','水心先生挽章二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','孤嶼秋風寺，三過夫子家。',48,'全唐诗/poet.song.203000.json','["孤嶼秋風寺，三過夫子家。", "古心堅鐵石，軟語带烟霞。", "別嶺栖雙徑，逢人問永嘉。", "重看送行句，殞泪墨欹斜。"]'),
('021e5e09-d5a0-4598-9321-4a14928c205b','方蕙巖常簿二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','名教非無樂，何緣事上眉。',48,'全唐诗/poet.song.203000.json','["名教非無樂，何緣事上眉。", "不閑因接物，先老爲憂時。", "兩郡垂棠蔭，東園長桂枝。", "用公渾未盡，一世有餘悲。"]'),
('a4043b7e-f967-4be4-8ef6-c80a30843bc9','方蕙巖常簿二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','夙昔住山緣，來吳已八年。',48,'全唐诗/poet.song.203000.json','["夙昔住山緣，來吳已八年。", "獨憐寒塔影，時到碧巖前。", "埋玉亡何日，愁雲過別天。", "東風減回首，家學子能傳。"]'),
('1db9e999-680c-4619-bef1-6a49bd681dd6','張廉州奏院','釋元肇','宋','宋诗','song-poetry','','[]','合浦歸來久，遲敲月下門。',48,'全唐诗/poet.song.203000.json','["合浦歸來久，遲敲月下門。", "今朝隔生死，無處問乾坤。", "斜日寒天短，愁雲遠水吞。", "湖趺溪畔石，空憶繫舟痕。"]'),
('ab7a39ea-9fef-4dbb-9096-8a1686657489','吳荆溪大監','釋元肇','宋','宋诗','song-poetry','','[]','遥辭下石橋，南岳阻招邀。',48,'全唐诗/poet.song.203000.json','["遥辭下石橋，南岳阻招邀。", "五載未相見，三除不入朝。", "玉樓催作記，瓊闕伴吹簫。", "嘆世無知己，文章竟寂寥。"]'),
('cdc0cc4a-0349-4c5c-a2cc-f1bcaa2be845','趙東閣奏院','釋元肇','宋','宋诗','song-poetry','','[]','東閣王孫貴，才名似謫仙。',48,'全唐诗/poet.song.203000.json','["東閣王孫貴，才名似謫仙。", "可憐頒郡下，不及蓋棺前。", "家乏千金計，詩應萬古傳。", "生來同四柱，豈料哭君先。"]'),
('2bdae12a-1614-4629-8966-aa42691173ef','周伯弜明府','釋元肇','宋','宋诗','song-poetry','','[]','昨過楊州日，知君病已侵。',48,'全唐诗/poet.song.203000.json','["昨過楊州日，知君病已侵。", "殊非折腰具，竟作斷弦吟。", "遠信逢秋笛，驚哀徹樹禽。", "有才無命者，從古至于今。"]'),
('c3eb27cc-f66d-43df-a4b5-49435fc481e5','印僉判','釋元肇','宋','宋诗','song-poetry','','[]','才業魁多士，英聲早歲馳。',48,'全唐诗/poet.song.203000.json','["才業魁多士，英聲早歲馳。", "宦涂將晚達，賢路有深知。", "月借山城白，風飄鼓角悲。", "用公渾不盡，珠樹照清時。"]'),
('1d53f731-fbfb-42fb-9aae-ab1f896b9a12','陸稅院','釋元肇','宋','宋诗','song-poetry','','[]','甫里雲間譜，知幾類計然。',48,'全唐诗/poet.song.203000.json','["甫里雲間譜，知幾類計然。", "本期拋舊宅，豈料見新阡。", "宦遠無年及，門高有子傳。", "鄉音何處認，哀泣似淮堧。"]'),
('56d874bc-9737-4592-9ab3-c0989acd0530','陳孺人','釋元肇','宋','宋诗','song-poetry','','[]','靜正成家道，賢明訓子孫。',48,'全唐诗/poet.song.203000.json','["靜正成家道，賢明訓子孫。", "園林冬出笋，霜露早摧萱。", "有泪瞻遺像，無言似倚門。", "傷心夜臺月，不照再承恩。"]'),
('8c1805d8-de8f-4d48-95c1-6f0512237d77','寧少耘','釋元肇','宋','宋诗','song-poetry','','[]','逢師竹澗旁，歲慘下歸航。',48,'全唐诗/poet.song.203000.json','["逢師竹澗旁，歲慘下歸航。", "我獨疑深隠，僧來說坐亡。", "草墟曾住寺，塵鏁別營房。", "渺渺吳中道，無因過上塘。"]'),
('eea41070-b1fb-4183-932d-1b2bf98ed5e7','舟別浦禪師塔','釋元肇','宋','宋诗','song-poetry','','[]','諸老凋零盡，江湖轉憶君。',48,'全唐诗/poet.song.203000.json','["諸老凋零盡，江湖轉憶君。", "人經十年換，寺革一番焚。", "庭冷池來月，山空塔裹雲。", "惟應有游衲，時到炷爐薰。"]'),
('064c32fa-0703-452b-9dbd-235a288908fc','天台山中十首  其一','釋元肇','宋','宋诗','song-poetry','','[]','道喪幾千載，不復還其淳。',48,'全唐诗/poet.song.203000.json','["道喪幾千載，不復還其淳。", "强者用詐力，弱者傷夷淪。", "芒芒大塊中，何人得其真。", "已矣難重陳，吾將誰與鄰。"]'),
('0886687c-9414-4c79-b347-ad0052f3fe48','天台山中十首  其二','釋元肇','宋','宋诗','song-poetry','','[]','千山萬山中，翠薜相交羅。',48,'全唐诗/poet.song.203000.json','["千山萬山中，翠薜相交羅。", "春風來何遲，積雪常峩峩。", "折木有清響，采薇聞遠歌。", "不因尋石橋，長年無人過。"]'),
('06039d78-619e-4c40-b96d-3cff737735a8','天台山中十首  其三','釋元肇','宋','宋诗','song-poetry','','[]','面對香爐峰，朝昏起雲霧。',48,'全唐诗/poet.song.203000.json','["面對香爐峰，朝昏起雲霧。", "飄飄無定形，忽被風吹去。", "去去還復留，半挂長松樹。", "悠然會我心，政自有佳趣。"]'),
('e1b87c56-6bc8-48eb-a396-bd5b76c52078','天台山中十首  其四','釋元肇','宋','宋诗','song-poetry','','[]','四時多幽禽，日日鳴前林。',48,'全唐诗/poet.song.203000.json','["四時多幽禽，日日鳴前林。", "呼喚烟樹重，應答山水深。", "靜中無別響，獨聽有餘音。", "載歌仍載吟，半晴還半陰。"]'),
('52132fbc-0290-450c-8360-62c2b730d392','天台山中十首  其五','釋元肇','宋','宋诗','song-poetry','','[]','澗底有清泉，日夜鳴涓涓。',48,'全唐诗/poet.song.203000.json','["澗底有清泉，日夜鳴涓涓。", "風聲過樹頭，月色當窗前。", "起坐不成寐，白髮悲流年。", "向來稱達人，兩耳何緣濺。"]'),
('b21d08a5-5f92-4d9b-849a-62147c62cfe0','天台山中十首  其六','釋元肇','宋','宋诗','song-poetry','','[]','山中産靈藥，四望清藹藹。',48,'全唐诗/poet.song.203000.json','["山中産靈藥，四望清藹藹。", "神僊久不逢，世上何人采。", "桃源路豈遥，蓬萊非隔海。", "惟有天地根，古今常獨在。"]'),
('9e79b47f-ac02-49de-9f54-4d3e163b4fd6','天台山中十首  其七','釋元肇','宋','宋诗','song-poetry','','[]','蘭生在深林，衆草相陸沈。',48,'全唐诗/poet.song.203000.json','["蘭生在深林，衆草相陸沈。", "微承雨露滋，積受霜雪侵。", "幽薌時一吹，樵牧空見尋。", "采采當我前，遠此違世心。"]'),
('1ac8db39-e0c6-455b-a165-1f66ce0fa50a','天台山中十首  其八','釋元肇','宋','宋诗','song-poetry','','[]','紅紅白白花，萬萬千千樹。',48,'全唐诗/poet.song.203000.json','["紅紅白白花，萬萬千千樹。", "開亦不知名，落亦不知數。", "幽禽來上啼，野鹿銜將去。", "可望不可攀，四向高無路。"]'),
('6dd94df9-f6b6-4eb9-ac0f-fe4d613eace1','天台山中十首  其九','釋元肇','宋','宋诗','song-poetry','','[]','野草紛其類，托根孤高地。',48,'全唐诗/poet.song.203000.json','["野草紛其類，托根孤高地。", "誰榮誰瘁之，動摇春風至。", "凄迷烟雨中，碧滿閑庭際。", "王孫歸不歸，山深易寒氣。"]'),
('6edcd6ef-7d65-41e5-bb5b-34e9c6cbe8ed','天台山中十首  其一○','釋元肇','宋','宋诗','song-poetry','','[]','爲愛簷前竹，特立萬竿玉。',48,'全唐诗/poet.song.203000.json','["爲愛簷前竹，特立萬竿玉。", "蕭蕭送雨聲，沈沈照窗綠。", "風雪凌壓之，可摧不可曲。", "澹然如幽人，長年在空谷。"]'),
('b63cb29a-5f40-4e40-9749-e8acb16d236e','許來亭','釋元肇','宋','宋诗','song-poetry','','[]','猗歟觀石橋，境物皆天趣。',84,'全唐诗/poet.song.203000.json','["猗歟觀石橋，境物皆天趣。", "山高礙鳥飛，瀑響驚龍睡。", "真流半千尊，只在雲中住。", "驗盡世間人，到此煎茶去。", "曇猷昔何爲，苦苦欲相遇。", "餠峯忽面牆，石上穿雙泪。", "他年許重來，老却青松樹。"]'),
('1c3e772b-8297-4b9d-8082-d716548327eb','擬寒山吳下菴居','釋元肇','宋','宋诗','song-poetry','','[]','一昨離天台，事事皆不會。',120,'全唐诗/poet.song.203000.json','["一昨離天台，事事皆不會。", "西風信杖藜，吹落齊關外。", "主人新卜築，林塘倏蒼薈。", "埤堄隠周遭，市聲隔繁碎。", "出門與入門，朝昏隨向背。", "浮圖一兩尖，雲際忽相對。", "鴈陣拽如繩，鴉喚斜陽隊。", "有僧來扣門，路跨田翁耒。", "人應笑我疎，我笑人多昧。", "古今佳遯情，可在此菴內。"]'),
('1eded822-6fa9-4192-9364-e737cb5e98ad','題楊梅山人渭川圖','釋元肇','宋','宋诗','song-poetry','','[]','不識山人面，今見山人竹。',60,'全唐诗/poet.song.203000.json','["不識山人面，今見山人竹。", "鵝溪半幅間，渭川千畝足。", "細細穿石泉，猗猗動寒綠。", "望之意已凉，况當親㨫觸。", "賢哉懷隠居，疇能繼高躅。"]'),
('31b7bf6f-efe0-4b50-9e01-4700096a20b8','羅漢樹','釋元肇','宋','宋诗','song-poetry','','[]','人生天地間，飄然無根蔕。',240,'全唐诗/poet.song.203000.json','["人生天地間，飄然無根蔕。", "貴賤壽夭形，總被造物戲。", "達者常晏如，不作包桑計。", "如何閒草木，剛受人嫵媚。", "寒松作大夫，枯木號居士。", "便有徼福人，未免斧斤至。", "孤高本無心，反以名疣贅。", "此樹亦歲寒，婆娑立蒼翠。", "著子秋纍纍，何啻五百位。", "顱圓從誰度，身紫何人賜。", "問之無人說，法門入不二。", "喬特不世情，與我却相類。", "許我折一枝，幽窗浸缶器。", "辭柯漏已空，森然遂生意。", "荏苒三暑寒，傲睨萬物顇。", "翻思陰陽家，水木推生利。", "但存節操堅，莫訝垛根異。", "鴈蕩與天台，泉石平生志。", "木上座脫洒，竹尊者風味。", "何當笑相逢，同歸第一義。"]'),
('dc1a1246-32fb-4b19-b451-a49f6db57785','縣胥歸耕','釋元肇','宋','宋诗','song-poetry','','[]','籠中無樂鳥，檻外無樂獸。',96,'全唐诗/poet.song.203000.json','["籠中無樂鳥，檻外無樂獸。", "何嘗費飲啄，不忘念翔驟。", "子今既知此，欲拂事公袖。", "不將無事眉，閑爲鞭笞皺。", "社甕雖濁醪，勝醉歌樓酎。", "婦饁雖糗糲，勝冷書案豆。", "門前有追胥，皂衣皆我舊。", "布穀鳴春深，斯言誠可復。"]'),
('d6be014a-a366-4d3a-a3d0-00b7f8eb8c7d','高鼓院桃村','釋元肇','宋','宋诗','song-poetry','','[]','舉頭見青山，高與天齊平。',216,'全唐诗/poet.song.203000.json','["舉頭見青山，高與天齊平。", "俯首鑑靈泉，派分天池清。", "是中十畝園，爛若紅霞蒸。", "夫差昔不國，舞榭歌臺傾。", "風驚柳腰折，雨集蛙部鳴。", "靄靄墟里煙，紛紛鷄犬聲。", "寂寥千載後，公來暢幽情。", "手種桃千株，草架屋數楹。", "厥壤宜芬芳，昭儉易落成。", "子孫相追隨，日夕生遐征。", "公今雲臺仙，輕强垂百齡。", "支筇歌紫芝，倚松誦黄庭。", "綠陰長蟠實，白蓮闖池生。", "客從何方來，畧不通姓名。", "自云多昔人，食之能飛升。", "更老上所尊，只恐蒲輪徵。", "公乎笑而已，客言曾不聽。", "歸來向人說，洞口雲縱橫。"]'),
('325b7034-9ba6-49bb-a864-7737bb9a25e1','二蟲詩','釋元肇','宋','宋诗','song-poetry','','[]','蛛螫包禍心，滿腹皆素絲。',168,'全唐诗/poet.song.203000.json','["蛛螫包禍心，滿腹皆素絲。", "補綴曾無功，貪傷不知疲。", "誰云禁網密，施設近茅茨。", "旦暮待游蚋，所得亦已卑。", "蝎虎誇捷巧，緣壁行跂跂。", "蛜蝛青蠅輩，苦遭暗中窺。", "失身在蛛網，竟日秋簷垂。", "蛛猶懼蝎紿，睥睨不敢爲。", "蛛網既已裂，蝎命不亦危。", "嗟哉復嗟哉，誠大黠小癡。", "紛紛事爭奪，復何異於斯。", "我閔爲解粘，蝎去何所知。", "但令嬉飽日，莫忘倒縣時。", "感彼兩物情，成此一篇詩。"]'),
('373e2e17-aee3-47a6-b4e2-93d04a95efd4','和上官右史韻','釋元肇','宋','宋诗','song-poetry','','[]','夫子作春秋，大義明素王。',96,'全唐诗/poet.song.203000.json','["夫子作春秋，大義明素王。", "至于游夏輩，一字不敢當。", "文風下秦漢，詩體更晉唐。", "世道有隆替，人才隨翕張。", "致君與澤民，夷險公備嘗。", "山川尋謝屐，風月歸奚囊。", "滿城風雨朝，采采籬下黄。", "臨風懷美人，在彼天一方。"]'),
('0f303799-6727-423a-8b72-26179c860578','上水心先生三首  其一','釋元肇','宋','宋诗','song-poetry','','[]','文字滔滔江漢東，早從伊洛定宗風。',64,'全唐诗/poet.song.203000.json','["文字滔滔江漢東，早從伊洛定宗風。", "中興之後數人物，北斗以南唯此公。", "聞道治平猶草奏，向來持論不和戎。", "匪伊再入脩門去，只有孤忠與昔同。"]'),
('0260a869-4c33-4b9a-88c7-b848c73c7059','上水心先生三首  其二','釋元肇','宋','宋诗','song-poetry','','[]','華髮蕭騷減带圍，可勝憂國更傷時。',64,'全唐诗/poet.song.203000.json','["華髮蕭騷減带圍，可勝憂國更傷時。", "樂天名位微堪酒，靈運池塘不廢詩。", "架上牙籤燒燭短，窗間花影轉春遲。", "天教惜取如椽筆，要勒磨崖大字碑。"]'),
('cb4deb14-1d62-4f6b-972a-1e226dbb04ec','上水心先生三首  其三','釋元肇','宋','宋诗','song-poetry','','[]','十年缾鉢走天涯，四海聲名一永嘉。',64,'全唐诗/poet.song.203000.json','["十年缾鉢走天涯，四海聲名一永嘉。", "不趁新霜嘗橘柚，了無歸夢到蒹葭。", "江頭來往春强半，門外推敲月又斜。", "換骨奪胎如得妙，願從勾漏問丹砂。"]'),
('bd794fef-f635-4a88-9943-36d569acf732','寄上制使賈端明二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','洛陽聲賈自傳臚，三十專城總要涂。',64,'全唐诗/poet.song.203000.json','["洛陽聲賈自傳臚，三十專城總要涂。", "黄鶴樓中納雲夢，碧油幢下重江都。", "爭誇國士無雙傑，堪對瓊花獨一株。", "王事只消談笑了，好吟佳句繼歐蘇。"]'),
('3f929e22-f96c-4296-9726-6e87d7e3d706','寄上制使賈端明二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','天台山壓衆峰高，極勝窮幽是石橋。',64,'全唐诗/poet.song.203000.json','["天台山壓衆峰高，極勝窮幽是石橋。", "在昔一詩留翠壁，至今萬壑響青霄。", "淮南草木皆霑潤，塞北煙塵即便銷。", "將相功名古來有，可曾江上問漁樵。"]'),
('7dd0a01d-862e-4c7c-b5dc-f31c7f0498ac','江心春日','釋元肇','宋','宋诗','song-poetry','','[]','江邊春日正遲遲，岸草汀蒲綠漲肥。',64,'全唐诗/poet.song.203000.json','["江邊春日正遲遲，岸草汀蒲綠漲肥。", "有戶不扃僧懶出，種花無地客來稀。", "破烟白鳥成雙下，度壍昏鴉接翅歸。", "流轉自憐鄉國異，風光隨處不相違。"]'),
('c0c2f5f3-304b-4649-aea3-b42221adde46','次呂教授游江心韻','釋元肇','宋','宋诗','song-poetry','','[]','魚龍吹浪雪霏霏，更著青山倚落暉。',64,'全唐诗/poet.song.203000.json','["魚龍吹浪雪霏霏，更著青山倚落暉。", "一幅風帆到煙寺，十年塵土愧征衣。", "漁家蓑笠應堪換，老宿缾盂未可依。", "回首謝公樓上去，池塘春草昔人非。"]'),
('2c69e49b-5aa2-4509-b0e7-96f88c29a915','湖上','釋元肇','宋','宋诗','song-poetry','','[]','五年踏破幾芒鞋，山色湖光識再來。',64,'全唐诗/poet.song.203000.json','["五年踏破幾芒鞋，山色湖光識再來。", "魚鳥散時浮鼓吹，煙雲缺處見樓臺。", "白綿飛盡蘇公柳，青豆初嘗處士梅。", "小立東風爭渡急，句中無地著塵埃。"]'),
('a7f983bc-a36e-487c-93bb-e207aec2f836','庵中牡丹','釋元肇','宋','宋诗','song-poetry','','[]','誰將根底種靈丹，開處凡花比亦難。',64,'全唐诗/poet.song.203000.json','["誰將根底種靈丹，開處凡花比亦難。", "勝賞莫嫌僧院僻，久長留到子孫看。", "有時垂泪傷多雨，未肯扶頭怯曉寒。", "自笑色空俱照了，也來隨例並闌干。"]'),
('1c40255c-73b3-4f8a-84a1-05d03e3f7645','春郊有感','釋元肇','宋','宋诗','song-poetry','','[]','用舍行藏只自傷，五年留滯在江鄉。',64,'全唐诗/poet.song.203000.json','["用舍行藏只自傷，五年留滯在江鄉。", "青松遠引來南塔，白髮猶欣見北堂。", "麥浪有時迎燕舞，菜花無頼學鶑黄。", "騎馿又打津頭過，楊柳飛綿出短牆。"]'),
('ec4a2560-b21b-4145-96f9-2dcdcf5dd10e','舟中','釋元肇','宋','宋诗','song-poetry','','[]','三月長安似夢中，回頭春事已成空。',64,'全唐诗/poet.song.203000.json','["三月長安似夢中，回頭春事已成空。", "桑麻暗鎖村村雨，蒲稗新翻浦浦風。", "燕子不知家遠近，杜鵑長怨客西東。", "籬根竹外無人見，猶有殘花墮曉紅。"]'),
('845e8ddd-6dfc-4d32-a8e9-ff7bd3a81d2a','春日書懷','釋元肇','宋','宋诗','song-poetry','','[]','靜倚晴窗笑此生，出遊歸隠兩無成。',64,'全唐诗/poet.song.203000.json','["靜倚晴窗笑此生，出遊歸隠兩無成。", "故園小作三春夢，倦翼長垂萬里情。", "庭樹欲紅聞鳥閙，郊原新綠見人耕。", "湖山舊友如相問，只向梅花說姓名。"]'),
('4f42c971-7dbe-4c41-bcc6-7a28679d1af6','雪竇','釋元肇','宋','宋诗','song-poetry','','[]','上盡崎嶇脚力微，毳袍零碎染煙霏。',64,'全唐诗/poet.song.203000.json','["上盡崎嶇脚力微，毳袍零碎染煙霏。", "妙高峯頂見日出，千丈巖前看雪飛。", "寒木著霜山衣錦，清池得月鏡交輝。", "翩然又作東南去，肯落台溫第二機。"]'),
('7c7a9909-a14a-4af5-b126-8816b39fdcc2','鴈山夏夜','釋元肇','宋','宋诗','song-poetry','','[]','浮嵐空翠濕衣襟，合磵流泉奏玉琴。',64,'全唐诗/poet.song.203000.json','["浮嵐空翠濕衣襟，合磵流泉奏玉琴。", "古殿薌寒起僧定，莫樓煙重咽鐘音。", "隨風螢火光明滅，得雨芭蕉語淺深。", "猛省南來二千里，不應翻作兔投林。"]'),
('82aaf187-0065-4955-954a-da653fc23008','張宰湖山堂','釋元肇','宋','宋诗','song-poetry','','[]','別來萍梗浙東西，得向湖山手重携。',64,'全唐诗/poet.song.203000.json','["別來萍梗浙東西，得向湖山手重携。", "風定波間鷗出沒，雲深天闊鴈高低。", "擬將脩竹題歸隠，長恐扁舟路欲迷。", "明日棹歌回首處，葦花蘋葉冷凄凄。"]'),
('c50bf360-088d-4e00-a5aa-4ea1854cadd8','狼山池上有感','釋元肇','宋','宋诗','song-poetry','','[]','池上凉多生萬松，登臨懷感興何窮。',64,'全唐诗/poet.song.203000.json','["池上凉多生萬松，登臨懷感興何窮。", "催詩不雨雲空黑，結社無人蓮自紅。", "翡翠得魚忙蘸水，蜻蜓避燕巧低風。", "靈龜未解蒙莊意，慇慇時來亂葉中。"]'),
('ee703769-3b16-4352-9773-78c6327a5ddf','蔡守監丞得祠次韻送之','釋元肇','宋','宋诗','song-poetry','','[]','墨行儒名固可麾，愧無織錦別梭機。',64,'全唐诗/poet.song.203000.json','["墨行儒名固可麾，愧無織錦別梭機。", "隔林喜聽黄鸝語，離岸愁看畫鷁飛。", "松菊未荒三徑在，山川都是幾人非。", "只應父老千行泪，立盡斜陽未肯歸。"]'),
('c56d807c-81df-429f-b98e-e6dac4eee5e9','和楊節使登徑山','釋元肇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閶闔門西湖水臨，深深院落見春心。',64,'全唐诗/poet.song.203000.json','["閶闔門西湖水臨，深深院落見春心。", "梨花風弄影來去，燕子日長談古今。", "起早每緣朝玉闕，歸遲多是宴瓊林。", "肯將吹竹彈絲耳，來聽重雲鐘鼓音。"]'),
('5f983246-3962-4080-b566-300cfef159c2','過無懷故廬','釋元肇','宋','宋诗','song-poetry','','[]','壯歲無心預祖圖，莫年卜築伴林逋。',64,'全唐诗/poet.song.203000.json','["壯歲無心預祖圖，莫年卜築伴林逋。", "閒名已在羲皇上，詩句曾將島可奴。", "尚想風流悲斷柳，更無人共致生芻。", "自憐淮海飄零客，也向春風聽鷓鴣。"]'),
('4512e19d-73f4-4ac7-bd5e-470402001caf','和白玉蟾韻','釋元肇','宋','宋诗','song-poetry','','[]','蓬萊仙客興無酬，汗漫來游海上州。',64,'全唐诗/poet.song.203000.json','["蓬萊仙客興無酬，汗漫來游海上州。", "明月滿山歌踏踏，紅塵入市笑休休。", "釣竿不用空遮日，詩句時能一掉頭。", "醉後抱琴歸去也，人間知是幾春秋。"]'),
('9473471d-fdc7-4276-a5f5-90875e70783b','舟中雪','釋元肇','宋','宋诗','song-poetry','','[]','扁舟泊晚櫓咿啞，飄灑隨風整復斜。',64,'全唐诗/poet.song.203000.json','["扁舟泊晚櫓咿啞，飄灑隨風整復斜。", "照夜初疑篷背月，隔溪遥認樹頭花。", "村深浦遠人迷路，葦折荷傾鴈著沙。", "漁父披蓑歸去後，带煙茅屋兩三家。"]'),
('19fcd1af-5311-46e7-adef-38609d85e36c','九日','釋元肇','宋','宋诗','song-poetry','','[]','曉煙和露濕秋光，幽鳥聲聲在翠篁。',64,'全唐诗/poet.song.203000.json','["曉煙和露濕秋光，幽鳥聲聲在翠篁。", "世事又隨明日別，菊花只作去年香。", "風前落帽人千古，雲外驚寒鴈一行。", "脫木蕭疎砧杵急，倚筇無語到斜陽。"]'),
('4adead95-e1cc-40fe-b5f8-152dfc63a3ce','聞邊報','釋元肇','宋','宋诗','song-poetry','','[]','高皇宏遠立規模，建武猶能復壯圖。',64,'全唐诗/poet.song.203000.json','["高皇宏遠立規模，建武猶能復壯圖。", "聞道煙塵暗淮海，夢成風雨落江湖。", "可無歸鴈傳家信，定有非熊出釣徒。", "目斷關河正愁絕，東風吹綠入平蕪。"]'),
('d825ff5f-8bdb-4543-aead-fe18e254da6b','贈畫僧之金陵','釋元肇','宋','宋诗','song-poetry','','[]','澹薄輕雲橫素秋，緩行籬落菊香浮。',64,'全唐诗/poet.song.203000.json','["澹薄輕雲橫素秋，緩行籬落菊香浮。", "我今已是溝中斷，君去還同水上鷗。", "鐘磬僧敲煙際寺，管弦人在夕陽樓。", "一江風月渾依舊，六代英雄畫得不。"]'),
('60cde560-454a-482b-b77a-69d5af6cbf7c','別心首座','釋元肇','宋','宋诗','song-poetry','','[]','四面湖山展畫屏，故人相見眼偏青。',64,'全唐诗/poet.song.203000.json','["四面湖山展畫屏，故人相見眼偏青。", "迎風春鳥語猶滑，過雨山花睡欲醒。", "出處既分南北海，別離空恨短長亭。", "明朝又作松江去，幾棹煙波月滿汀。"]'),
('16c9178d-eacf-43ba-b002-70a8a30d2892','仲子平下第二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','直道干時徒爾勞，歸來門徑長蓬蒿。',64,'全唐诗/poet.song.203000.json','["直道干時徒爾勞，歸來門徑長蓬蒿。", "朱研玉露點周易，燈撥金花讀楚騷。", "時把漁竿釣煙雨，閒同僧飯薦溪芼。", "兒曹不會箇中意，只管區區問綠袍。"]'),
('a442035e-8f54-4d2d-8031-417891173139','仲子平下第二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','不是雲林勝市朝，都將名利等鴻毛。',64,'全唐诗/poet.song.203000.json','["不是雲林勝市朝，都將名利等鴻毛。", "床頭紙被今年破，林外霜風昨夜高。", "虛白室無儋石計，清新詩有十分豪。", "黄花時節明朝是，冷眼相看栗里陶。"]'),
('8b36dde9-f84e-44bb-829b-108a0834deed','次陳平甫提幹晚春韻','釋元肇','宋','宋诗','song-poetry','','[]','莫雲豈特看江東，朋舊如今四海中。',64,'全唐诗/poet.song.203000.json','["莫雲豈特看江東，朋舊如今四海中。", "花落不禁三日雨，顔衰消得幾春風。", "簷前雛竹娟娟粉，階下櫻桃滴滴紅。", "辛苦廣騷將底用，弋人何處慕冥鴻。"]'),
('73aec087-b956-40a4-bced-1a3501b33087','次柳倅見寄','釋元肇','宋','宋诗','song-poetry','','[]','是中空洞任天游，去住飄然百不憂。',64,'全唐诗/poet.song.203000.json','["是中空洞任天游，去住飄然百不憂。", "黄獨有苗師懶瓚，碧雲無語繼湯休。", "才名如此分千里，道術相忘混九流。", "寄得詩來乘月看，滿身風露一庭秋。"]'),
('6a5ec26b-f65c-4e3a-9151-a20826ac7dfa','見海門韓宰','釋元肇','宋','宋诗','song-poetry','','[]','心遠遥知地自偏，杖藜隨處有雲泉。',64,'全唐诗/poet.song.203000.json','["心遠遥知地自偏，杖藜隨處有雲泉。", "朝來原上一犂雨，春到淮南二月天。", "短短菰蒲初弄水，依依楊柳欲摇煙。", "淵明自是無爲者，能使懦夫懷凜然。"]'),
('c139c229-eb68-4f76-ac8c-828dfd506b1c','徐丞見一堂','釋元肇','宋','宋诗','song-poetry','','[]','菊長新叢春事成，先生歸賦見深情。',64,'全唐诗/poet.song.203000.json','["菊長新叢春事成，先生歸賦見深情。", "麻衣草座自行樂，明月清風人不爭。", "郡榻莫留青眼舊，客星閑傍紫微明。", "箇中萬象渾無礙，門外何妨車馬聲。"]'),
('ae68e1fc-f93a-41f8-b43f-5cdc53451be6','喜雨','釋元肇','宋','宋诗','song-poetry','','[]','去年民病屢思安，天意爲霖不作難。',64,'全唐诗/poet.song.203000.json','["去年民病屢思安，天意爲霖不作難。", "地脈無窮窺井淺，波光不斷倚樓寬。", "梅林時落黄金彈，荷沼新擎碧玉盤。", "蛙吹莫供閑客耳，一時去和老農歡。"]'),
('ff5daba2-da63-4e53-85b1-9121565c83e4','雪','釋元肇','宋','宋诗','song-poetry','','[]','鬭舞爭飛住復飄，寒林開盡玉枝條。',64,'全唐诗/poet.song.203000.json','["鬭舞爭飛住復飄，寒林開盡玉枝條。", "清緣煮茗開蓬戶，冷爲尋梅過野橋。", "髣髴村前出圖畫，依稀江上見漁樵。", "牆根屋角且寧耐，留與詩人款寂寥。"]'),
('f6e501f8-4ae4-430b-ab3c-d7a551754abb','送杜守','釋元肇','宋','宋诗','song-poetry','','[]','一麾長嘯靜邊陲，丹詔飛催上玉墀。',64,'全唐诗/poet.song.203000.json','["一麾長嘯靜邊陲，丹詔飛催上玉墀。", "送別莫辭行路遠，感恩深是到州時。", "名垂峴首山能重，誓指江流水自知。", "他日登臨見遺愛，太平樓外柳絲絲。"]'),
('dd2c493d-c914-412f-8ae5-7a00aee6c7bf','送尹教授','釋元肇','宋','宋诗','song-poetry','','[]','鴈塔題名二十年，青衫手板坐無氈。',64,'全唐诗/poet.song.203000.json','["鴈塔題名二十年，青衫手板坐無氈。", "時清朝野諸公薦，句好江湖萬口傳。", "杜宇不啼淮樹冷，宮鶑未老上林煙。", "麟臺鳳閣思靈徹，只在山邊與水邊。"]'),
('2c5f319d-fafa-4111-a62b-07b391627d14','送林陶懽','釋元肇','宋','宋诗','song-poetry','','[]','不見陶懽今四載，欣然復會在通川。',64,'全唐诗/poet.song.203000.json','["不見陶懽今四載，欣然復會在通川。", "行囊覺重添新藁，顔貌如前轉少年。", "到處諸侯爭下榻，醉來騎馬似乘船。", "掉頭又向何方去，笑指長洲萬頃蓮。"]'),
('3c3276ab-9016-4089-8f3b-12a7818e7126','宿舊巢','釋元肇','宋','宋诗','song-poetry','','[]','故廬重到莫春時，物色風光總欠詩。',64,'全唐诗/poet.song.203000.json','["故廬重到莫春時，物色風光總欠詩。", "柳絮有情飛滿袖，牡丹無語恨空枝。", "燕歸不用深垂幕，笋出應須密護籬。", "明日籃輿又東去，迢迢煙草綠相隨。"]'),
('4bb4722c-82fd-44df-8a11-db7440e1ff36','中秋','釋元肇','宋','宋诗','song-poetry','','[]','滿目依然明鏡流，無家空折大刀頭。',64,'全唐诗/poet.song.203000.json','["滿目依然明鏡流，無家空折大刀頭。", "人間動是經年別，客裏尤深此夜愁。", "牢落關河還出塞，蕭條江國更登樓。", "不知何處風砧發，添得詩人兩鬢秋。"]'),
('34566f3f-19cc-453c-95b3-cc5e30755fef','宿西禪','釋元肇','宋','宋诗','song-poetry','','[]','竹杖芒鞋去問津，波生鴨綠草鋪茵。',64,'全唐诗/poet.song.203000.json','["竹杖芒鞋去問津，波生鴨綠草鋪茵。", "雨迷阡陌留連客，風入園林著摸人。", "寂寞數家收市井，蕭條一榻卧埃塵。", "避人幽鳥渾無語，桃李明朝依舊春。"]'),
('c9677b30-98f8-4a04-97aa-d3be37dfe6f2','寄趙檢法','釋元肇','宋','宋诗','song-poetry','','[]','津頭梅白柳青青，却憶春時送別情。',64,'全唐诗/poet.song.203000.json','["津頭梅白柳青青，却憶春時送別情。", "紙上有懷難盡寫，夢中相見不分明。", "清臺婉畫從輕典，紫禁催班識重名。", "幾欲寄君無好句，夕陽秋色滿江城。"]'),
('0988a5f8-7a71-4fcd-ac4f-013cb81c4df0','和趙寺丞中秋韻','釋元肇','宋','宋诗','song-poetry','','[]','太守能詩趙倚樓，良宵開宴領清秋。',64,'全唐诗/poet.song.203000.json','["太守能詩趙倚樓，良宵開宴領清秋。", "挂簷玉鑑明如洗，劃漢銀河近欲流。", "雅興自來輕庾亮，頌聲翕爾變營丘。", "關河萬里須長嘯，莫問膏腴在橘洲。"]'),
('37634546-e5b7-4834-a7e1-581f4714b79b','春雪','釋元肇','宋','宋诗','song-poetry','','[]','竹邊聲細夜方闌，開盡南窗獨自看。',64,'全唐诗/poet.song.203000.json','["竹邊聲細夜方闌，開盡南窗獨自看。", "桃杏學梅唯欠瘦，池塘堆絮怪能寒。", "纖纖尚舞東風力，片片還隨曉氣乾。", "芳草已滋三徑綠，誰知陋巷有袁安。"]'),
('9ca30a31-65f7-45ee-8c3a-db971bf52d1f','喝石巖','釋元肇','宋','宋诗','song-poetry','','[]','皓首來迎宴坐師，山靈易地致俱胝。',64,'全唐诗/poet.song.203000.json','["皓首來迎宴坐師，山靈易地致俱胝。", "要知弘法回天力，但看精誠裂石時。", "一徑蘚苔春寂寞，斷崖文字雨淋漓。", "徘徊想像登雲處，風撼松杉萬壑悲。"]'),
('f83479f5-12f2-42c5-b62c-226d78277ec3','菖蒲田','釋元肇','宋','宋诗','song-poetry','','[]','一從神武挂冠纓，便入千峰適性情。',64,'全唐诗/poet.song.203000.json','["一從神武挂冠纓，便入千峰適性情。", "已向耆英逃姓字，肯因楊柳作歌行。", "石田水冷菖蒲節，茅屋雲深薜荔榮。", "白髮山僧知此意，時時來聽野泉聲。"]'),
('c013816b-4f11-47ec-ac97-32039053cbf6','樹王','釋元肇','宋','宋诗','song-poetry','','[]','翠絲縝密赤心存，膚腠凌風溜雨皴。',64,'全唐诗/poet.song.203000.json','["翠絲縝密赤心存，膚腠凌風溜雨皴。", "直節向時曾遇上，微荄率土莫非臣。", "輪囷古柏空生蜀，偃蹇寒松枉仕秦。", "瀑布青山堪带礪，森森同見萬年春。"]'),
('20dd60a8-73d4-4f5c-a96e-17fb164f2fee','與印學正','釋元肇','宋','宋诗','song-poetry','','[]','郢手由來善運斤，楚天空闊鶚書頻。',64,'全唐诗/poet.song.203000.json','["郢手由來善運斤，楚天空闊鶚書頻。", "蛟龍豈是池中物，蟣虱聊爲地上臣。", "細雨斜風潜入夜，岸花汀草已知春。", "君如不負虛前席，治體當言寢積薪。"]'),
('760a65fe-72c4-4be9-b0b1-89fd79e2d34f','上浙翁','釋元肇','宋','宋诗','song-poetry','','[]','凌霄峰頂極高寒，中有高人把釣竿。',64,'全唐诗/poet.song.203000.json','["凌霄峰頂極高寒，中有高人把釣竿。", "萬里江湖未歸客，滿天風雪獨凭闌。", "醫和世遇肱三折，慈氏門開指一彈。", "管領梅花春有意，免教回首望長安。"]'),
('bb41759a-6baa-4b24-9778-c11d2ccd874e','見北磵','釋元肇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','橘洲骨冷不容呼，正始遺音掃地無。',64,'全唐诗/poet.song.203000.json','["橘洲骨冷不容呼，正始遺音掃地無。", "一代風流今北磵，十年妙語得西湖。", "人皆去獻遼東豕，我亦來觀屋上烏。", "春盡閉門無恙不，楊花飛作雪模糊。"]'),
('7f00dc4f-204e-4808-99b7-31a174d7975f','寄江西益侍者','釋元肇','宋','宋诗','song-poetry','','[]','狼伍峯前一御風，十年消息莫相通。',64,'全唐诗/poet.song.203000.json','["狼伍峯前一御風，十年消息莫相通。", "山從入望何曾極，水若知愁不向東。", "芳草天迷雲夢澤，垂楊煙暝舘娃宮。", "聞君已作包桑計，可念餘生尚轉蓬。"]'),
('492251fc-8d29-4598-9c0e-a43861e1d646','吳江','釋元肇','宋','宋诗','song-poetry','','[]','不到松江又一年，且於佳處小留連。',64,'全唐诗/poet.song.203000.json','["不到松江又一年，且於佳處小留連。", "千尋彩影虹垂地，萬頃清寒玉浸天。", "塘路罕逢騎馬客，人家少似釣魚船。", "三高冷眼應相笑，送往迎來亦可憐。"]'),
('4e5797f3-4556-4d96-975b-11624456aaff','次趙蓴湖飽看風雨樓韻','釋元肇','宋','宋诗','song-poetry','','[]','江山高處據胡床，豪氣如虹貫野塘。',64,'全唐诗/poet.song.203000.json','["江山高處據胡床，豪氣如虹貫野塘。", "且去已知元亮醉，興來非是次公狂。", "滿天風雨供吟眺，一幅瀟湘不卷藏。", "聽得鷄鳴還待旦，蓴羹雖美在他鄉。"]'),
('68fc1fe8-0afb-40e1-9cdd-0fad31c4c14b','次方蕙巖行春韻','釋元肇','宋','宋诗','song-poetry','','[]','及時槃樂足幽閑，近自丘園遠到關。',64,'全唐诗/poet.song.203000.json','["及時槃樂足幽閑，近自丘園遠到關。", "見綵桃符知歲換，带黄楊柳覺春還。", "飄飄衣袂風雩轉，草草杯行笑語間。", "高興磊然降不下，更須相約過西山。"]'),
('4826152f-fc53-4008-aa03-1c558a19d202','寄江陰史君尹梅津','釋元肇','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','清簡何曾五馬榮，時艱念慮在生靈。',64,'全唐诗/poet.song.203000.json','["清簡何曾五馬榮，時艱念慮在生靈。", "江如謝脁詩中靜，山似岳陽樓上青。", "戢戢魚頭曝冬日，翩翩鴉字出宸庭。", "三吳父老遥相祝，幾向天邊望福星。"]'),
('a0af8ef7-7fb1-4256-b0ae-88cf6ebc7001','寄池陽許史君','釋元肇','宋','宋诗','song-poetry','','[]','紫塞將軍有重名，雄藩正管翠微亭。',64,'全唐诗/poet.song.203000.json','["紫塞將軍有重名，雄藩正管翠微亭。", "西來江水依前碧，北面淮山似舊青。", "因報平安逢驛使，懸知臨照老人星。", "寄言文選樓中主，莫道湯休語不靈。"]'),
('55a3e406-278c-4578-a41f-a87278b5c0d1','狼山','釋元肇','宋','宋诗','song-poetry','','[]','仙子飛昇歲月閒，游人猶向此躋攀。',64,'全唐诗/poet.song.203000.json','["仙子飛昇歲月閒，游人猶向此躋攀。", "五峯寺踞葱蘢處，孤塔雲撐杳靄間。", "波渺渺邊來漢水，望青青際是吳山。", "風帆沙鳥無今古，潮落潮生自往還。"]'),
('14022f20-6a12-45ba-9519-0a9131d72756','寄題釣臺','釋元肇','宋','宋诗','song-poetry','','[]','漢代高人曾釣此，至今山水有清輝。',64,'全唐诗/poet.song.203000.json','["漢代高人曾釣此，至今山水有清輝。", "多年祠像真還不，舊日臺磯是也非。", "尚想扁舟成獨往，問他明月幾時歸。", "雙雙鷗鷺應相識，飛落前灘更不飛。"]'),
('fbcd9642-b43a-4748-8fef-00b46392ffbc','送周伯弜帳管','釋元肇','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','不見山楹喜見君，才名端不愧芳塵。',64,'全唐诗/poet.song.203000.json','["不見山楹喜見君，才名端不愧芳塵。", "青雲自古遲佳士，白髮如今尚選人。", "鸚鵡洲邊文寂寞，滕王閣上句清新。", "相逢無語又相別，紅葉殘陽野水濱。"]'),
('37494e16-a862-44df-b97b-4b0bf74c0597','送方常簿赴召','釋元肇','宋','宋诗','song-poetry','','[]','門徑森陰带草堂，脩篁摇翠間垂楊。',64,'全唐诗/poet.song.203000.json','["門徑森陰带草堂，脩篁摇翠間垂楊。", "不知夢到三竿日，又拜除音一炷香。", "池上游魚覓清影，天邊儀鳳集朝陽。", "袖中大有安時策，長樂鐘聲夜未央。"]'),
('7640d515-214a-47c4-9ef4-1f6162f83ac9','姑蘇臺放生','釋元肇','宋','宋诗','song-poetry','','[]','高臺一上一消魂，觸目猶多古跡存。',64,'全唐诗/poet.song.203000.json','["高臺一上一消魂，觸目猶多古跡存。", "谿水流來聞越號，舟人指點是胥門。", "煙雲弄曉青山澹，城郭初晴碧瓦昏。", "魚躍鳶飛歸至化，當時歌舞不須論。"]'),
('31ed8001-d0d3-415d-be7b-56273d97498e','牡丹','釋元肇','宋','宋诗','song-poetry','','[]','嬌紅膩紫炫晴芳，好本傳來自洛陽。',64,'全唐诗/poet.song.203000.json','["嬌紅膩紫炫晴芳，好本傳來自洛陽。", "譜上有方曾換骨，花中無比合稱王。", "道妝宜貯黄金屋，素艷堪居白玉堂。", "羅幕重重護風日，幾家歌管惜春光。"]'),
('b4382e98-0b01-42c6-aa2e-9e03a1ce18f1','送朔齋右司赴宣城','釋元肇','宋','宋诗','song-poetry','','[]','鴛鷺胡爲久未歸，江東民瘦要公肥。',64,'全唐诗/poet.song.203000.json','["鴛鷺胡爲久未歸，江東民瘦要公肥。", "詔飜雲露宮鴉濕，帆起秋風畫鷁飛。", "把酒敬亭呼李白，高吟靜練壓玄暉。", "不須舉手遮西日，花待劉郎對紫微。"]'),
('70bf8609-683c-4af0-bdda-2bf1f02bb593','和魏侍郎登虎丘','釋元肇','宋','宋诗','song-poetry','','[]','朱輪千騎出行秋，覽勝須登海湧丘。',64,'全唐诗/poet.song.203000.json','["朱輪千騎出行秋，覽勝須登海湧丘。", "水與天光遠相接，雲遮山色半如羞。", "先賢祠下修時敬，古劍池邊記昔游。", "醉墨淋浪足酬唱，歸來鼓角動城頭。"]'),
('2cd2f127-d8f1-40d8-8428-8e2fe69c3f5b','天台道中','釋元肇','宋','宋诗','song-poetry','','[]','台嶺岧嶢道路長，周遭無數接青蒼。',64,'全唐诗/poet.song.203000.json','["台嶺岧嶢道路長，周遭無數接青蒼。", "溪頭枯樹如人立，峯頂孤松似傘張。", "片片開田種階級，家家壘石作門牆。", "籃輿摇兀東風裏，却憶西州上野航。"]'),
('e0e877a4-99da-4aa8-a6bb-bab61f5b075f','萬年開新塘','釋元肇','宋','宋诗','song-poetry','','[]','八峯聚首最幽奇，驅石攔雲貯碧池。',64,'全唐诗/poet.song.203000.json','["八峯聚首最幽奇，驅石攔雲貯碧池。", "倒擁旌幢千影樹，平沈星象一枰碁。", "爭鳴已被蛙先覺，歸宿多應鷺未知。", "肝膽到來都照了，何須更待入門時。"]'),
('746a2754-519b-4c42-b4cf-1b824018eb30','巾山','釋元肇','宋','宋诗','song-poetry','','[]','一登峯頂思悠然，始覺城臨滄海邊。',64,'全唐诗/poet.song.203000.json','["一登峯頂思悠然，始覺城臨滄海邊。", "水趁半江流缺月，塔將雙筆寫青天。", "茫茫帆影隨潮遠，杳杳鐘聲带郭圓。", "可是任蕃來宿後，獨留詩句到今傳。"]'),
('23f5eb3f-f829-402d-85a1-e6cfc301749c','西渡','釋元肇','宋','宋诗','song-poetry','','[]','復渡錢塘又六年，山川風物只依然。',64,'全唐诗/poet.song.203000.json','["復渡錢塘又六年，山川風物只依然。", "海潮有信看人老，江月無情却自圓。", "滿櫂白蘋催去國，五更朱旆喝朝天。", "獨憐皓首江湖上，不立沙鷗一點煙。"]'),
('a4790c91-86c1-48f4-b5cc-83bfce8ea3cb','霜夜有感','釋元肇','宋','宋诗','song-poetry','','[]','寒漏時聞一兩聲，夜窗危坐對孤檠。',64,'全唐诗/poet.song.203000.json','["寒漏時聞一兩聲，夜窗危坐對孤檠。", "半千里外無家客，十五年前舊月明。", "世事蕭蕭黄葉下，交情汩汩白鷗驚。", "市人應笑疎狂甚，莫怪龐公不入城。"]'),
('38bbd328-caab-42a9-8416-e73fb2514c07','揚州','釋元肇','宋','宋诗','song-poetry','','[]','高陵爲谷曲池平，亭館多存舊日名。',64,'全唐诗/poet.song.203000.json','["高陵爲谷曲池平，亭館多存舊日名。", "風月豈關興廢事，江山不盡古今情。", "浪花飛雪雄新塹，楊柳垂雲護細營。", "欲識揚州奇絕處，廟前瓊樹尚敷榮。"]'),
('827a4ca2-297e-4d88-9c1a-71a3eb62553e','秀野園','釋元肇','宋','宋诗','song-poetry','','[]','洛陽園圃久荒烟，秀野佳名向此傳。',64,'全唐诗/poet.song.203000.json','["洛陽園圃久荒烟，秀野佳名向此傳。", "雲外移山高出屋，門前遠水靜兼天。", "四時爭發花無數，五畝中分竹半邊。", "不用笙歌與銀燭，夜深漁唱月娟娟。"]'),
('cbb759a1-c5c1-4e5b-ad26-f0ba5740c36e','和上官右史韻','釋元肇','宋','宋诗','song-poetry','','[]','雖然身世兩相違，不以無爲礙有爲。',64,'全唐诗/poet.song.203000.json','["雖然身世兩相違，不以無爲礙有爲。", "偶被閑名難免俗，因將黄葉强題詩。", "一年好是中秋節，萬事能如采菊時。", "自古聖賢觀出處，只今誰解帝王師。"]'),
('0f0f8392-76fe-4193-814d-182f414d83a5','歸舊隠','釋元肇','宋','宋诗','song-poetry','','[]','六載城塵閙壓頭，一朝脫屣返林丘。',64,'全唐诗/poet.song.203000.json','["六載城塵閙壓頭，一朝脫屣返林丘。", "青山不遠迎人笑，綠水依前遶郭流。", "隨意野花開欲遍，盡情幽鳥語相留。", "門前若有敲門客，多謝山陰王子猷。"]'),
('34c0b0d9-69e0-4e5a-99fd-eb2f9df39f92','暮春','釋元肇','宋','宋诗','song-poetry','','[]','顧我疎慵事事休，三間茅屋碧溪頭。',64,'全唐诗/poet.song.203000.json','["顧我疎慵事事休，三間茅屋碧溪頭。", "喜添新竹當門礙，踏破蒼苔怕客游。", "菜葉不教隨水去，松花應待及時收。", "有時乘興登臯望，上水舟衝下水舟。"]'),
('02cacfca-b063-4718-b15c-297893a2d84f','送正西堂','釋元肇','宋','宋诗','song-poetry','','[]','弟兄相見竟何如，一見尤勝寄百書。',64,'全唐诗/poet.song.203000.json','["弟兄相見竟何如，一見尤勝寄百書。", "况是青春三月莫，相看白首七旬餘。", "勞生衮衮誰休息，世事悠悠我定居。", "索去自言生處樂，乾坤等是一蘧廬。"]'),
('ab624a1e-31b5-44f9-84d0-5f4c3f790dda','寄鄂渚印知府','釋元肇','宋','宋诗','song-poetry','','[]','黄鶴樓前鸚鵡洲，高持麾節去悠悠。',64,'全唐诗/poet.song.203000.json','["黄鶴樓前鸚鵡洲，高持麾節去悠悠。", "功名自古無雙地，人物當今第一流。", "句裏可逢崔顥者，樽前還得禰生不。", "思君日夜廑西望，欲買潯陽江上舟。"]'),
('b47e2f23-d75a-4e36-bac0-f003b43cc5ad','洞庭用白樂天韻  其一','釋元肇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','兩丸跳擲幾昇沉，誰識僊源洞府深。',64,'全唐诗/poet.song.203000.json','["兩丸跳擲幾昇沉，誰識僊源洞府深。", "月在波間明片玉，舟從水口出橫金。", "夫差醉後無吳舞，范蠡來時有越吟。", "千古烟波興廢事，白鷗漁叟是知心。"]'),
('0e644dec-0ced-405e-8716-10dea335934b','洞庭用白樂天韻  其二','釋元肇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西緲東峨日未沉，洞庭山水更幽深。',64,'全唐诗/poet.song.203000.json','["西緲東峨日未沉，洞庭山水更幽深。", "微茫雪浪疑浮玉，杳靄煙霞似紫金。", "壇上綠毛遺竈冷，橘中皓首采芝吟。", "桃花洞口年年發，自是尋人不盡心。"]'),
('2e18d472-6747-4220-875b-f73d44baeb92','丁巳生朝','釋元肇','宋','宋诗','song-poetry','','[]','露白風清八月時，晨光初度透熹微。',64,'全唐诗/poet.song.203000.json','["露白風清八月時，晨光初度透熹微。", "更添來歲一分健，便是浮生七十稀。", "識得榮枯皆是妄，了知出處未全非。", "旁人不用相薰祝，自有天香桂子飛。"]'),
('8a5b6509-1c92-43d6-b5cb-76c0497727a8','寄馮深居','釋元肇','宋','宋诗','song-poetry','','[]','人世還如客路同，可堪垂老尚飄蓬。',64,'全唐诗/poet.song.203000.json','["人世還如客路同，可堪垂老尚飄蓬。", "舊年兩向吳中見，今日相思白下東。", "烏鵲橋邊望明月，鳳凰臺上詠秋風。", "滿題紅葉隨流去，惆悵才高命不通。"]'),
('2e041359-eee1-4827-b401-8c5bc9ae3720','董丞相去國','釋元肇','宋','宋诗','song-poetry','','[]','寶祐丙辰七月前，相公力請得歸田。',64,'全唐诗/poet.song.203000.json','["寶祐丙辰七月前，相公力請得歸田。", "聖朝已致無爲治，天下今逢大有年。", "諸葛終身出師表，留侯底事學神僊。", "何人得似鴟夷子，萬頃烟波一釣舡。"]'),
('4f72ccd1-cf38-4fa1-89c6-e1245ace34a8','挽高鼓院','釋元肇','宋','宋诗','song-poetry','','[]','葉墮遥空萬景沈，致芻誰不重傷心。',64,'全唐诗/poet.song.203000.json','["葉墮遥空萬景沈，致芻誰不重傷心。", "仕當釣石歸來蚤，閑比香山樂更深。", "一片新碑難載德，百年故土絕遺音。", "定從兜率天中去，莫向桃源路上尋。"]'),
('6cd9f365-0410-4599-888a-8c109c0e9d0b','上官右史','釋元肇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','螭坳立後別明光，歲晚婆娑慶幸堂。',64,'全唐诗/poet.song.203000.json','["螭坳立後別明光，歲晚婆娑慶幸堂。", "鶴怨只能隨髮白，菊愁竟不上腰黄。", "西歸有地從先壟，北望長江是故鄉。", "枌下解空情已盡，西風吹泪濕斜陽。"]'),
('179205df-8e4a-48af-860e-428f32c663a6','陳府判','釋元肇','宋','宋诗','song-poetry','','[]','考亭真派落姑蘇，克己工夫到物初。',64,'全唐诗/poet.song.203000.json','["考亭真派落姑蘇，克己工夫到物初。", "文好祇教供草檄，命慳聊得坐題輿。", "循良殄瘁悲民社，儒道凋零泣里閭。", "素業可傳雙桂子，家留經訓是菑畬。"]'),
('c9722416-4b1b-4c91-b417-68b5b11a8660','陸主簿','釋元肇','宋','宋诗','song-poetry','','["\u592a\u6e56"]','洽人恩惠在鄉閭，石有璵璠水有珠。',64,'全唐诗/poet.song.203000.json','["洽人恩惠在鄉閭，石有璵璠水有珠。", "愛日欲烘陰枳棘，壽星悵望落姑蘇。", "池臺舊宅流滄海，丘壠新封近太湖。", "却憶渡江同到處，寒城渺渺夜啼烏。"]'),
('fcd0e301-7a3d-4282-b7a5-32ed23cec242','高輦院','釋元肇','宋','宋诗','song-poetry','','[]','人生七十古難過，賢德如公未足多。',64,'全唐诗/poet.song.203000.json','["人生七十古難過，賢德如公未足多。", "晚歲傷心非故土，東洲有泪是恩波。", "青松護壟雲成蓋，白玉遺箴世不磨。", "湖海舊游終踐約，夕陽來此挂烟蓑。"]'),
('5e1747b8-12bb-489c-a0d2-e9f7d3fa5225','陸教授致政','釋元肇','宋','宋诗','song-poetry','','[]','去秋哭子過蒸山，豈料今年逝不還。',64,'全唐诗/poet.song.203000.json','["去秋哭子過蒸山，豈料今年逝不還。", "自是廣文甘獨冷，卑從神武樂高閑。", "枌閭南望無回日，蓮土西歸覺夢間。", "同隊相看成白首，先將老泪爲君潸。"]'),
('e15e426b-8c65-4d32-8625-28f628eaa8d8','陳子翔殿元','釋元肇','宋','宋诗','song-poetry','','[]','少年飛鶚上秋空，二十四青楊柳風。',64,'全唐诗/poet.song.203000.json','["少年飛鶚上秋空，二十四青楊柳風。", "庭草未霑恩綬綠，種花空作狀元紅。", "三更共渡追前事，半世生涯似夢中。", "燕子歸來談寂寞，舊巢零落布洲東。"]'),
('9c178057-fd2a-4ed2-90f9-8b7724cc37f8','清月溪','釋元肇','宋','宋诗','song-poetry','','[]','萬劫高超一念輕，來非住相去何曾。',64,'全唐诗/poet.song.203000.json','["萬劫高超一念輕，來非住相去何曾。", "定逢葱嶺當年使，誰訪洪川舊日僧。", "舍利未安無縫塔，伽梨空對短檠燈。", "凌霄多少薰風淚，吹入淮南紫翠層。"]'),
('dbca9774-d43a-4d77-9902-c1ca06607b4d','江上雪','釋元肇','宋','宋诗','song-poetry','','[]','人道甌閩不識寒，北風吹雪夜漫漫。',32,'全唐诗/poet.song.203000.json','["人道甌閩不識寒，北風吹雪夜漫漫。", "斷蓬折葦滄江上，只作淮南舊日看。"]'),
('3b7437c9-4d89-484e-b361-7289017b77c5','湖上秋日','釋元肇','宋','宋诗','song-poetry','','[]','湖上新晴人競游，幽懷無處領清秋。',32,'全唐诗/poet.song.203000.json','["湖上新晴人競游，幽懷無處領清秋。", "夕陽送盡歌船了，始放鐘聲出寺樓。"]'),
('f133e954-c0a0-461d-9ba0-ed93f716646f','秋蓮','釋元肇','宋','宋诗','song-poetry','','[]','波面盈盈照影紅，月寒露重怨房空。',32,'全唐诗/poet.song.203000.json','["波面盈盈照影紅，月寒露重怨房空。", "鷺鷥目趁魚行急，驚得殘粧散曉風。"]'),
('81e870e8-798f-40a4-b9de-dc85ec5dc2af','荷葉浦','釋元肇','宋','宋诗','song-poetry','','[]','苕花蓼穗細明川，荷蓋經風半欲眠。',32,'全唐诗/poet.song.203000.json','["苕花蓼穗細明川，荷蓋經風半欲眠。", "隔浦有人歌宛轉，日斜不見採蓮船。"]'),
('024fd04f-f1e3-410b-bb81-4e157283b0e1','禁渡','釋元肇','宋','宋诗','song-poetry','','[]','渺渺煙江春思長，杏花風急燕歸忙。',32,'全唐诗/poet.song.203000.json','["渺渺煙江春思長，杏花風急燕歸忙。", "銜泥不解如精衛，又只來巢舊屋梁。"]'),
('d9270da0-aca4-494a-8b05-03ce6c808406','絡緯','釋元肇','宋','宋诗','song-poetry','','[]','沙塞風高纊帛輕，春蠶到死只吞聲。',32,'全唐诗/poet.song.203000.json','["沙塞風高纊帛輕，春蠶到死只吞聲。", "寒機未織回文字，夜夜籬邊訴月明。"]'),
('ebf92b3a-7766-4e00-bb69-e9cece5fba8e','起夫','釋元肇','宋','宋诗','song-poetry','','[]','木葉初飛夫去時，家家連夜辦征衣。',32,'全唐诗/poet.song.203000.json','["木葉初飛夫去時，家家連夜辦征衣。", "關河只在淮南北，未著寒衣可得歸。"]'),
('3632ea63-429f-4efb-98d3-87c96ecc5dbc','賣菊','釋元肇','宋','宋诗','song-poetry','','[]','故國風煙幾換秋，今年看菊御街頭。',32,'全唐诗/poet.song.203000.json','["故國風煙幾換秋，今年看菊御街頭。", "長安市上人無數，只買秋光不買愁。"]'),
('2f1dbc45-7451-447d-9e60-4dfa78a06022','寄歸','釋元肇','宋','宋诗','song-poetry','','[]','燕子辭巢始別家，杜鵑啼處在天涯。',32,'全唐诗/poet.song.203000.json','["燕子辭巢始別家，杜鵑啼處在天涯。", "十分春事都看了，盡是他人園裏花。"]'),
('835bc381-70c2-4e97-99ef-d8426adf489c','贈日者','釋元肇','宋','宋诗','song-poetry','','[]','君推造化最幽玄，白屋曾經定狀元。',32,'全唐诗/poet.song.203000.json','["君推造化最幽玄，白屋曾經定狀元。", "休向深雲問消息，春風只在杏花園。"]'),
('187d683c-e4b9-4406-9036-28e35a2aed5a','送人','釋元肇','宋','宋诗','song-poetry','','[]','春盡江南二月時，盈盈陌上燕差池。',32,'全唐诗/poet.song.203000.json','["春盡江南二月時，盈盈陌上燕差池。", "遊絲日暖垂千尺，不爲行人繫別離。"]'),
('516369bd-a7c0-4a60-a5c4-187a6abcd978','送僧還里','釋元肇','宋','宋诗','song-poetry','','[]','送君重疊上高臺，到得親庭却早來。',32,'全唐诗/poet.song.203000.json','["送君重疊上高臺，到得親庭却早來。", "楊子江頭應看取，無情潮水亦西回。"]'),
('b7751e7d-7ff5-4355-bd6d-a6ffa54a2f25','送僧歸淮西二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','高堂無地寄征衣，淮水西邊近解圍。',32,'全唐诗/poet.song.203000.json','["高堂無地寄征衣，淮水西邊近解圍。", "想得夜闌更秉燭，天寒木落一僧歸。"]'),
('36bf5d06-1c19-47d0-8439-8e2befd5a2d3','送僧歸淮西二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','滿目鄉心怕著秋，東州見了又西州。',32,'全唐诗/poet.song.203000.json','["滿目鄉心怕著秋，東州見了又西州。", "明年莫看中秋月，曾是當時照別愁。"]'),
('21e0cc18-7e2c-41a5-9ba4-d9329896fbc0','北堂寄布','釋元肇','宋','宋诗','song-poetry','','[]','消息雖真見若何，愁中日月手中梭。',32,'全唐诗/poet.song.203000.json','["消息雖真見若何，愁中日月手中梭。", "莫言不寫平安信，布眼爭如望眼多。"]'),
('1cb422cd-83b4-4320-9fbc-ac77fd1f98cb','同游歸故隠','釋元肇','宋','宋诗','song-poetry','','[]','庭前杏樹手親栽，曾見空花兩度開。',32,'全唐诗/poet.song.203000.json','["庭前杏樹手親栽，曾見空花兩度開。", "聞道濛濛煙雨裏，亂禽爭子落莓苔。"]'),
('b87202f3-23bd-446e-98b5-6ea72a216534','送僧游岳','釋元肇','宋','宋诗','song-poetry','','[]','上人年少易拋鄉，湖海茫茫道路長。',32,'全唐诗/poet.song.203000.json','["上人年少易拋鄉，湖海茫茫道路長。", "憑內州軍莫游盡，鴈飛不肯過衡陽。"]'),
('3618faab-d3a7-42cf-b825-57fc812d1b20','宿鳳山寄楓橋詮無言','釋元肇','宋','宋诗','song-poetry','','[]','澤國春深綠暗天，來時已不見君船。',32,'全唐诗/poet.song.203000.json','["澤國春深綠暗天，來時已不見君船。", "十年湖海飄零恨，一夜空山聽杜鵑。"]'),
('cef224b6-af1b-4b91-8aa5-53fd70efbb1a','石湖晚泊','釋元肇','宋','宋诗','song-poetry','','[]','磨子峰頭日已傾，楞伽塔頂月初生。',32,'全唐诗/poet.song.203000.json','["磨子峰頭日已傾，楞伽塔頂月初生。", "鴟夷去後烟波冷，悵望吳臺與越城。"]'),
('842ce62f-1241-4f70-b854-7c03dd94e65f','西園晚春','釋元肇','宋','宋诗','song-poetry','','[]','水影煙光上客衣，樓前燕子自由飛。',32,'全唐诗/poet.song.203000.json','["水影煙光上客衣，樓前燕子自由飛。", "鞦韆春去無人管，相伴垂楊舞落暉。"]'),
('ce99ec0b-4007-427c-9449-1a9dd03b0b13','謝史春坊遠招','釋元肇','宋','宋诗','song-poetry','','[]','支林煙雨舊池臺，麾節將春今幾回。',32,'全唐诗/poet.song.203000.json','["支林煙雨舊池臺，麾節將春今幾回。", "湖上梅花方做夢，樓頭畫角又相催。"]'),
('56a76858-26f3-43ec-8878-38b3c4ebcb82','徐神公墓','釋元肇','宋','宋诗','song-poetry','','[]','出郭門東宿靄披，僊公靈跡尚堪追。',32,'全唐诗/poet.song.203000.json','["出郭門東宿靄披，僊公靈跡尚堪追。", "空林日日傳清響，敝帚年年付與誰。"]'),
('8fcbacba-e922-4f87-9f8a-b96fb2232df0','送客','釋元肇','宋','宋诗','song-poetry','','[]','遲遲送客過前溪，脫木風高日易低。',32,'全唐诗/poet.song.203000.json','["遲遲送客過前溪，脫木風高日易低。", "寂寞歸來理殘菊，野禽啼在竹籬西。"]'),
('f05b889e-a193-4a46-8a2f-caa05eb686b2','寒食','釋元肇','宋','宋诗','song-poetry','','[]','荒塚無人捧土修，夕陽芳草替生愁。',32,'全唐诗/poet.song.203000.json','["荒塚無人捧土修，夕陽芳草替生愁。", "路傍知是誰家子，猶把花枝插滿頭。"]'),
('d8100d0f-1d5d-4829-a0a7-c59429ef2da2','江路午行','釋元肇','宋','宋诗','song-poetry','','[]','誰家吠犬出低籬，橋在村西人未知。',32,'全唐诗/poet.song.203000.json','["誰家吠犬出低籬，橋在村西人未知。", "白鳥自來還自去，柳陰濃處立多時。"]'),
('c4b37a4b-f95a-445d-90d2-12d93903d518','歸涂雪','釋元肇','宋','宋诗','song-poetry','','[]','蹇馿騎破野村前，愛惜飛花懶著鞭。',32,'全唐诗/poet.song.203000.json','["蹇馿騎破野村前，愛惜飛花懶著鞭。", "到得歸來山舍晚，竹籬遥認煮茶煙。"]'),
('c8011df0-75d4-4ceb-9f5f-460611b16025','秋霽','釋元肇','宋','宋诗','song-poetry','','[]','一室蟲悲萬感生，林梢攧雨濕秋聲。',32,'全唐诗/poet.song.203000.json','["一室蟲悲萬感生，林梢攧雨濕秋聲。", "詩成後夜無人問，月到雲間不肯明。"]'),
('ddbc8ef9-d90f-435e-8682-7d2562208566','送僧歸武昌','釋元肇','宋','宋诗','song-poetry','','[]','赤壁西邊舊武昌，吳波蜀浪幾興亡。',32,'全唐诗/poet.song.203000.json','["赤壁西邊舊武昌，吳波蜀浪幾興亡。", "歸來黄鶴樓前看，半是寒濤半夕陽。"]'),
('a35a3c74-6a2c-4f8d-ba23-719cb0c5611b','曉過吳江','釋元肇','宋','宋诗','song-poetry','','[]','雨洗雲梳曉色遲，空江楓冷一虹垂。',32,'全唐诗/poet.song.203000.json','["雨洗雲梳曉色遲，空江楓冷一虹垂。", "漁人偷釣煙波破，鷗鷺沙頭睡不知。"]'),
('d7747c2e-1c9a-42e2-b27e-8ea3cdfc5605','渡江','釋元肇','宋','宋诗','song-poetry','','[]','天地無情日夜流，樹煙濃澹岸沈浮。',32,'全唐诗/poet.song.203000.json','["天地無情日夜流，樹煙濃澹岸沈浮。", "浪花倏忽千堆雪，白似江南去客頭。"]'),
('8e536b84-5119-4255-a903-3d86965cc568','別菊','釋元肇','宋','宋诗','song-poetry','','[]','世情遷變總由他，冷眼相看只此花。',32,'全唐诗/poet.song.203000.json','["世情遷變總由他，冷眼相看只此花。", "露葉霜枝愁不語，主人明日又天涯。"]'),
('753f3bb0-dc99-4a3f-9310-9f7ce35c149e','題飲仙圖','釋元肇','宋','宋诗','song-poetry','','[]','蹇馿破帽少陵寒，吐出歌辭字字酸。',32,'全唐诗/poet.song.203000.json','["蹇馿破帽少陵寒，吐出歌辭字字酸。", "渭水驪山腸斷日，諸公肯待醒時看。"]'),
