('14057a35-0bee-4ef0-a604-6671f0729cac','送人','釋元肇','宋','宋诗','song-poetry','','[]','疎雨梧桐滴滴秋，涼吹別袂上歸舟。',32,'全唐诗/poet.song.203000.json','["疎雨梧桐滴滴秋，涼吹別袂上歸舟。", "釜山青立蒼茫外，潮落潮生一點愁。"]'),
('356505e3-e111-4589-9824-eb548e970f21','送月上人之東州','釋元肇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭波上木蘭舟，只解年年載客愁。',32,'全唐诗/poet.song.203000.json','["洞庭波上木蘭舟，只解年年載客愁。", "月到甬東天似水，釣絲全力重金鈎。"]'),
('4f13443d-8e79-4561-b9f6-aca1e93b5a7c','送祖書記之武昌','釋元肇','宋','宋诗','song-poetry','','[]','黄鶴樓前舊月明，吳王臺上莫秋聲。',32,'全唐诗/poet.song.203000.json','["黄鶴樓前舊月明，吳王臺上莫秋聲。", "離情只在斜陽裏，斷柳荒煙寫不成。"]'),
('31a466d6-80bd-403a-853a-b3944ab3fce5','華夷圖','釋元肇','宋','宋诗','song-poetry','','[]','禹迹茫茫宇宙寬，等閒移向壁間安。',32,'全唐诗/poet.song.203000.json','["禹迹茫茫宇宙寬，等閒移向壁間安。", "從頭指點須開展，莫只東南角上看。"]'),
('98fdda32-80b0-41b1-adaa-15cf31800959','池梅','釋元肇','宋','宋诗','song-poetry','','[]','水浄方塘曉鏡清，依依冷照玉娉婷。',32,'全唐诗/poet.song.203000.json','["水浄方塘曉鏡清，依依冷照玉娉婷。", "昭君莫怨毛延壽，此意如何畫得成。"]'),
('f3d2eacc-fa86-446d-a0f2-c79ba8d45264','春意','釋元肇','宋','宋诗','song-poetry','','[]','山客偶來城裏住，頻年孤負惜芳心。',32,'全唐诗/poet.song.203000.json','["山客偶來城裏住，頻年孤負惜芳心。", "一株楊柳南池上，日日看春到淺深。"]'),
('b42c0c8c-2a3e-4466-95a8-951335bd9b30','哀通人俘虜二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','沙漠無春雪滿天，不知舊歲與新年。',32,'全唐诗/poet.song.203000.json','["沙漠無春雪滿天，不知舊歲與新年。", "如何化得身雙翼，飛向南方學杜鵑。"]'),
('eb5302a4-dde5-4eb0-bb5a-3ee725e5f5bc','哀通人俘虜二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','見鴈南飛欲寄音，裂衣刳血寫鄉心。',32,'全唐诗/poet.song.203000.json','["見鴈南飛欲寄音，裂衣刳血寫鄉心。", "書成剗地添惆悵，又恐無人射上林。"]'),
('26207e08-8942-49b8-81a3-e3d3d1199d40','酬杜北山','釋元肇','宋','宋诗','song-poetry','','[]','杜君世胄本蟬聯，流落南天不記年。',32,'全唐诗/poet.song.203000.json','["杜君世胄本蟬聯，流落南天不記年。", "買箇草堂湖上住，醉吟如在曲江邊。"]'),
('5b4114fb-b337-4b7f-9a14-083ff9095c43','初至建鄴','釋元肇','宋','宋诗','song-poetry','','[]','六朝陳迹認應難，只有春風燕子還。',32,'全唐诗/poet.song.203000.json','["六朝陳迹認應難，只有春風燕子還。", "陌上花開又花落，看人來往是鍾山。"]'),
('ba3e43a1-bb77-456c-8e93-6ce2a808b525','懷吳中','釋元肇','宋','宋诗','song-poetry','','[]','消息傳來竟不真，楊花落後更無春。',32,'全唐诗/poet.song.203000.json','["消息傳來竟不真，楊花落後更無春。", "誰知十載游吳夢，却作桑乾渡水人。"]'),
('d7c733d8-3fd5-420d-99cd-77171c81209d','行宮詞','釋元肇','宋','宋诗','song-poetry','','[]','一片紅雲擁不開，天津橋上久徘徊。',32,'全唐诗/poet.song.203000.json','["一片紅雲擁不開，天津橋上久徘徊。", "當時未了中興業，應待君王法駕來。"]'),
('b6ae1966-81b4-45f8-aba1-8b3185502c71','晉元帝廟','釋元肇','宋','宋诗','song-poetry','','[]','元帝遺宮在石頭，年年長吏祀春秋。',32,'全唐诗/poet.song.203000.json','["元帝遺宮在石頭，年年長吏祀春秋。", "幾多整頓乾坤手，閒遶回廊看不休。"]'),
('ae6a14b5-4378-46f4-8ce6-fcde72e7786e','王荆公半山祠','釋元肇','宋','宋诗','song-poetry','','[]','來往鍾山住半腰，騎馿松下莫蕭蕭。',32,'全唐诗/poet.song.203000.json','["來往鍾山住半腰，騎馿松下莫蕭蕭。", "只因墩號分人我，到了經綸恨不消。"]'),
('b3e12b78-c7df-4a75-b885-c839f993c1a7','桃紅菊','釋元肇','宋','宋诗','song-poetry','','[]','桃葉桃根逐水流，冷煙凉月幾番秋。',32,'全唐诗/poet.song.203000.json','["桃葉桃根逐水流，冷煙凉月幾番秋。", "籬邊强作春風面，滿地黄金不替愁。"]'),
('1df7aa0b-6c19-4915-848a-878397d2fa35','酬張槎溪','釋元肇','宋','宋诗','song-poetry','','[]','一笑相逢白下城，秋光滿路雨初晴。',32,'全唐诗/poet.song.203000.json','["一笑相逢白下城，秋光滿路雨初晴。", "滄江上與天河接，應是乘槎到玉清。"]'),
('7ebb6876-b200-4bfa-b7be-4710e1f637b7','用趙倅韻二首  其一','釋元肇','宋','宋诗','song-poetry','','[]','江山陳迹六朝遺，寂歷寒花野水湄。',32,'全唐诗/poet.song.203000.json','["江山陳迹六朝遺，寂歷寒花野水湄。", "猶有石頭城畔月，夜深還照昔人詩。"]'),
('2fa09f0c-eaf1-4721-920d-445b4f05658f','用趙倅韻二首  其二','釋元肇','宋','宋诗','song-poetry','','[]','憑高一望興何窮，晴雨朝昏景不同。',32,'全唐诗/poet.song.203000.json','["憑高一望興何窮，晴雨朝昏景不同。", "莫向吟邊苦懷古，敗荷疎柳怯西風。"]'),
('a2ecd155-5cb6-49f5-93e8-0d735548a1bf','寄題孤嶼琚師半雲','釋元肇','宋','宋诗','song-poetry','','[]','江上悠悠寄此身，一間茅屋半邊雲。',32,'全唐诗/poet.song.203000.json','["江上悠悠寄此身，一間茅屋半邊雲。", "長年相伴閑怡悅，去住無心不用分。"]'),
('2210a4b3-bcb4-4396-bcb3-a508caebf4fd','送黄宰之江陵','釋元肇','宋','宋诗','song-poetry','','[]','滑石橋寒玉萬尋，到君游日正春深。',32,'全唐诗/poet.song.203000.json','["滑石橋寒玉萬尋，到君游日正春深。", "詩人今擁油幢坐，曾聽孤猿月下吟。"]'),
('15369f84-6ea9-48ac-b11b-8271dd085f3a','寄歸','釋元肇','宋','宋诗','song-poetry','','[]','鴈過天南菊又開，故鄉拋了十年來。',32,'全唐诗/poet.song.203000.json','["鴈過天南菊又開，故鄉拋了十年來。", "可憐亂後皆無定，夢過寒江却自回。"]'),
('5bfe6fd8-5677-4f21-b49d-fbe9ef2a1e38','立虛舟游洞庭','釋元肇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','君向洞庭看秋色，軟琉璃地黄金國。',32,'全唐诗/poet.song.203000.json','["君向洞庭看秋色，軟琉璃地黄金國。", "興來題破曉霜天，七十二峯幾點墨。"]'),
('b65df80b-bfa0-457c-bdf9-f7c72b5a48c1','贈四明趙秀才','釋元肇','宋','宋诗','song-poetry','','[]','梅雪初消柳欲金，弄春天氣晝沈沈。',32,'全唐诗/poet.song.203000.json','["梅雪初消柳欲金，弄春天氣晝沈沈。", "當時東越西吳事，試上高臺爲一吟。"]'),
('c5cdb69c-3831-468b-82b6-7322c2243419','梅溪','釋元肇','宋','宋诗','song-poetry','','[]','三花兩蘂開枝上，淡月微雲動水邊。',32,'全唐诗/poet.song.203000.json','["三花兩蘂開枝上，淡月微雲動水邊。", "坐到夜深誰是伴，陽春雪曲和潺湲。"]'),
('0973ba60-24c5-4be6-a30b-d04f7b357cad','趙計議半雲','釋元肇','宋','宋诗','song-poetry','','[]','蒼蒼茫茫烟樹昏，靜是青山動是雲。',32,'全唐诗/poet.song.203000.json','["蒼蒼茫茫烟樹昏，靜是青山動是雲。", "待得從龍爲雨後，一間茅屋與平分。"]'),
('ffbe4c23-0dd7-4202-8982-1c78878d6a4c','憶馮宗諭','釋元肇','宋','宋诗','song-poetry','','[]','去歲無辜出帝鄉，石頭城下水雲長。',32,'全唐诗/poet.song.203000.json','["去歲無辜出帝鄉，石頭城下水雲長。", "鳳凰臺上多今古，李白題詩恐斷腸。"]'),
('486a0f30-0c48-4407-b8f3-27b68542ab8b','題遠景山水四首  其一','釋元肇','宋','宋诗','song-poetry','','[]','老樹風煙醉，危橋野水寒。',24,'全唐诗/poet.song.203000.json','["老樹風煙醉，危橋野水寒。", "玉流飛作綫，牽補斷雲殘。"]'),
('dd633963-0b7e-4ff0-b205-7b2b5176c540','題遠景山水四首  其二','釋元肇','宋','宋诗','song-poetry','','[]','剎景重遮壑，鐘聲出莫樓。',24,'全唐诗/poet.song.203000.json','["剎景重遮壑，鐘聲出莫樓。", "欲尋歸寺路，灘畔問漁舟。"]'),
('3f93ab3c-298e-4d80-b7ca-9b01bd57f9c6','題遠景山水四首  其三','釋元肇','宋','宋诗','song-poetry','','[]','繚白認飛流，千峰暗不收。',24,'全唐诗/poet.song.203000.json','["繚白認飛流，千峰暗不收。", "何人拄寒瘦，擔雨到溪頭。"]'),
('647a2b0c-b352-40be-a628-6a1cb42aca8e','題遠景山水四首  其四','釋元肇','宋','宋诗','song-poetry','','[]','山遠天高下，雲深樹有無。',24,'全唐诗/poet.song.203000.json','["山遠天高下，雲深樹有無。", "出關曾萬里，慣識曉行圖。"]'),
('ccd2320c-5320-4e95-bbb2-57f2471b3fb5','杜少陵像','釋元肇','宋','宋诗','song-poetry','','[]','許國丹心苦，唐天春日低。',24,'全唐诗/poet.song.203000.json','["許國丹心苦，唐天春日低。", "蹇馿應借得，吟過瀼溪西。"]'),
('c6380b21-e7c6-466a-bf5c-4a7fc3eaff42','賈浪仙像','釋元肇','宋','宋诗','song-poetry','','[]','撚鬚聳瘦肩，蹇步兀如顛。',24,'全唐诗/poet.song.203000.json','["撚鬚聳瘦肩，蹇步兀如顛。", "大尹不衝撞，清狂直上天。"]'),
('0713395b-41a9-4c62-a934-f1da9e52ade4','題江心寺','釋元肇','宋','宋诗','song-poetry','','[]','晏歲着脚來東甌，始覺坤軸東南浮。',240,'全唐诗/poet.song.203000.json','["晏歲着脚來東甌，始覺坤軸東南浮。", "百川同歸無異味，有如天子朝諸侯。", "何年飛落兩巨石，孤撐骯髒分江流。", "初疑鍊失女媧手，又恐鰲脫任公鈎。", "馮夷海若不敢有，湧出精舍中連洲。", "樓高百尺蜃吐氣，塔聳雙角龍昂頭。", "蒲牢撞撞鼉坎坎，潮聲衮衮風颼颼。", "妙高峯頂德雲住，海門山上焦公留。", "長淮在望鐵甕近，大浪不洗英雄愁。", "孰知隸古百粵地，今爲禮樂衣冠州。", "池塘春草年年綠，謝公勝事遺江樓。", "藍田無纇蟾駕夜，黄金作顆人家秋。", "客帆渺茫拂辰極，漁舠散漫同鳬鷗。", "麗天紅日記初浴，五雲扶上煙氛收。", "孤臣涕泗如此水，恨不從帝崆峒游。"]'),
('0c73b29a-79e2-4a11-9caf-a3b081f10447','次水心先生鴈山韻','釋元肇','宋','宋诗','song-poetry','','[]','方壺圓嶠神僊經，遠不可到虛其名。',160,'全唐诗/poet.song.203000.json','["方壺圓嶠神僊經，遠不可到虛其名。", "東嘉自古山水郡，往往俗駕回山靈。", "了知天地不終惜，鴈蕩殿出集大成。", "輞川無人王宰死，五日十日徒勞形。", "有生莫厭行犖确，四十九折重盤縈。", "珠璣亂撒龍鬭富，樓殿巧著僧爭清。", "巔崖咫尺分陰晴，幽壑噫欠生雷霆。", "新詩彈壓得二妙，厖眉雪頂交懽迎。", "煮茶夜坐發深省，古澗旋汲銅花青。", "老子於此興不淺，落紅千點春無情。"]'),
('8ef63e61-5e5a-4f53-9d1d-b3a7fabc938f','登狼山','釋元肇','宋','宋诗','song-poetry','','[]','江南見山猶可惜，千里萬里行不極。',112,'全唐诗/poet.song.203000.json','["江南見山猶可惜，千里萬里行不極。", "江北見山絕可憐，三峯兩峯謾堆積。", "平生未識蜀道難，頼此爲余雙眼碧。", "真人僊去狼不來，突兀與江相怒射。", "尋詩更上最高峰，莫嘆能消幾緉屐。", "水光山色只依然，顧我重來鬢非昔。", "笑歸丘壑橫胸臆，別倩東風吹脚力。"]'),
('ae8f091e-1cc9-40c9-914a-66a2c10bd430','和寧川王大卿寄游天台韻','釋元肇','宋','宋诗','song-poetry','','[]','我觀人生天地間，古今吁嗟行路難。',224,'全唐诗/poet.song.203000.json','["我觀人生天地間，古今吁嗟行路難。", "躋攀尺寸不可上，太行蜀道凋朱顔。", "天台勝絕神僊錄，遐方企仰傾心讀。", "跬步之間未暇登，多緣重耳而輕目。", "胸量汪汪滄海窄，筆端舊有回天力。", "莫年閑伴赤松游，興來不負東山屐。", "華頂萬八千丈高，衡南泰北齊堪招。", "凌風矯首欲飛舉，收拾萬象窮秋毫。", "方廣雲中忽披覿，半千聖者皆相識。", "妙法轟轟兩澗宣，危磴蜒蜒一潭碧。", "安得妙手李伯時，貌取牛背劉凝之。", "猗歟樗散巖壑底，與世聿兀略不覊。", "愛山只愁山可移，獨許明月清風知。", "興公按圖曾作賦，拂庵未到先題詩。"]'),
('564fa2f8-4a9d-42a5-81c9-8b4121fe34bb','詩一首','釋元肇','宋','宋诗','song-poetry','','[]','大夫去作棟梁材，無復清陰覆綠苔。',32,'全唐诗/poet.song.203000.json','["大夫去作棟梁材，無復清陰覆綠苔。", "惆悵月波亭上望，夜深惟見鶴歸來。"]'),
('a56f1af0-778b-49cf-89ea-76e13987c36e','惜松','釋元肇','宋','宋诗','song-poetry','','[]','不爲栽松種茯苓，祇緣山色四時青。',32,'全唐诗/poet.song.203000.json','["不爲栽松種茯苓，祇緣山色四時青。", "老僧只恐移松去，留與青山作畫屏。"]'),
('7b93d7c5-25bc-4248-9048-3c4cf3d007d5','讚達磨偈','釋元肇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','踏翻地軸與天關，合國人追不再還。',32,'全唐诗/poet.song.203000.json','["踏翻地軸與天關，合國人追不再還。", "去去一身輕似葉，長江千古浪如山。"]'),
('3025b7ce-a1ce-4f9f-a886-1b9612a31396','明堂慶成頌  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','穆穆聖皇，出震乘乾。',20,'全唐诗/poet.song.203000.json','["穆穆聖皇，出震乘乾。", "二十二載，如日中天。"]'),
('088ef640-7ce5-4c08-a5af-1a3d9181e370','明堂慶成頌  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','大祀有彝，親享凡七。',20,'全唐诗/poet.song.203000.json','["大祀有彝，親享凡七。", "嚴父配天，昉自今日。"]'),
('0a9d8152-79a0-4c88-b6da-df323c98f091','明堂慶成頌  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','遠稽前載，其在成周。',20,'全唐诗/poet.song.203000.json','["遠稽前載，其在成周。", "皇皇宗祀，奕奕垂休。"]'),
('dcd79570-9263-4451-bc61-0256678dc70c','明堂慶成頌  其四','徐鹿卿','宋','宋诗','song-poetry','','[]','近參家法，有若皇祐。',20,'全唐诗/poet.song.203000.json','["近參家法，有若皇祐。", "一祖二宗，於焉並侑。"]'),
('035b02c7-8c82-4d65-a68f-e8bd5faccfda','明堂慶成頌  其五','徐鹿卿','宋','宋诗','song-poetry','','[]','時維秋季，涓吉中辛。',20,'全唐诗/poet.song.203000.json','["時維秋季，涓吉中辛。", "本以忱敬，秩以儀文。"]'),
('9f3210a4-8b45-4393-ae56-d59e3bb3365e','明堂慶成頌  其六','徐鹿卿','宋','宋诗','song-poetry','','[]','皇在原廟，推迹本始。',20,'全唐诗/poet.song.203000.json','["皇在原廟，推迹本始。", "錫慶儲祥，仙源演迤。"]'),
('725415b9-921f-4cfd-9918-96fb6550683e','明堂慶成頌  其七','徐鹿卿','宋','宋诗','song-poetry','','[]','皇入太室，祼獻必躬。',20,'全唐诗/poet.song.203000.json','["皇入太室，祼獻必躬。", "列聖在天，時降于宗。"]'),
('007f2561-2978-4ee0-8c53-7951fdbc41a5','明堂慶成頌  其八','徐鹿卿','宋','宋诗','song-poetry','','[]','皇升玉輅，齋莊中御。',20,'全唐诗/poet.song.203000.json','["皇升玉輅，齋莊中御。", "一塵不驚，六飛如舞。"]'),
('a3fd29c4-83e4-47e5-ab01-a0e10ebd12d2','明堂慶成頌  其九','徐鹿卿','宋','宋诗','song-poetry','','[]','皇登陽館，幣玉交陳。',20,'全唐诗/poet.song.203000.json','["皇登陽館，幣玉交陳。", "伍位時序，徧于群神。"]'),
('637fbaee-75bf-481a-982d-f780b6f7f5d0','明堂慶成頌  其一○','徐鹿卿','宋','宋诗','song-poetry','','[]','相維辟公，耆俊布列。',20,'全唐诗/poet.song.203000.json','["相維辟公，耆俊布列。", "珩璜鏘鳴，籩豆豐潔。"]'),
('af60ca7a-3212-4c7c-9f96-c3b5c38d214a','明堂慶成頌  其一一','徐鹿卿','宋','宋诗','song-poetry','','[]','樂既具奏，佾舞工歌。',20,'全唐诗/poet.song.203000.json','["樂既具奏，佾舞工歌。", "八音克諧，兩間浹和。"]'),
('9949fdbf-e0e6-466c-bf1d-f4af45607142','明堂慶成頌  其一二','徐鹿卿','宋','宋诗','song-poetry','','[]','秋空無滓，萬里一碧。',20,'全唐诗/poet.song.203000.json','["秋空無滓，萬里一碧。", "璧月珠星，瑞光浮溢。"]'),
('5638d360-9c61-45e1-bee3-43147338ac4f','明堂慶成頌  其一三','徐鹿卿','宋','宋诗','song-poetry','','[]','曶焉低垂，非雲非煙。',20,'全唐诗/poet.song.203000.json','["曶焉低垂，非雲非煙。", "若降若接，郁郁紛紛。"]'),
('0ca5052e-498f-48ac-a1be-236d3bbf5531','明堂慶成頌  其一四','徐鹿卿','宋','宋诗','song-poetry','','[]','肸蠁潜通，受胙飲福。',20,'全唐诗/poet.song.203000.json','["肸蠁潜通，受胙飲福。", "移班紫宸，嵩呼三祝。"]'),
('86696407-64b7-4c3e-83a5-596292a307c3','明堂慶成頌  其一五','徐鹿卿','宋','宋诗','song-poetry','','[]','祭澤下流，肆眚端門。',20,'全唐诗/poet.song.203000.json','["祭澤下流，肆眚端門。", "雷雨既作，草木皆春。"]'),
('016bb379-39dc-41cd-a32e-00f9ee63db90','明堂慶成頌  其一六','徐鹿卿','宋','宋诗','song-poetry','','[]','人曰吾君，兼旬蔬食。',20,'全唐诗/poet.song.203000.json','["人曰吾君，兼旬蔬食。", "孰知陟降，常在帝側。"]'),
('c5dd9df3-ce4e-45af-b856-a1657055f4b9','明堂慶成頌  其一七','徐鹿卿','宋','宋诗','song-poetry','','[]','人曰吾君，精禱天章。',20,'全唐诗/poet.song.203000.json','["人曰吾君，精禱天章。", "孰知明德，日薦馨香。"]'),
('91129788-f967-44f6-ac69-6e91fc252f78','明堂慶成頌  其一八','徐鹿卿','宋','宋诗','song-poetry','','[]','凡皆可爲，天不容僞。',20,'全唐诗/poet.song.203000.json','["凡皆可爲，天不容僞。", "眡此休嘉，豈其力致。"]'),
('239244cf-ec12-4092-9067-9f30688e3da4','明堂慶成頌  其一九','徐鹿卿','宋','宋诗','song-poetry','','[]','一念之善，神人具懽。',20,'全唐诗/poet.song.203000.json','["一念之善，神人具懽。", "朝野傳夸，中外鎮安。"]'),
('6177d50c-551b-438c-9ee4-8652bb2538d0','明堂慶成頌  其二○','徐鹿卿','宋','宋诗','song-poetry','','[]','流民可綏，夷狄可滅。',20,'全唐诗/poet.song.203000.json','["流民可綏，夷狄可滅。", "天且弗違，人誰敢越。"]'),
('bb320f0b-1dde-4477-852a-4144c90a2d1c','明堂慶成頌  其二一','徐鹿卿','宋','宋诗','song-poetry','','[]','前星必耀，年穀必豐。',20,'全唐诗/poet.song.203000.json','["前星必耀，年穀必豐。", "人所同欲，天寧弗從。"]'),
('65d6f7b6-37df-4622-9742-96b13fa74de1','明堂慶成頌  其二二','徐鹿卿','宋','宋诗','song-poetry','','[]','侔德周成，儷美仁祖。',20,'全唐诗/poet.song.203000.json','["侔德周成，儷美仁祖。", "於萬斯年，受天之祜。"]'),
('1754f7d6-d2c9-43c6-b4a2-8eef4e3cd3d3','明堂慶成頌  其二三','徐鹿卿','宋','宋诗','song-poetry','','[]','若古有訓，明命難諶。',20,'全唐诗/poet.song.203000.json','["若古有訓，明命難諶。", "雖休勿休，惟單厥心。"]'),
('5d439d64-c814-4986-ba61-9bcc59b5c862','明堂慶成頌  其二四','徐鹿卿','宋','宋诗','song-poetry','','[]','我將不作，臣竊其義。',20,'全唐诗/poet.song.203000.json','["我將不作，臣竊其義。", "請誦末章，夙夜祇畏。"]'),
('c6b69e7e-75c6-490a-bd0b-d25a9bd62c97','明堂慶成詩','徐鹿卿','宋','宋诗','song-poetry','','[]','聖皇歷服萬斯年，今搆精禋第八番。',320,'全唐诗/poet.song.203000.json','["聖皇歷服萬斯年，今搆精禋第八番。", "配合二儀嚴太報，侑兼三后有常尊。", "純心實德期先盡，縟典彝儀匪謾繁。", "淳祐本因皇祐制，民心所欲聖心存。", "季秋肇卜中辛吉，旦氣深憂宿靄昏。", "罙月齋居忘肉味，寸丹靡日不天閽。", "閽臨原廟清風穆，既駕鑾輿曉日暾。", "明德馨香非黍稷，真機軒豁露乾坤。", "高空不夜天澄湛，大樂同和景晏溫。", "福祿穰穰綿帝錫，本支奕奕慶文孫。", "誕敷解澤傳鷄赦，環列臣工肅駿奔。", "河海晏清成鉅典，神祇安樂衍璿源。", "無前休美方揚厲，持敬工夫重討論。", "武帝中年惛內慾，明皇晚歲異開元。", "願將英斷充剛健，早正皇儲立本根。", "駿骨廣求來冀馬，烏巢不毀集庭鵷。", "長存鯁亮爲元氣，痛絕陰柔杜倖門。", "肅正紀綱强國勢，細分臂指鎮侯藩。", "微臣何幸逢熈事，奏雅終篇罄瞽言。", "執戟從官今老矣，華封祝壽報君恩。"]'),
('f732b747-004c-4ce8-a250-f74d5dc88c9e','湛泉送客二絕句  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','吾生如寄耳，嶺阯又三年。',24,'全唐诗/poet.song.203000.json','["吾生如寄耳，嶺阯又三年。", "政自歸心碎，那堪送客船。"]'),
('1307983f-b879-4c66-8a6f-23bad5af7d1c','湛泉送客二絕句  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','中年懷易惡，更聽斷腸聲。',24,'全唐诗/poet.song.203000.json','["中年懷易惡，更聽斷腸聲。", "多謝兩榕樹，逢人管送迎。"]'),
('80d9a639-5b54-4a5d-a119-68749bf6f17d','護法寺勸農呈秘丞','徐鹿卿','宋','宋诗','song-poetry','','[]','出郭囂塵遠，邵農德意宣。',48,'全唐诗/poet.song.203000.json','["出郭囂塵遠，邵農德意宣。", "旌旗清賞地，簑笠嫩晴天。", "犬吠柴門曉，牛肥草徑鮮。", "殷勤觴父老，和氣釀豐年。"]'),
('33094284-d3dd-4341-95bf-dd9dff1651bf','贈曾司戶','徐鹿卿','宋','宋诗','song-poetry','','[]','君家螺江頭，我家劍江邊。',60,'全唐诗/poet.song.203000.json','["君家螺江頭，我家劍江邊。", "千載會相望，飲水同一川。", "朅來古梅關，相識春風前。", "高義軋層漢，清譚響幽泉。", "努力效往哲，勿爲時俗牽。"]'),
('44e9ef69-5f47-4a81-b28e-fcf85cf8d455','詠蘭','徐鹿卿','宋','宋诗','song-poetry','','[]','叢蘭抱幽姿，結根託山壤。',72,'全唐诗/poet.song.203000.json','["叢蘭抱幽姿，結根託山壤。", "所據良孤高，其下俯深廣。", "雲氣接清潤，雨露從資養。", "雖然翳深林，未肯群衆莽。", "輪蹄紛紫陌，誰此事幽賞。", "幽賞縱不及，香風自來往。"]'),
('33ce6b83-a232-4713-9551-4636b7b708b8','酬正錄直學  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','我生愜幽尋，訪古梅花邊。',72,'全唐诗/poet.song.203000.json','["我生愜幽尋，訪古梅花邊。", "道原渺無際，滄海匯群川。", "仰之歎彌高，立則參於前。", "爲山始覆簣，掘井當及泉。", "端期會真意，可但窺陳編。", "再拜禮雙趺，清風生誦絃。"]'),
('12f0281a-f4aa-4277-933b-39d4706d9687','酬正錄直學  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','劍冰望梅關，山川接鄰壤。',72,'全唐诗/poet.song.203000.json','["劍冰望梅關，山川接鄰壤。", "前哲餘典刑，多士德心廣。", "曾子重而厚，朱張妙存養。", "吳子粹而雅，筆耕懲鹵莽。", "有友五人焉，亦足共清賞。", "烱然玉韞櫝，持此將安往。"]'),
('9cd51733-d5a2-41bc-8068-e9318f151682','酬衆士友  其一','徐鹿卿','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','行歌有妙趣，聲滿滄浪邊。',72,'全唐诗/poet.song.203000.json','["行歌有妙趣，聲滿滄浪邊。", "岱嶽宗衆山，渤澥傾百川。", "今人悉闇投，無因難至前。", "古人貴漸進，有本如原泉。", "周程不可作，三歎撫遺編。", "正音渺難聽，蛛絲潤鳴絃。"]'),
('99cca594-5a0a-4e11-ad18-2ce70109160f','酬衆士友  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','大鵬息天地，蚯蚓潔槁壤。',72,'全唐诗/poet.song.203000.json','["大鵬息天地，蚯蚓潔槁壤。", "吾儒苟自適，心與天地廣。", "受之不爲泰，鍾鼎備榮養。", "挽之或不留，林野歌浪莽。", "令譽妙文繡，片言榮爵賞。", "物理有乘除，大來斯小往。"]'),
('ec0be179-a306-400a-9848-d49f23bf07ad','次曾司戶見貽之韻併餞其行','徐鹿卿','宋','宋诗','song-poetry','','[]','聞道常苦遲，生世何用早。',48,'全唐诗/poet.song.203000.json','["聞道常苦遲，生世何用早。", "洛學此開端，文義富論討。", "高山勞景仰，內境幾回照。", "此心同古今，一理該衆妙。"]'),
('9d66a844-d2c7-4181-bd41-7af3251c1d26','和黎丞梅關嶺','徐鹿卿','宋','宋诗','song-poetry','','[]','峭壁接高天，閑雲淡橫嶺。',48,'全唐诗/poet.song.203000.json','["峭壁接高天，閑雲淡橫嶺。", "稍便僧房靜，未覺官曹冷。", "風月兩閑人，山川一佳境。", "誰歟共茲樂，老仙白垂領。"]'),
('ea572f8d-81e7-49b6-8245-fc18b268e6ce','判府羅郎中舉似快閣佳篇輒次嚴韻','徐鹿卿','宋','宋诗','song-poetry','','[]','此庵湖海士，心學富家傳。',48,'全唐诗/poet.song.203000.json','["此庵湖海士，心學富家傳。", "德量擎天柱，功名下瀨船。", "風流今尚爾，頭角已嶄然。", "蚤晚分清切，輸忠雨露邊。"]'),
('f681c036-00b7-4ee9-8d9c-246a8c36f57f','輓陳太庾  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','前身簡齋老，今世令河陽。',48,'全唐诗/poet.song.203000.json','["前身簡齋老，今世令河陽。", "眼底功名小，胸中書傳香。", "清談了公事，餘力到詩章。", "鳬履今安在，清都侍紫皇。"]'),
('3154a747-fe42-417a-ae93-5edfe0a8fa19','輓陳太庾  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','一病成疎隔，琴堂入見時。',48,'全唐诗/poet.song.203000.json','["一病成疎隔，琴堂入見時。", "形癯已非昔，客至尚談詩。", "手墨松烟濕，聲歌薤露悲。", "春風誰管領，梅月重相思。"]'),
('f32c3540-40e2-490e-87c8-1b5a95d4a586','再遊梅關書呈黄幹','徐鹿卿','宋','宋诗','song-poetry','','[]','雲邊大庾嶺，嶺上一叢林。',48,'全唐诗/poet.song.203000.json','["雲邊大庾嶺，嶺上一叢林。", "送往迎來路，升高望遠心。", "年華今復古，人事古猶今。", "唯有關門石，相看歲月深。"]'),
('a5c07cb2-4e52-4591-b350-22d9c9b23c15','次黄幹梅關韻  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','老盧行法地，千載復抽關。',48,'全唐诗/poet.song.203000.json','["老盧行法地，千載復抽關。", "崖石橫雙翠，禪機漏一斑。", "兩泉涵定慧，半榻卧雲閒。", "着我談風月，真成出世間。"]'),
('db816f6e-7647-4e82-ba80-4dacba6ade78','次黄幹梅關韻  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','相逢白蓮社，失脚過前溪。',48,'全唐诗/poet.song.203000.json','["相逢白蓮社，失脚過前溪。", "野興雲橫浦，禪心絮着泥。", "梅花大庾嶺，鉢石古招提。", "擾擾仕途夢，從前幾箇迷。"]'),
('d3698c22-1738-4930-81f9-b7187ce62e15','廬陵試院次陳明叔韻','徐鹿卿','宋','宋诗','song-poetry','','[]','西風下黄葉，客裏上新愁。',48,'全唐诗/poet.song.203000.json','["西風下黄葉，客裏上新愁。", "許我聯舟渡，從君借箸籌。", "坐縻三月久，寬作兩旬留。", "聚散一場夢，邯鄲鼻息齁。"]'),
('5ddd99b3-1676-4152-b0d3-02087d6129a2','快閣書呈吳宰','徐鹿卿','宋','宋诗','song-poetry','','[]','千里江章路，登臨獨此雄。',48,'全唐诗/poet.song.203000.json','["千里江章路，登臨獨此雄。", "清波長夜月，落木又秋風。", "浪蕋浮花外，盟鷗狎鷺中。", "詩魂蘇醒在，千載豫章公。"]'),
('1c05e746-64d7-48ea-9854-09fe8a525589','丙戌年新春偶成','徐鹿卿','宋','宋诗','song-poetry','','[]','新年十許日，才有一篇詩。',48,'全唐诗/poet.song.203000.json','["新年十許日，才有一篇詩。", "鄉思風中亂，春心雨裏知。", "病緣衰驟至，懶與睡相宜。", "暗想泉溪上，杜鵑啼故枝。"]'),
('9197e0a4-f1fb-4dc3-a8bb-a89877bd38df','感興  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','吹竽媚所好，乞墦厭其餘。',24,'全唐诗/poet.song.203000.json','["吹竽媚所好，乞墦厭其餘。", "邇來效尤者，往往拾芥如。"]'),
('e9d674e1-5ff7-4fe8-8778-e2925d532b6c','感興  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','浮名豈不榮，遺道亦安忍。',24,'全唐诗/poet.song.203000.json','["浮名豈不榮，遺道亦安忍。", "君看趙孟徒，千古同一盡。"]'),
('5115e9bb-54ca-448e-a13b-343a4340166c','春日','徐鹿卿','宋','宋诗','song-poetry','','[]','地冷春無力，野晴天有功。',48,'全唐诗/poet.song.203000.json','["地冷春無力，野晴天有功。", "芝蘭傲幽谷，蓬藋長東風。", "政以身爲患，非關詩得窮。", "且求吾適意，敢擬衆人同。"]'),
('57cc207c-9e3a-41c5-a1c2-0f323e92fef8','小英石峰','徐鹿卿','宋','宋诗','song-poetry','','[]','舊作英巖隠，今爲庾嶠行。',48,'全唐诗/poet.song.203000.json','["舊作英巖隠，今爲庾嶠行。", "雖然一拳許，有此數峰青。", "崷崒驚凡目，堅剛悖世情。", "墨卿相指似，只尺是蓬瀛。"]'),
('d35fc019-f835-43b6-ba80-ea372ca9b2de','送太庾黎丞  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','老矣黎夫子，拳拳只此書。',48,'全唐诗/poet.song.203000.json','["老矣黎夫子，拳拳只此書。", "萬緣俱淺澹，一字不遺餘。", "庾嶺風烟句，石溪雲水居。", "無人知此味，說似子非魚。"]'),
('089f60c6-1f8f-4fca-9375-f08596e06339','送太庾黎丞  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','客懷秋易惡，送客更當秋。',48,'全唐诗/poet.song.203000.json','["客懷秋易惡，送客更當秋。", "薄宦相從久，孤征肯暫留。", "酒輕離思重，目短大江流。", "黄菊聊持贈，寒香晚不羞。"]'),
('0bc1e5c8-a610-4559-83b7-27dc6bb2c861','次瀛父詩','徐鹿卿','宋','宋诗','song-poetry','','[]','青山闖門戶，綠竹窺簷楹。',132,'全唐诗/poet.song.203000.json','["青山闖門戶，綠竹窺簷楹。", "巋然一亭石，境界涵幽清。", "季候昔經始，扁以橫浦名。", "亭前兩泓泉，吞吐寒蟾明。", "方員中規矩，曲水相紆縈。", "汲溉當瓶盎，觀覽駢簪纓。", "黄君靜者徒，磊落千人英。", "朅來梅花邊，一見眼爲青。", "官居廉泉上，復此逢清冷。", "詩豪瀉銀漢，興逸凌紫京。", "回首聲潺潺，恍如醉翁亭。"]'),
('4344465d-5152-42b7-9b57-15c842d73b2f','林判府和前韻見示且約暇日論茗次韻爲謝','徐鹿卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔我觀西湖，碧瓦蔭丹楹。',132,'全唐诗/poet.song.203000.json','["昔我觀西湖，碧瓦蔭丹楹。", "冷泉一泓玉，占斷錢塘清。", "南來泝西江，灘以十八名。", "出石訪廉泉，醉眼增雙明。", "平生山水性，不着塵俗縈。", "佳處輒留憩，竟日陪衿纓。", "薄宦落橫浦，師友皆豪英。", "尋勝得湛泉，古甃莓苔青。", "上有石崖峻，下有沙水冷。", "近可俯貢川，遠可企吳京。", "爲公飲春茶，日日來新亭。"]'),
('30332680-5767-4cae-be17-c1a3531ab025','府判再示楹字韻詩再和之','徐鹿卿','宋','宋诗','song-poetry','','[]','別駕寶橫道，冷官槁代楹。',132,'全唐诗/poet.song.203000.json','["別駕寶橫道，冷官槁代楹。", "誰令塵土姿，近映冰壺清。", "君家閩山陽，泉以蒙著名。", "平生養正功，烱烱心地明。", "我家古泉溪，四顧巖巒縈。", "日迂長者轍，來往紛振纓。", "湛泉偶趨風，嗽液咀流英。", "古榕憩陰陰，綠竹哦青青。", "泉鳴似喚客，盈耳清音泠。", "歡謠動海隅，溫詔來宸京。", "只今遊覽地，回首真郵亭。"]'),
('70892ad2-5f8c-411c-963a-cc57586166e4','出灘賦灘石','徐鹿卿','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嵯峨聶都山，豫水茲發原。',288,'全唐诗/poet.song.203000.json','["嵯峨聶都山，豫水茲發原。", "始者才濫觴，其流細涓涓。", "東行介南埜，章水西入焉。", "又東漸雄張，有州故名虔。", "貢水遠來赴，融合爲贛川。", "當其初合時，泓渟匪爲淵。", "中通尺五流，玉虹卧蜿蜒。", "群山來左右，萬石梗後前。", "初疑牧群羊，忽訝墮飛鳶。", "伏犀狀魁桀，浮鴈影接聯。", "阿河陣敢死，赴浴池連錢。", "下者宛蹲踞，上者將騰騫。", "或矯首欲鬭，或宛留安眠。", "或退然深伏，露尖大如掌。", "或竦然特起，儼立高齊肩。", "或兩兩爲偶，或伍伍相連。", "此有一席平，彼有萬竅穿。", "齒齒漱寒冽，眼眼開青圓。", "形模互馳騁，氣勢相吐吞。", "平坦十數丈，變怪紛百千。", "顧盼不暇給，算數疇能殫。", "天公轟震霆，力士推雷門。", "上下相舂撞，對語不得聞。", "衆灘角巇嶮，四灘獨稱專。"]'),
('112b9da1-6396-4c60-a960-453b2a40e6d7','雜興  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','荒凉橫浦郡，頗稱冷官居。',24,'全唐诗/poet.song.203000.json','["荒凉橫浦郡，頗稱冷官居。", "爲甚更清睡，冬來不讀書。"]'),
('4dac59e0-1b44-4a14-a666-db490bf5085d','雜興  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','梅花亦何奇，偏便幽人愛。',24,'全唐诗/poet.song.203000.json','["梅花亦何奇，偏便幽人愛。", "清寒風雪夜，一枝靜相對。"]'),
('aa9de6ca-732d-43ea-a7d1-50e12cf0890e','雜興  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','竹枝雙翡翠，縮頸照寒水。',24,'全唐诗/poet.song.203000.json','["竹枝雙翡翠，縮頸照寒水。", "驀見渡溪人，一聲忽飛起。"]'),
('bb6c0318-57e7-429b-a43a-0002c7333862','雜興  其四','徐鹿卿','宋','宋诗','song-poetry','','[]','庭蘭尚牢落，庭草已勾萌。',24,'全唐诗/poet.song.203000.json','["庭蘭尚牢落，庭草已勾萌。", "草與蘭何似，東風亦世情。"]'),
('b041ec03-97ce-4ee5-8456-3e61b6ce015e','雜興  其五','徐鹿卿','宋','宋诗','song-poetry','','[]','豈不謀數椽，吾力苦未足。',24,'全唐诗/poet.song.203000.json','["豈不謀數椽，吾力苦未足。", "破屋儻支撐，尚堪燈火讀。"]'),
('215fbb3e-6821-4e28-964c-0fe0c2c1e6d0','雜興  其六','徐鹿卿','宋','宋诗','song-poetry','','[]','學詩不能神，得句常草草。',24,'全唐诗/poet.song.203000.json','["學詩不能神，得句常草草。", "儻可寄吾懷，豈必人稱好。"]'),
('de698adc-5429-49b7-a019-790eff7525b6','月夜赴郡會歸輾轉不成寐觸事感懷口占四古句  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','庾山高入雲，章水清見骨。',48,'全唐诗/poet.song.203000.json','["庾山高入雲，章水清見骨。", "山高晚宜梅，水清寒浸月。", "美人天一方，雲烟妙空闊。", "带月簪梅花，獨起舞殘雪。"]'),
('dc324315-249c-48f7-b55b-b3038aa0b19a','月夜赴郡會歸輾轉不成寐觸事感懷口占四古句  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','槎牙兩榕木，偃蹇江之濆。',48,'全唐诗/poet.song.203000.json','["槎牙兩榕木，偃蹇江之濆。", "雖緣擁腫廢，幸免尋斧斤。", "東家不鳴鴈，喑默存其神。", "事固不一概，鴈烹木長春。"]'),
('774f9e72-4b9d-4886-8efe-96fcbe0be37e','月夜赴郡會歸輾轉不成寐觸事感懷口占四古句  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','連雲峙華屋，東隅滿荆棘。',48,'全唐诗/poet.song.203000.json','["連雲峙華屋，東隅滿荆棘。", "延緣耗地利，狼藉窺空壁。", "一朝火燎原，根枝蕩無迹。", "蔓除亦可喜，火烈憂轉劇。"]'),
('dbd6ff47-9872-4997-8508-93c2a6954615','月夜赴郡會歸輾轉不成寐觸事感懷口占四古句  其四','徐鹿卿','宋','宋诗','song-poetry','','[]','騎獵似爲業，養鷹如養兒。',48,'全唐诗/poet.song.203000.json','["騎獵似爲業，養鷹如養兒。", "人言鷹玩兔，主翁鼎鑊之。", "玩兔信不忠，九死固其宜。", "萬一疑似間，群鷹驚欲飛。"]'),
('00858474-fc4d-43ef-b92f-e019aba1f430','賀判府生子','徐鹿卿','宋','宋诗','song-poetry','','[]','西江最上流，南安古名城。',240,'全唐诗/poet.song.203000.json','["西江最上流，南安古名城。", "庾山蔚然秀，章水瀏其清。", "異代得偉人，分此風月平。", "往者程伯溫，關决燁有聲。", "煌煌萬金産，烱烱雙珠明。", "四海名父子，一門佳弟兄。", "造詣極洙泗，叩擊鏗英莖。", "流風已百載，今日復一程。", "提屏東方來，寬令孚群甿。", "名門衍餘慶，蘭玉添新榮。", "山川萃神秀，穹垕儲精英。", "仲律青陽熙，五夜璧月盈。", "天上雙麒麟，剛欲逐隊行。", "抱送者釋氏，協夢兮長庚。", "昔爲程氏子，俱以斯道鳴。", "今爲陳家兒，岐嶷由天成。", "覓公洗兒錢，我不學世情。", "期公愛子深，視厥程先生。", "器質待涵養，門戶須支撐。", "會看三世間，接踵當拒衡。"]'),
('c98c3f47-f4fb-481b-b104-3154ebe4727c','之官過贛灘  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','玉局詩中皇恐灘，聞之已爲骨毛寒。',32,'全唐诗/poet.song.203000.json','["玉局詩中皇恐灘，聞之已爲骨毛寒。", "那知舞索并天柱，更向前頭作怒瀾。"]'),
('d768c5d9-edd8-4d99-9c53-8ff42485b350','之官過贛灘  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','灘聲嘈雜怒轟雷，頑石參差撥不開。',32,'全唐诗/poet.song.203000.json','["灘聲嘈雜怒轟雷，頑石參差撥不開。", "行客盡言灘路嶮，誰教君向嶮中來。"]'),
('58b9ec30-91c0-4b56-9d76-3de03ff5d6b7','雨霽報謁見一鷺得魚群鷺爭食之  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','一鷺翩翩傍釣磯，隔汀群鷺已知機。',32,'全唐诗/poet.song.203000.json','["一鷺翩翩傍釣磯，隔汀群鷺已知機。", "空將辛苦供群吻，畢竟貪魚罪有歸。"]'),
('32fa3363-7575-47fd-8358-31bb4578dd69','雨霽報謁見一鷺得魚群鷺爭食之  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','履嶮窺魚得幾何，傍來攫取較多多。',32,'全唐诗/poet.song.203000.json','["履嶮窺魚得幾何，傍來攫取較多多。", "爭如歛翼餐餘粟，猶在人間潔白科。"]'),
('2658eab8-d813-4d5b-b744-9835b1ba446a','壽曾僉判  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','漸報星橋鐵鎖開，遊仙失脚下蓬萊。',32,'全唐诗/poet.song.203000.json','["漸報星橋鐵鎖開，遊仙失脚下蓬萊。", "一番春色歸桃杏，半吐歌唇獻壽杯。"]'),
('55292062-e439-48c4-ad16-599a476c671c','壽曾僉判  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','陸地新開萬朵蓮，綵雲擁出幙中仙。',32,'全唐诗/poet.song.203000.json','["陸地新開萬朵蓮，綵雲擁出幙中仙。", "傅巖已入春宵夢，火急排雲叶九天。"]'),
('dbc08ed4-84d1-4897-8055-470707c63027','和杜子野湛泉詩來詩有塵事分清事之句','徐鹿卿','宋','宋诗','song-poetry','','[]','榕陰漠漠俯清泉，泉溜涓涓不計年。',32,'全唐诗/poet.song.203000.json','["榕陰漠漠俯清泉，泉溜涓涓不計年。", "未必塵紛敗佳思，憑欄得句却天然。"]'),
('90ce482c-c9ff-40db-aba4-44e6fdfcde17','子野又以詩來言不畫涪翁畫李翁再和之','徐鹿卿','宋','宋诗','song-poetry','','[]','太守一時留惠愛，詩仙萬古自清風。',32,'全唐诗/poet.song.203000.json','["太守一時留惠愛，詩仙萬古自清風。", "尋常藻繪初何記，終是人心記此翁。"]'),
('b2da96ee-c0ea-4632-bfa3-5eca2724b8da','聞鴉有感','徐鹿卿','宋','宋诗','song-poetry','','[]','鵲群饒舌本何功，鴉陣狂言却似忠。',32,'全唐诗/poet.song.203000.json','["鵲群饒舌本何功，鴉陣狂言却似忠。", "聞鵲忻然鴉輒唾，甘諛易售古來同。"]'),
('f00d1cf8-6d06-45aa-a1d7-ee208292a7bb','讀楊妃傳','徐鹿卿','宋','宋诗','song-poetry','','[]','六宮粉黛溢三千，一箇中間寵愛專。',32,'全唐诗/poet.song.203000.json','["六宮粉黛溢三千，一箇中間寵愛專。", "自此世情生妄想，推排妃子作神仙。"]'),
('035c3b33-fa5b-4fe8-a365-f9d0dce455e4','曾氏清江亭','徐鹿卿','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','想得當年月浸扃，諸公翰墨此縱橫。',32,'全唐诗/poet.song.203000.json','["想得當年月浸扃，諸公翰墨此縱橫。", "亭荒久矣詩亡恙，一道長江萬古清。"]'),
('45f6aeee-f904-4736-8625-39ee23a5f85e','杜子野寄雲山蘭石四畫且以近詩來和韻酬之  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','石瘦蘭馨入骨寒，筆端往往带儒酸。',32,'全唐诗/poet.song.203000.json','["石瘦蘭馨入骨寒，筆端往往带儒酸。", "河陽桃李春風滿，此段煩君更畫看。"]'),
('12d06725-eaa6-4622-a2f2-a3c2365d8d07','杜子野寄雲山蘭石四畫且以近詩來和韻酬之  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','愛君標格碧峰清，爲輟床頭竹葉瓶。',32,'全唐诗/poet.song.203000.json','["愛君標格碧峰清，爲輟床頭竹葉瓶。", "想得醉餘鋒穎健，群鵝端欲博黄庭。"]'),
('5115a539-0fba-4be2-b86b-5e982826839b','和杜宰送茶韻  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','誰遣持書晝打門，茶魁有句牧之孫。',32,'全唐诗/poet.song.203000.json','["誰遣持書晝打門，茶魁有句牧之孫。", "煎調還我西江手，水茗相投自不渾。"]'),
('888cd511-80ae-4c91-9f16-43d569b1278a','和杜宰送茶韻  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','月團不遣貢脩門，却寄書癡閉戶孫。',32,'全唐诗/poet.song.203000.json','["月團不遣貢脩門，却寄書癡閉戶孫。", "若把焦坑分品第，濬功端合遜王渾。"]'),
('ab229bf8-8d99-4cf4-b3dc-a77bd0c2ba3f','杜子野惠來禽內碧桃謝以一絕','徐鹿卿','宋','宋诗','song-poetry','','[]','五色雲牋到冷曹，更將果實飽詩饕。',32,'全唐诗/poet.song.203000.json','["五色雲牋到冷曹，更將果實飽詩饕。", "便應譜入來禽內，青李刊除着碧桃。"]'),
('589e7d08-2865-47f4-9fd8-b3da17c04984','子野惠竹𪕋有感而賦二絕  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','玉局詩中曾識面，小山書後忽題名。',32,'全唐诗/poet.song.203000.json','["玉局詩中曾識面，小山書後忽題名。", "鴟夷混沌俱慙遜，更勝河豚大瘦生。"]'),
('1338caba-b501-4e32-aec9-8694e6bc351b','子野惠竹𪕋有感而賦二絕  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','食根爲𪕋肥腰腹，食實爲凰長羽毛。',32,'全唐诗/poet.song.203000.json','["食根爲𪕋肥腰腹，食實爲凰長羽毛。", "同是此君供廩餼，居然地位判卑高。"]'),
('97875104-8120-40f7-a800-28e8dfe85243','七月二十一日重過贛灘十絕句  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','矯矯雄張虎欲奔，低低蹲伏鴈成群。',32,'全唐诗/poet.song.203000.json','["矯矯雄張虎欲奔，低低蹲伏鴈成群。", "丁寧莫礙行舟過，喚作長生萬石君。"]'),
('f570ade1-246c-4ca7-9f02-94b3a5fce269','七月二十一日重過贛灘十絕句  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','初疑萬馬立沙汀，又似臨流簇戍兵。',32,'全唐诗/poet.song.203000.json','["初疑萬馬立沙汀，又似臨流簇戍兵。", "激怒灘聲能許劣，終宵長泄不平鳴。"]'),
('67a174f8-718d-472d-9910-1a7d5a190dbf','七月二十一日重過贛灘十絕句  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','漱崖嚙石出奇功，浴月涵風淡蕩中。',32,'全唐诗/poet.song.203000.json','["漱崖嚙石出奇功，浴月涵風淡蕩中。", "過者千帆閙如織，會心知有幾人同。"]'),
('63a75b76-5ab4-4187-a691-66e74bb51f41','七月二十一日重過贛灘十絕句  其四','徐鹿卿','宋','宋诗','song-poetry','','[]','乘車山徑苦崎傾，舟涉飛湍石膽驚。',32,'全唐诗/poet.song.203000.json','["乘車山徑苦崎傾，舟涉飛湍石膽驚。", "等是危途休計較，此心無礙盡堪行。"]'),
('0c9f5877-0433-4809-b144-ab1aecf2bc43','七月二十一日重過贛灘十絕句  其五','徐鹿卿','宋','宋诗','song-poetry','','[]','北來快順一篙駃，南去間關百丈牽。',32,'全唐诗/poet.song.203000.json','["北來快順一篙駃，南去間關百丈牽。", "世事從來且如許，下灘船看上灘船。"]'),
('f0a2a9a1-5199-4eab-a517-8e192711034a','七月二十一日重過贛灘十絕句  其六','徐鹿卿','宋','宋诗','song-poetry','','[]','嶺海脂膏自古傳，至今來往共長川。',32,'全唐诗/poet.song.203000.json','["嶺海脂膏自古傳，至今來往共長川。", "靈靈有眼還知道，幾箇歸人月滿船。"]'),
('c133f618-39ad-4f33-9e4c-82135caca86f','七月二十一日重過贛灘十絕句  其七','徐鹿卿','宋','宋诗','song-poetry','','[]','江清端可樂朝饑，嶮處行人盡得知。',32,'全唐诗/poet.song.203000.json','["江清端可樂朝饑，嶮處行人盡得知。", "平陸波濤良叵測，嶮中却自是平夷。"]'),
('731c3b9f-6d33-4501-9b08-9378fbeb09c7','七月二十一日重過贛灘十絕句  其八','徐鹿卿','宋','宋诗','song-poetry','','[]','聞道春江瀲灧時，灘平如掌棹如飛。',32,'全唐诗/poet.song.203000.json','["聞道春江瀲灧時，灘平如掌棹如飛。", "何時滿却葵丘戍，流水桃花送客歸。"]'),
('0dd3de3b-2f89-43f4-846e-bebe52d92359','七月二十一日重過贛灘十絕句  其九','徐鹿卿','宋','宋诗','song-poetry','','[]','十八灘頭一葉身，山川曾識舊詞臣。',32,'全唐诗/poet.song.203000.json','["十八灘頭一葉身，山川曾識舊詞臣。", "詩魂百載猶蘇醒，應笑風波解戲人。"]'),
('2a125a73-bb6e-4aba-a49e-ca4c45c3733e','七月二十一日重過贛灘十絕句  其一○','徐鹿卿','宋','宋诗','song-poetry','','[]','儲潭初發未朝餐，一日經行十八灘。',32,'全唐诗/poet.song.203000.json','["儲潭初發未朝餐，一日經行十八灘。", "不似來時推不進，吟詩把酒傲驚湍。"]'),
('3bdac66a-097e-4972-8bc3-13f51cae68ac','廬陵試院次陳明叔韻','徐鹿卿','宋','宋诗','song-poetry','','[]','曉看窗影過飛鴉，短髮蓬鬆一半斜。',32,'全唐诗/poet.song.203000.json','["曉看窗影過飛鴉，短髮蓬鬆一半斜。", "兩月不遨直瘦却，夢尋庾嶺訪梅花。"]'),
('fdb0dd98-e68f-4d5c-baee-037d8a666f4c','梅花','徐鹿卿','宋','宋诗','song-poetry','','[]','舊傳庾嶺梅花好，及到梅關少見梅。',32,'全唐诗/poet.song.203000.json','["舊傳庾嶺梅花好，及到梅關少見梅。", "唯有一般差可信，南枝長占小春開。"]'),
('4d2ed60c-60fc-4ed2-b24b-b3902e76b729','觀釣','徐鹿卿','宋','宋诗','song-poetry','','[]','熱猶造請褦襶子，老未知休矍鑠翁。',32,'全唐诗/poet.song.203000.json','["熱猶造請褦襶子，老未知休矍鑠翁。", "立懦廉頑今幾見，桐江夢想一絲風。"]'),
('9f9b13e0-1cdb-4324-ab8f-73ea30137c54','府判社日招飲蔣園座中索賦詩三絕句  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','玉妃圍坐簇娉婷，勾引陽和媚德星。',32,'全唐诗/poet.song.203000.json','["玉妃圍坐簇娉婷，勾引陽和媚德星。", "洗盡凡花脂粉氣，月香亭是雪香亭。"]'),
('acbdabc3-6b4f-40bd-8780-b5414f3d630e','府判社日招飲蔣園座中索賦詩三絕句  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','城西好事主人家，走送天香國色花。',32,'全唐诗/poet.song.203000.json','["城西好事主人家，走送天香國色花。", "嶺阯三年才見此，便應奴婢命山茶。"]'),
('9ba0a401-5242-409a-bbb8-504531e5bbcc','府判社日招飲蔣園座中索賦詩三絕句  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','柳絲摇曳春風裏，山色空濛社雨中。',32,'全唐诗/poet.song.203000.json','["柳絲摇曳春風裏，山色空濛社雨中。", "領略韶華拚一醉，巴歌聊爾效南翁。"]'),
('080191c6-9a3f-45b9-a75c-4ddc45f6c472','再續前韻  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','鶑谷聲喧雨乍晴，邦人引領望屏星。',32,'全唐诗/poet.song.203000.json','["鶑谷聲喧雨乍晴，邦人引領望屏星。", "陽和一氣元無際，小爲尋花到野亭。"]'),
('76679f37-f252-4c62-990f-1b8847c3cd9c','再續前韻  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','荷囊清白舊傳家，來看溶溶月下花。',32,'全唐诗/poet.song.203000.json','["荷囊清白舊傳家，來看溶溶月下花。", "不似尋常殺風景，也宜飲酒也宜茶。"]'),
('52dffbd5-cc8d-48a9-8498-513902d4ec2b','再續前韻  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','筆端鸞鳳詩千首，社下鷄豚酒一鍾。',32,'全唐诗/poet.song.203000.json','["筆端鸞鳳詩千首，社下鷄豚酒一鍾。", "九十日春今强半，典衣還憶少陵翁。"]'),
('813e5bdc-b219-4622-b7c0-c2d70c45daac','依前韻呈府判  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','城南烟雨趁春耕，遥指屏星是福星。',32,'全唐诗/poet.song.203000.json','["城南烟雨趁春耕，遥指屏星是福星。", "肯學晉人耽燕樂，只因修禊會蘭亭。"]'),
('74218af7-e426-4ef7-874d-a1e89dcd0aac','依前韻呈府判  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','占籍蓬萊第一家，勸農蒔稻莫蒔花。',32,'全唐诗/poet.song.203000.json','["占籍蓬萊第一家，勸農蒔稻莫蒔花。", "時和不但歌華黍，牆有柔桑焙有茶。"]'),
('3531e932-ec86-4507-b959-ff115fa37c23','依前韻呈府判  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','發舒生意烟花外，醖釀豐年雨意中。',32,'全唐诗/poet.song.203000.json','["發舒生意烟花外，醖釀豐年雨意中。", "關决郡條知有助，故應千里化文翁。"]'),
('64ab532b-bd16-4516-8cce-65d8e7898da7','月香亭主人送似牡丹座客作芍藥品題  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','素粧芍藥萬花王，葉未全舒滿國香。',32,'全唐诗/poet.song.203000.json','["素粧芍藥萬花王，葉未全舒滿國香。", "醉眼夢騰渾不醒，虎賁却似蔡中郎。"]'),
('b32f8ace-0b12-443f-965d-7e63820380bb','月香亭主人送似牡丹座客作芍藥品題  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','玉容當配水仙王，壓盡群花不敢香。',32,'全唐诗/poet.song.203000.json','["玉容當配水仙王，壓盡群花不敢香。", "晝困未甦酣宿雨，也疑湯餠試何郎。"]'),
('e10b53f3-32dc-442a-a0bb-16dec4a52b87','愛山堂七絕句  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','橫江江上四山環，少得當前面勢寬。',32,'全唐诗/poet.song.203000.json','["橫江江上四山環，少得當前面勢寬。", "試上此堂舒遠目，疎林盡處見峰巒。"]'),
('e920a206-a670-448f-8167-4b89ea40a456','愛山堂七絕句  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','大峰舒肆小峰崷，簾幙中間坐五侯。',32,'全唐诗/poet.song.203000.json','["大峰舒肆小峰崷，簾幙中間坐五侯。", "立斷斜陽吟不透，一聲牧笛滿林秋。"]'),
('2e8fe7a4-94a9-46ae-92bc-fbb7e61fe279','愛山堂七絕句  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','竹籬茅店野人家，門外清流一带斜。',32,'全唐诗/poet.song.203000.json','["竹籬茅店野人家，門外清流一带斜。", "小隠桃溪端的是，更須水上覓胡麻。"]'),
('8ba72c21-5687-454f-9307-863b1f46ff4d','愛山堂七絕句  其四','徐鹿卿','宋','宋诗','song-poetry','','[]','比屋桑麻三月雨，夾溪桃李四時春。',32,'全唐诗/poet.song.203000.json','["比屋桑麻三月雨，夾溪桃李四時春。", "誰歟幻出山前景，指似堂中覓句人。"]'),
('195b0e2e-060c-49af-8f7d-23b32bdce272','愛山堂七絕句  其五','徐鹿卿','宋','宋诗','song-poetry','','[]','自有堂來三換扁，官居賢否只山知。',32,'全唐诗/poet.song.203000.json','["自有堂來三換扁，官居賢否只山知。", "酴醾嫵媚今何許，山色青妍宛舊時。"]'),
('bb4e03e8-eec8-457b-bab5-d21a199c15bc','愛山堂七絕句  其六','徐鹿卿','宋','宋诗','song-poetry','','[]','客問主人今暇否，主人心與水雲閒。',32,'全唐诗/poet.song.203000.json','["客問主人今暇否，主人心與水雲閒。", "庭空吏散文書靜，茗椀熏爐上愛山。"]'),
('9bd743ca-b588-4762-bcff-1e6a4bd086f7','愛山堂七絕句  其七','徐鹿卿','宋','宋诗','song-poetry','','[]','坡谷經行久品題，顧令迂拙强搜詩。',32,'全唐诗/poet.song.203000.json','["坡谷經行久品題，顧令迂拙强搜詩。", "雖然何世無坡谷，山立孤高好自持。"]'),
('ed50cdad-c685-468a-b00d-3184c925fe36','贈琴士翁明遠併簡幹教二黄丈  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','鍾期不作伯牙死，琴墮雲烟莽蒼中。',32,'全唐诗/poet.song.203000.json','["鍾期不作伯牙死，琴墮雲烟莽蒼中。", "翠玉樓前幾識子，山風吹散又西東。"]'),
('a781b824-296b-4021-866a-947647da9ec7','贈琴士翁明遠併簡幹教二黄丈  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','莫恨吾琴難入俗，俗人不聽韻方高。',32,'全唐诗/poet.song.203000.json','["莫恨吾琴難入俗，俗人不聽韻方高。", "𥱧箏耳畔休拈出，韶石亭前走一遭。"]'),
('2a4b01e8-139a-4eed-991e-49918f8cd79b','贈琴士翁明遠併簡幹教二黄丈  其三','徐鹿卿','宋','宋诗','song-poetry','','[]','靜寄琴中適意吟，魯庵句裏自然琴。',32,'全唐诗/poet.song.203000.json','["靜寄琴中適意吟，魯庵句裏自然琴。", "琴詩苦要清如許，千古寥寥覓賞音。"]'),
('7d828188-3494-4951-a423-412dde2f1cab','贈琴士翁明遠併簡幹教二黄丈  其四','徐鹿卿','宋','宋诗','song-poetry','','[]','我亦能琴妙不傳，無琴無譜併無絃。',32,'全唐诗/poet.song.203000.json','["我亦能琴妙不傳，無琴無譜併無絃。", "客來問訊琴安在，指似孤鴻落日邊。"]'),
('2a0880d9-2281-48c2-9dd2-ba35cae7f864','章貢三咏 鬰孤臺','徐鹿卿','宋','宋诗','song-poetry','','[]','群山湧浪翠周遭，中峙層臺氣象豪。',32,'全唐诗/poet.song.203000.json','["群山湧浪翠周遭，中峙層臺氣象豪。", "萬里闕庭長在望，定應天眼照孤高。"]'),
('421bfad3-76a3-45a4-a36c-283e5c0e24c1','章貢三咏 鬰孤洞天','徐鹿卿','宋','宋诗','song-poetry','','[]','崇山脩竹小蘭亭，人在雲烟深處行。',64,'全唐诗/poet.song.203000.json','["崇山脩竹小蘭亭，人在雲烟深處行。", "環立千竿了清絕，中盤一徑巧紆縈。", "紛紛鴈鶩庭堆案，擾擾蠅蝸市有聲。", "洞裏道人忘底事，小橋西畔句初成。"]'),
('553a009c-4260-4173-86fa-711676a1d3b3','章貢三咏 翠玉樓','徐鹿卿','宋','宋诗','song-poetry','','[]','夢跨長虹海上遊，寒生肌骨一壺秋。',32,'全唐诗/poet.song.203000.json','["夢跨長虹海上遊，寒生肌骨一壺秋。", "好風吹得時魂醒，自寄雲間翠玉樓。"]'),
('52abc256-d8f3-41a8-84e3-439c13097119','上判府陳秘丞  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','斗大山州枕上流，蓬山仙客此遨遊。',64,'全唐诗/poet.song.203000.json','["斗大山州枕上流，蓬山仙客此遨遊。", "讀書竹屋公多暇，樂業江郊民有秋。", "泮藻叢邊深長育，嶺梅香裏費賡酬。", "有人來問和羹味，太守忘言一笑休。"]'),
('aa6b6611-7492-4508-8292-7ace4669024b','上判府陳秘丞  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','向來一榻下南州，此事無傳閲幾秋。',64,'全唐诗/poet.song.203000.json','["向來一榻下南州，此事無傳閲幾秋。", "顧我風流非孺子，乃今天幸事王侯。", "頹波甚矣誰能返，砥柱巋然好鎮浮。", "喚起東湖風月夢，請爲榱桷備兼收。"]'),
('c9353394-7bfa-4fb1-917d-09bac1161b6d','酬溫戶見和首篇','徐鹿卿','宋','宋诗','song-poetry','','[]','南來冠蓋總名流，契合全忘是宦遊。',64,'全唐诗/poet.song.203000.json','["南來冠蓋總名流，契合全忘是宦遊。", "清甚夜寒金井露，瑩於霜曉玉壺秋。", "梅關景物詩陶寫，蓮幙風流酒勸酬。", "只恐烏羅留不住，漢庭山立看揚休。"]'),
('d3125932-7b95-4b12-b859-db9d465c1687','酬陳太庾  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','後來令尹職承流，君亦牛刀嶺阯遊。',64,'全唐诗/poet.song.203000.json','["後來令尹職承流，君亦牛刀嶺阯遊。", "和氣滿城桃醉雨，仁風四野麥先秋。", "陳玄譜在交逾固，毛穎功多賞未酬。", "撫字勞心古如此，不須爲米便歸休。"]'),
('96c18d6b-f4fa-4d1e-b9a6-1693ea9ffb95','酬陳太庾  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','英聲獵獵滿山州，翠剡飛來鶚在秋。',64,'全唐诗/poet.song.203000.json','["英聲獵獵滿山州，翠剡飛來鶚在秋。", "父母視民非俗吏，子男分土列諸侯。", "篇詩捲送驪珠爛，杯酒相從蠟味浮。", "不必即人人即我，定知瑚璉合當收。"]'),
('ffceec22-f6a2-4fe3-91bf-e5e3481d28ae','酬何學賓  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','商山黄綺信清流，自合相從鶴禁遊。',64,'全唐诗/poet.song.203000.json','["商山黄綺信清流，自合相從鶴禁遊。", "鄴架爛觀三萬軸，莊椿行老八千秋。", "高懷莫遣群兒覺，佳句那無半語酬。", "我亦諸侯老賓客，更將墨守問何休。"]'),
('057391ad-6300-4445-99a9-ef85a5d68af5','酬何學賓  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','昔聞鼻祖在揚州，詩句清於玉露秋。',64,'全唐诗/poet.song.203000.json','["昔聞鼻祖在揚州，詩句清於玉露秋。", "奕世相承忻有後，在家還復勝封侯。", "觀頤義熟靈龜見，祝壽杯深綠蟻浮。", "丹鳳休銜丹詔下，黄冠已懶待黄收。"]'),
('a01dcdb3-c142-4ef5-a4ca-0336f2874d93','酬曾學錄王掌祠  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','夫君砥柱屹中流，也肯來爲泮水遊。',64,'全唐诗/poet.song.203000.json','["夫君砥柱屹中流，也肯來爲泮水遊。", "好句上摩周雅頌，褒詞榮過魯春秋。", "高山忽奏音逾古，美玉深藏價未酬。", "搜遍枯腸難論報，江淹聊欲擬陽休。"]'),
('91bf099c-e496-4a96-aaea-10a9c5e0271d','酬曾學錄王掌祠  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','去年射策古杭州，來到梅關歲已秋。',64,'全唐诗/poet.song.203000.json','["去年射策古杭州，來到梅關歲已秋。", "德薄豈堪儀衆俊，貧軀聊復客諸侯。", "一窗燈火味清苦，四座風流酒拍浮。", "弟子無非樑棟用，先生未必副先收。"]'),
('5d9b1a24-b397-4bf4-96b4-26bc5724529f','酬張錄南老  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','詞源傾寫峽江流，曾蹋槐花月裏遊。',64,'全唐诗/poet.song.203000.json','["詞源傾寫峽江流，曾蹋槐花月裏遊。", "梅嶺詩篇一甌雪，芹宮書冊四山秋。", "明珠小借枯崖潤，美玉那無善價酬。", "再戰定穿三級浪，絲鞭席帽拜新休。"]'),
('eb12628b-57fc-4f97-8f51-2c0206a38d22','酬張錄南老  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','生長西江帝子州，蟪蛄强欲語春秋。',64,'全唐诗/poet.song.203000.json','["生長西江帝子州，蟪蛄强欲語春秋。", "溉根正喜逢張籍，拾芥寧堪擬夏侯。", "冷淡工夫千兔禿，飄零蹤跡一萍浮。", "自量只合山林住，烏幙如何也見收。"]'),
('03310215-6f17-414a-9bf6-84b7292876c9','酬張直學  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','章水元通劍水流，朅來庠序得同遊。',64,'全唐诗/poet.song.203000.json','["章水元通劍水流，朅來庠序得同遊。", "自從快蹋梅花雪，一洗從前茆瘴秋。", "官况我今忘獨冷，鳴聲君合起相酬。", "龍光自有張華識，句不驚人未遽休。"]'),
('058d7b26-acfb-443a-93a0-255431aa8e18','酬張直學  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','平生久願識荆州，落落參辰幾度秋。',64,'全唐诗/poet.song.203000.json','["平生久願識荆州，落落參辰幾度秋。", "下榻有誰知孺子，運籌端合屬留侯。", "吟成春草夢非夢，跡漾風萍浮自浮。", "見說桂枝消息近，廣寒清徹片雲收。"]'),
('37b2f137-3c0b-467f-9b4e-d3afb412f45f','酬吳直學  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','滾滾詞源峽倒流，飄飄擬上廣寒遊。',64,'全唐诗/poet.song.203000.json','["滾滾詞源峽倒流，飄飄擬上廣寒遊。", "一編芹泮挑燈夜，兩捷槐花得意秋。", "賸喜文盟堪共結，忽驚詩債未曾酬。", "數能相過徵奇事，肯學淵明遣客休。"]'),
('2d251b62-75e1-4912-9c1d-cf0d97e982a7','酬吳直學  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','慚無健筆敵蘇州，蝸蚓聊鳴子夜秋。',64,'全唐诗/poet.song.203000.json','["慚無健筆敵蘇州，蝸蚓聊鳴子夜秋。", "問樂定應從季子，尋盟自許長滕侯。", "佇看騰踏飛黄去，小共徜徉大白浮。", "會有鷄林識風雅，一詩端把百金收。"]'),
('52606434-cff9-4522-ba96-3a84f7a0a8eb','酬朱直學  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','儒官領袖得名流，子佩應無在闕遊。',64,'全唐诗/poet.song.203000.json','["儒官領袖得名流，子佩應無在闕遊。", "只要松筠柰霜雪，須知蘭菊自春秋。", "年齡五十當榮顯，風月三千足唱酬。", "揚善推能需叶贊，有容心地儘休休。"]'),
('71b65bdb-10d5-4588-897f-5c940d3de5bc','酬朱直學  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','南來草木半炎州，喜見冰壺一段秋。',64,'全唐诗/poet.song.203000.json','["南來草木半炎州，喜見冰壺一段秋。", "所學有原真父子，自前無種是王侯。", "傳家肯羨金籯滿，用世還知玉璞酬。", "人事盡時天理見，但勤耕耨候豐收。"]'),
('3a058035-33c8-45ef-a242-eed376b56562','酬楊直學  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','人生遇坎與乘流，入則藏脩出則遊。',64,'全唐诗/poet.song.203000.json','["人生遇坎與乘流，入則藏脩出則遊。", "風順鵾鵬須擊海，時來蟋蟀自吟秋。", "教經已勝金籯贈，遺錦慚無玉案酬。", "着脚蘭臺自今始，懸知下筆不能休。"]'),
('51dd4cda-6669-4310-a120-450963c657d2','酬楊直學  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','四海聲名揚道州，亭亭心幹凜高秋。',64,'全唐诗/poet.song.203000.json','["四海聲名揚道州，亭亭心幹凜高秋。", "耳孫自是千人傑，骨相當爲萬里侯。", "春入草堂清夢透，名登桂籍暗香浮。", "錦囊正恨新詩少，說與奚奴取次收。"]'),
('dbcb040e-76bf-4980-9ba2-8431eb0ed9f2','贈太和曾機宜','徐鹿卿','宋','宋诗','song-poetry','','[]','故家名姓塞乾坤，曾上歐蘇涑水門。',64,'全唐诗/poet.song.203000.json','["故家名姓塞乾坤，曾上歐蘇涑水門。", "似此高風寧幾箇，至今流澤到諸孫。", "譚詩江上風烟圃，訪我梅邊竹石村。", "尚有典刑堪世守，會看溟海化鵬鵾。"]'),
('ae2133a2-4d03-4102-8fce-bbf12faff261','壽陳太庾','徐鹿卿','宋','宋诗','song-poetry','','[]','壽山輝彩照湖山，管領春光又一翻。',64,'全唐诗/poet.song.203000.json','["壽山輝彩照湖山，管領春光又一翻。", "動地名聲太丘長，傳家詩派簡齋孫。", "梅關訊息羹調鼎，桃縣風流酒滿尊。", "里社逢時公事在，好施奇計復中原。"]'),
('4c611431-a6b4-4b03-b582-10a3871e3467','去年脩禊後三日得南宮捷報於家今年是日與同年趙簿同事泮宮感而賦詩','徐鹿卿','宋','宋诗','song-poetry','','[]','淡烟疎雨杏花天，回首春光又一年。',64,'全唐诗/poet.song.203000.json','["淡烟疎雨杏花天，回首春光又一年。", "月桂香中方並駕，嶺梅陰裏競揚鞭。", "覺來始悟他人夢，着罷傍觀國手先。", "一動靜間知造化，吟情渾寄柳絲邊。"]'),
('7c1fbfe0-c2d8-4ea1-89d7-d4f73182cab5','趙簿見和復次韻','徐鹿卿','宋','宋诗','song-poetry','','[]','一昨瞻依尺五天，青衫槐簡是同年。',64,'全唐诗/poet.song.203000.json','["一昨瞻依尺五天，青衫槐簡是同年。", "飛騰影裏尋芳躅，警蹕聲中響靜鞭。", "夷路已看騰驥駃，競風須遜畫蛇先。", "宗臣底事猶棲棘，有策籌邊不在邊。"]'),
('2a8ada2f-4e32-4f15-8b1f-b5ca8efe5b8f','酬黎丞見和','徐鹿卿','宋','宋诗','song-poetry','','[]','極目龍門峻接天，仕塗傾蓋便忘年。',64,'全唐诗/poet.song.203000.json','["極目龍門峻接天，仕塗傾蓋便忘年。", "太平官府閑吟竹，勝處園林笑舉鞭。", "松柏凌霜知獨後，樓臺得月會居先。", "老臣憂國誰能識，飛雪飄飄上鬢邊。"]'),
('b38a64d8-50df-496e-ae8f-4efd886fa7b7','酬曾教正','徐鹿卿','宋','宋诗','song-poetry','','[]','襟懷瀟灑浴沂天，家學相傳幾百年。',64,'全唐诗/poet.song.203000.json','["襟懷瀟灑浴沂天，家學相傳幾百年。", "外物莫貪蒼玉佩，真才肯賈蠟黄鞭。", "不平未用鳴東野，懶讀難爲誚孝先。", "頼有濂溪衣鉢在，滿庭風月浩無邊。"]'),
('f6822962-3da2-4519-a335-1649721a2dc5','酬正錄直學','徐鹿卿','宋','宋诗','song-poetry','','[]','橫浦雖然一角天，周程清化幾經年。',64,'全唐诗/poet.song.203000.json','["橫浦雖然一角天，周程清化幾經年。", "從前步武堪同轍，近裏工夫好着鞭。", "自笑已居王勃後，相期常恐祖生先。", "地麟自此符佳讖，魁宿聯輝庾嶺邊。"]'),
('2aadeffd-749f-4214-9fb6-0c7efae6e0c1','酬何學賓','徐鹿卿','宋','宋诗','song-poetry','','[]','笑傲壺中別一天，德人端合享耆年。',64,'全唐诗/poet.song.203000.json','["笑傲壺中別一天，德人端合享耆年。", "鳴鳩不栩堪供杖，老驥馳思渠假鞭。", "儀表特居終賈上，名聲突出勝黄先。", "熊彲已入佳占未，明月清風渭水邊。"]'),
('407fc22c-0765-41ff-9150-a8ddc8fb3c32','去歲王監嶽以詩餞行且求無垢語錄次韻送之','徐鹿卿','宋','宋诗','song-poetry','','[]','我來橫浦訪遺言，無垢先生有正傳。',64,'全唐诗/poet.song.203000.json','["我來橫浦訪遺言，無垢先生有正傳。", "雙跡凄凉城下寺，一書泄露性中天。", "向來富貴俱荒草，今日風流尚湛泉。", "東谷有人知此意，平生耻售蠟黄鞭。"]'),
('95847bd6-bd4f-440b-ac4a-4b144cd9f0bc','和張直學送新茶韻','徐鹿卿','宋','宋诗','song-poetry','','[]','夢繞康王酌水簾，不知身世宦東南。',64,'全唐诗/poet.song.203000.json','["夢繞康王酌水簾，不知身世宦東南。", "蘇仙忽餉焦坑品，子尚渾凝曉露甘。", "便遏鼻雷醒睡思，仍澆舌本發清譚。", "搜枯破悶功神速，數到盧仝椀兩三。"]'),
('d8858a85-c825-4c61-8c16-3aac49486b99','壽提舉陳秘丞  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','南極星高月一弓，天將好事慶仙翁。',64,'全唐诗/poet.song.203000.json','["南極星高月一弓，天將好事慶仙翁。", "朝中詔遣鮮于使，境上民爭正獻公。", "葵藿傾陽清瘴霧，旗幢蓋海颺薰風。", "梅關南北俱和氣，祝壽歡聲兩處同。"]'),
('fb417c1e-15a1-47a3-922d-d5c66a6d6eb3','壽提舉陳秘丞  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','昔在興隆歲甲申，文恭當軸秉鴻鈞。',64,'全唐诗/poet.song.203000.json','["昔在興隆歲甲申，文恭當軸秉鴻鈞。", "如今休運重開宋，指日清朝再相陳。", "會有勳名償小戊，肯將官職怨雌辰。", "百年盛事看層見，請頌中興嶽降神。"]'),
('d4ff030c-a1d6-40a8-b74a-e7e440e76b6c','再用前韻送地圖','徐鹿卿','宋','宋诗','song-poetry','','[]','炎運中天歲甲申，誰令漢鼎重千鈞。',64,'全唐诗/poet.song.203000.json','["炎運中天歲甲申，誰令漢鼎重千鈞。", "故家輿地傷瓜裂，真主城樓細指陳。", "今古一時如合券，明良千載慶逢辰。", "來年竹帛功名就，圖繪雲臺筆有神。"]'),
('4455d7f4-3557-4ad9-a1c0-431f2a8ccf0f','至梅關書呈僚友','徐鹿卿','宋','宋诗','song-poetry','','[]','栖迹梅花嶺下州，梅關未到已神遊。',64,'全唐诗/poet.song.203000.json','["栖迹梅花嶺下州，梅關未到已神遊。", "右江左廣山分水，薄霧輕烟雨作秋。", "物是人非一今古，南來北往幾公侯。", "就中認得禪機者，非錫非泉是道不。"]'),
('87aefebe-74b8-497c-af1d-47170362dc38','士友見和七月七日曝書依元韻謝之','徐鹿卿','宋','宋诗','song-poetry','','[]','寒儒家世派南州，天遣芹宮並俊遊。',64,'全唐诗/poet.song.203000.json','["寒儒家世派南州，天遣芹宮並俊遊。", "劍水章江千里月，天孫河鼓一番秋。", "曬書舊事聊同郝，聯句新聲恐類侯。", "隔歲槐黄頻入夢，曾知山角已生不。"]'),
('ebdf53d5-9b0c-4c82-8bf2-d691e9ee2d05','送周幹','徐鹿卿','宋','宋诗','song-poetry','','[]','送客章江庾嶺邊，試將行止問蒼天。',64,'全唐诗/poet.song.203000.json','["送客章江庾嶺邊，試將行止問蒼天。", "雖然刖足終全璞，尚有知音莫斷絃。", "仕路偶來雲出岫，歸裝何有月隨船。", "鼠肝蟲臂冥心久，一笑掀髯對湛泉。"]'),
('ca6e8be7-be86-4a4e-8725-1042eed7486e','郭府判書友于堂榜謝之以詩  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','鳥篆開端不路鋒，錐紗成畫體逾工。',64,'全唐诗/poet.song.203000.json','["鳥篆開端不路鋒，錐紗成畫體逾工。", "中間三到屋漏雨，此後仍傳壁坼風。", "羲獻以來名絕學，徽章之外更明公。", "朝天此去承清問，一片丹心筆陣中。"]'),
('89cedb84-2eaa-4ab5-82d9-6495875911d3','郭府判書友于堂榜謝之以詩  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','堂礙雲霄扁友于，黑蛟光射斗牛墟。',64,'全唐诗/poet.song.203000.json','["堂礙雲霄扁友于，黑蛟光射斗牛墟。", "細筋入骨藏稜外，妙手師心灑墨初。", "只爲忠誠珍柳筆，多因節義重顔題。", "知君清德光前古，發露毫端直緒餘。"]'),
('d5769dd1-fb93-4b3c-b66b-ed2b3b62bf7e','廬陵曾省元求書見杜宰和韻餞其行','徐鹿卿','宋','宋诗','song-poetry','','[]','夫君漸是買臣年，耻眩虛名賈蠟鞭。',64,'全唐诗/poet.song.203000.json','["夫君漸是買臣年，耻眩虛名賈蠟鞭。", "斗酒新豐無飲伴，宮袍采石詫詩仙。", "寒花傲節休嫌晚，蟠木爲容不假先。", "更上詩壇參杜甫，清譚相對紙生烟。"]'),
('2f008b1a-822e-4f18-a6c6-c7007245619c','三山周省元索詩依杜宰韻賦二章  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','清夢蘧蘧楚峽陽，鎔成句法味悠長。',64,'全唐诗/poet.song.203000.json','["清夢蘧蘧楚峽陽，鎔成句法味悠長。", "栽桃小試經綸手，泛菊聊澆錦繡腸。", "逸思已堪凌賀白，高懷贏得傲羲皇。", "此中真趣人知麽，愛酒陶潛不是狂。"]'),
('a9e9dbe6-6863-4eeb-a3a5-0db813110e03','三山周省元索詩依杜宰韻賦二章  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','閒呼斗酒醉斜陽，欲說還休此話長。',64,'全唐诗/poet.song.203000.json','["閒呼斗酒醉斜陽，欲說還休此話長。", "笑我平生窮到骨，羨君萬卷富撐腸。", "向來一見梅初白，別後重逢菊正黄。", "潘縣主人如下問，爲言不減向來狂。"]'),
('0b3310ac-ef10-4170-b53d-4de6f0220b25','林府判錄示近製依韻和呈二首  其一','徐鹿卿','宋','宋诗','song-poetry','','[]','奇寶寧容棄道傍，名藩贊理令飛霜。',64,'全唐诗/poet.song.203000.json','["奇寶寧容棄道傍，名藩贊理令飛霜。", "冀都便覺群空馬，魯市應無詐飲羊。", "嶺阯雲烟新入詠，天邊日月趣依光。", "吾民疾痛誰醫得，好試家傳已效方。"]'),
('50041f8f-a174-46fc-b90e-f793c5882d6e','林府判錄示近製依韻和呈二首  其二','徐鹿卿','宋','宋诗','song-poetry','','[]','冷宦趨承木向陽，窺斑良覺愧真長。',64,'全唐诗/poet.song.203000.json','["冷宦趨承木向陽，窺斑良覺愧真長。", "摩挲千里紅塵脚，浣滌十年新學腸。", "小節自期冰皎潔，高吟滿聽月昏黄。", "青蠅附驥從茲始，底用行歌效楚狂。"]'),
('da5eb2a1-dfc3-4b33-ad02-aecece55e1ce','用羊字韻呈史君','徐鹿卿','宋','宋诗','song-poetry','','[]','曾揩醒眼奕棋傍，松柏孤高耐雪霜。',64,'全唐诗/poet.song.203000.json','["曾揩醒眼奕棋傍，松柏孤高耐雪霜。", "西蜀搜奇到金馬，南邦頌德繼羔羊。", "梅邊生意傳春信，筆底新詩燦夜光。", "運動樞衡當接踵，小煩千騎上東方。"]'),
('dd81eecf-c3eb-415a-9c42-641964b40596','侍林府判齋宿舉似頃在海陽縣齋丁祭詩依韻即席和呈','徐鹿卿','宋','宋诗','song-poetry','','[]','文星今夕照儒宮，多士青雲路已通。',64,'全唐诗/poet.song.203000.json','["文星今夕照儒宮，多士青雲路已通。", "沾溉有原芹泮水，吹噓無際杏壇風。", "溫醇德意覃千里，教養規模肇一同。", "疇昔周程鳴道處，鳶飛魚躍化鈞中。"]'),
('80e1c4d4-36df-4aeb-a87a-80ae7e253655','府判和答依韻上呈','徐鹿卿','宋','宋诗','song-poetry','','[]','芹藻生春水繞宮，吉蠲祠祀意潛通。',64,'全唐诗/poet.song.203000.json','["芹藻生春水繞宮，吉蠲祠祀意潛通。", "燈花飛舞看簷雨，詞藻清新繼國風。", "貳政坐令千里化，論文賸喜一樽同。", "彬彬執俎鳴鸞者，盡在明公和氣中。"]'),
('1bf09f2f-890a-424c-ab0c-4a9eb717937c','護法寺勸農呈史君','徐鹿卿','宋','宋诗','song-poetry','','[]','半載分符江水西，幾曾一日事遊嬉。',64,'全唐诗/poet.song.203000.json','["半載分符江水西，幾曾一日事遊嬉。", "忽聞千騎傳呼曉，正是三春勸相時。", "父老倚鋤聽號令，兒童騎竹望旌麾。", "東風歸路歡聲滿，野草閑花索賦詩。"]'),
('bc054bf4-9940-4dc6-bc31-9d52c1adc6f6','史君寵和復依韻上呈','徐鹿卿','宋','宋诗','song-poetry','','[]','禾生隴畝自東西，父老怡然市井嬉。',64,'全唐诗/poet.song.203000.json','["禾生隴畝自東西，父老怡然市井嬉。", "列郡幾人知此意，五風十雨盡如時。", "買牛已解田間劍，分虎難淹嶺下麾。", "一任吏人來報事，不妨遊戯作春詩。"]'),
('77636040-e03d-44c5-b4ff-f1a7b7604006','同日依齋宮韻呈府判','徐鹿卿','宋','宋诗','song-poetry','','[]','屏星小駐梵王宮，草碧泉清一徑通。',64,'全唐诗/poet.song.203000.json','["屏星小駐梵王宮，草碧泉清一徑通。", "細細秧針抽夜雨，盈盈麥浪汎東風。", "登臨不爲溪山勝，守助端期井里同。", "此去豐穰知有兆，百年父老笑聲中。"]'),
('b026a69b-b4e8-4a78-b18a-bcd9b0e36f3e','寄題胡叔軫香山樓詩','徐鹿卿','宋','宋诗','song-poetry','','[]','笑問香山似舊邪，風流宛是更詞華。',64,'全唐诗/poet.song.203000.json','["笑問香山似舊邪，風流宛是更詞華。", "由江距洛路千驛，以宋繼唐詩一家。", "今日重簷窺斗柄，向來遺趾面湖沙。", "莫忘先世規恢策，贏取芳名並冠霞。"]'),
('abc690fd-a4f5-4d2c-8da0-7bf9366e81fe','史君贈所臨蜀本三蘇入京圖詩以謝之','徐鹿卿','宋','宋诗','song-poetry','','[]','至和嘉祐正塗開，綵鳳將雛出蜀來。',64,'全唐诗/poet.song.203000.json','["至和嘉祐正塗開，綵鳳將雛出蜀來。", "父子名聲天宇小，弟兄筆力海潮迴。", "岷峨一氣鍾三傑，歐富諸公識異材。", "後百餘年拜遺像，凜然高節尚崔嵬。"]'),
('8ccfcb04-2060-4358-88c2-a21e908f6be1','黎丞傳示史宰聾字詩走筆和之','徐鹿卿','宋','宋诗','song-poetry','','[]','毛穎翻成一禿翁，文章苦欲誑盲聾。',64,'全唐诗/poet.song.203000.json','["毛穎翻成一禿翁，文章苦欲誑盲聾。", "從前結實無非妄，勝處生涯好用工。", "天上高深關守虎，馬前奔走背生蟲。", "榮枯數定何須問，了却公家是奉公。"]');
